// English facts loaded before the main Oracle app.
const FACTS_EN=[
  // >>> SCIENCE (50 faits)
  {id:'s1',cat:'science',text:"A lightning bolt heats the surrounding air to a temperature five times hotter than the surface of the Sun — roughly 30,000 °C."},
  {id:'s2',cat:'science',text:"93% of your body's mass is stardust: the atoms that make you up were forged in long-dead stars billions of years ago."},
  {id:'s3',cat:'science',text:"Migratory birds literally see Earth's magnetic field lines superimposed on their vision, like a built-in compass in their eyes."},
  {id:'s4',cat:'science',text:"In a single teaspoon of soil, there are more micro-organisms than there are humans on the entire planet."},
  {id:'s5',cat:'science',text:"Some Australian raptors deliberately start wildfires by carrying embers in their talons to flush out prey."},
  {id:'s6',cat:'science',text:"Some icebergs have green stripes: when an iceberg absorbs sea water, algae colour its layers from the inside."},
  {id:'s7',cat:'science',text:"Half the oxygen you breathe is produced by microscopic plankton invisible to the naked eye in the oceans."},
  {id:'s8',cat:'science',text:"Fossilized lightning exists: when a bolt strikes sand, it instantly vitrifies it into hollow tubes called fulgurites."},
  {id:'s9',cat:'science',text:"The number of trees on Earth — around 3 trillion — exceeds the number of stars in the Milky Way."},
  {id:'s10',cat:'science',text:"Viruses constantly rain down on us from the stratosphere, carried by air currents around the globe."},
  {id:'s11',cat:'science',text:"Some trees communicate through an underground network of fungi — scientists call it the 'wood wide web'."},
  {id:'s12',cat:'science',text:"Hot water can freeze faster than cold water in certain conditions — the Mpemba effect, known since antiquity and still debated."},
  {id:'s13',cat:'science',text:"Sound travels fifteen times faster through steel than through air."},
  {id:'s14',cat:'science',text:"Human DNA contains around 3 billion base pairs. If fully unravelled, it would stretch about 2 metres long — yet it fits inside a cell nucleus."},
  {id:'s15',cat:'science',text:"A free neutron decays in about 14 minutes and 38 seconds, transforming into a proton, an electron and an antineutrino."},
  {id:'s16',cat:'science',text:"Tardigrades are the most resilient animals on Earth: they survive the vacuum of space, extreme radiation, and temperatures of -272°C."},
  {id:'s17',cat:'science',text:"The human brain generates around 23 watts of electricity when awake — enough to power a small LED light bulb."},
  {id:'s18',cat:'science',text:"Octopuses have three hearts and blue blood, thanks to haemocyanin, a copper-containing protein that replaces iron-based haemoglobin."},
  {id:'s19',cat:'science',text:"One gram of DNA can theoretically store up to 215 petabytes of data — the equivalent of 215 million gigabytes."},
  {id:'s20',cat:'science',text:"Hot ice, or Ice XVI, is a form of ice that forms under very high pressure and is actually less dense than ordinary liquid water."},
  {id:'s21',cat:'science',text:"Plants 'hear' water: their roots grow toward the sound of a flowing pipe, even without any contact with moisture."},
  {id:'s22',cat:'science',text:"The lowest temperature ever created in a lab is 38 picoKelvins — colder than interstellar space."},
  {id:'s23',cat:'science',text:"A single lightning bolt contains enough energy to toast 100,000 slices of bread — but it's released too fast to capture."},
  {id:'s24',cat:'science',text:"Time crystals, predicted in 2012 and created in 2017, oscillate without ever consuming energy — a new state of matter."},
  {id:'s25',cat:'science',text:"Gravity makes time pass more slowly: a clock on the ground floor ticks ever so slightly behind a clock on the top floor."},
  {id:'s26',cat:'science',text:"Flames in space are spherical and blue — without gravity, there's no convection to stretch the flame upward."},
  {id:'s27',cat:'science',text:"Glass is not a slow-moving liquid — it's an amorphous solid. Old windowpanes are thicker at the bottom due to manufacturing techniques."},
  {id:'s28',cat:'science',text:"A photon emitted at the Sun's core takes between 10,000 and 170,000 years to reach the surface, bouncing endlessly off atoms."},
  {id:'s29',cat:'science',text:"Fire tornadoes exist: when a wildfire generates enough heat, it can spawn a vortex of flames exceeding 1,000°C."},
  {id:'s30',cat:'science',text:"The loudest sound ever recorded was the eruption of Krakatoa in 1883 — audible 5,000 km away, it circled the globe four times."},
  {id:'s31',cat:'science',text:"There are more water molecules in a single glass than there are glasses of water in all the oceans of the planet combined."},
  {id:'s32',cat:'science',text:"The observable universe is about 93 billion light-years wide, even though it's only 13.8 billion years old — because space itself expands."},
  {id:'s33',cat:'science',text:"Each year, millions of tons of dust from the Sahara cross the Atlantic and fertilize the Amazon rainforest, 5,000 km away."},
  {id:'s34',cat:'science',text:"Cooled near absolute zero, helium becomes a superfluid that can climb up the walls of a container and escape on its own."},
  {id:'s35',cat:'science',text:"Weight for weight, spider silk is stronger than steel: a strand the thickness of a pencil could in theory stop an airliner."},
  {id:'s36',cat:'science',text:"An atom is almost entirely empty: if its nucleus were the size of a marble, the electrons would orbit hundreds of meters away."},
  {id:'s37',cat:'science',text:"The human eye is so sensitive it can detect a single photon — the smallest possible amount of light."},
  {id:'s38',cat:'science',text:"Helium was discovered on the Sun before it was found on Earth: its name comes from Helios, the Greek sun god."},
  {id:'s39',cat:'science',text:"Days are slowly getting longer: the Moon brakes Earth's rotation, which gains about 1.7 milliseconds per century."},
  {id:'s40',cat:'science',text:"The speed of light is exactly 299,792,458 meters per second — because it's what now defines the length of the meter."},
  {id:'s41',cat:'science',text:"The world's longest-running lab experiment has gone on since 1927: a block of pitch, which looks solid, flows so slowly it drips only about once a decade."},
  {id:'s42',cat:'science',text:"Earth's inner core is almost as hot as the Sun's surface — about 5,400 °C — yet stays solid because of the colossal pressure."},
  {id:'s43',cat:'science',text:"The smell of rain on dry ground has a name: petrichor — a mix of plant oils and a molecule made by soil bacteria."},
  {id:'s44',cat:'science',text:"The most common state of matter in the universe is neither solid, liquid, nor gas: it's plasma, what all stars are made of."},
  {id:'s45',cat:'science',text:"Some cooled materials become superconductors and completely repel magnetic fields — enough to make a magnet levitate above them."},
  {id:'s46',cat:'science',text:"Trillions of neutrinos pass through your body every second without ever touching it — these ghost particles go straight through the entire Earth."},
  {id:'s47',cat:'science',text:"Antimatter is real: CERN produces tiny amounts of it, and when it meets matter, the two annihilate in a burst of pure energy."},
  {id:'s48',cat:'science',text:"The Eiffel Tower grows about 15 cm taller in summer: heat expands the iron, and the structure can also lean slightly away from the Sun."},
  {id:'s49',cat:'science',text:"Two 'entangled' particles stay linked no matter the distance: measuring one instantly sets the state of the other, even across the universe."},
  {id:'s50',cat:'science',text:"If you could fold a single sheet of paper in half 42 times, its thickness would, in theory, reach the Moon."},
  // <<< SCIENCE
  // >>> POSITIVE (50 faits)
  {id:'p1',cat:'positive',text:"The green sea turtle officially moved to 'least concern' status in 2025 — its populations have grown 28% since 1970."},
  {id:'p2',cat:'positive',text:"For the first time ever, the world generated more electricity from renewables than from coal in the first half of 2025."},
  {id:'p3',cat:'positive',text:"The global number of deaths linked to air pollution has been halved since 1990."},
  {id:'p4',cat:'positive',text:"The ozone layer has been recovering since CFCs were banned in the 1980s — one of the greatest successes of international cooperation."},
  {id:'p5',cat:'positive',text:"The UK closed its last coal-fired power station in 2024, becoming the first G7 nation to phase out this energy source entirely."},
  {id:'p6',cat:'positive',text:"Earth gained 5% more green surface between 2000 and 2017 — the equivalent of an entire Amazon rainforest — thanks to reforestation."},
  {id:'p7',cat:'positive',text:"British researchers successfully slowed the progression of Huntington's disease using gene therapy for the first time in 2025."},
  {id:'p8',cat:'positive',text:"France created the world's largest marine protected area in 2025, in French Polynesia."},
  {id:'p9',cat:'positive',text:"The global child mortality rate has fallen by 60% since 1990, saving millions of lives every year."},
  {id:'p10',cat:'positive',text:"Deforestation slowed in every region of the world in 2025, according to a United Nations report."},
  {id:'p11',cat:'positive',text:"Malaria has been reduced by 76% in the most affected countries thanks to insecticide-treated nets and antimalarials — sparing more than 7 million lives since 2000."},
  {id:'p12',cat:'positive',text:"The cost of solar energy fell by 90% in ten years. In 2023, it became the cheapest source of electricity in human history in most regions of the world."},
  {id:'p13',cat:'positive',text:"The humpback whale, once on the brink of extinction due to commercial whaling, is now classified as 'least concern' by the IUCN — its global population has rebounded by more than 93%."},
  {id:'p14',cat:'positive',text:"In 1990, 36% of the world's population lived in extreme poverty. By 2024, that figure had fallen below 9% — an unprecedented reduction in human history."},
  {id:'p15',cat:'positive',text:"Smallpox was officially eradicated in 1980 through a global vaccination campaign coordinated by the WHO — it is the only human disease ever fully eliminated by human action."},
  {id:'p16',cat:'positive',text:"Global forest cover has grown in parts of Europe and Asia thanks to reforestation efforts — France has gained 30% more forest since 1950."},
  {id:'p17',cat:'positive',text:"In 2023, 73% of the world's population had access to safely managed drinking water — up from 59% in 2000, representing more than one billion additional people."},
  {id:'p18',cat:'positive',text:"Global electric vehicle sales exceeded 14 million units in 2023, representing 18% of new cars sold — a 60-fold increase in less than ten years."},
  {id:'p19',cat:'positive',text:"The number of wild animal species tracked by WWF increased by 4% since 2020 in protected areas, thanks to targeted conservation efforts focused on priority threatened species."},
  {id:'p20',cat:'positive',text:"The proportion of the world's population suffering from hunger has been halved since the 1990s. In 2023, the UN estimates that one million fewer children suffered from severe malnutrition than in 2020."},
  {id:'p21',cat:'positive',text:"The Iberian lynx, down to 94 individuals in 2002, now exceeds 2,000 thanks to reintroduction programs in Spain and Portugal."},
  {id:'p22',cat:'positive',text:"Since 2000, primary school enrollment has risen from 60% to 90% in sub-Saharan Africa — tens of millions more children in school."},
  {id:'p23',cat:'positive',text:"Costa Rica has produced over 99% of its electricity from renewable sources for several consecutive years."},
  {id:'p24',cat:'positive',text:"Deaths from natural disasters have dropped 90% in a century, thanks to early warning systems and earthquake-resistant buildings."},
  {id:'p25',cat:'positive',text:"India planted 220 million trees in a single day in 2019 — a world record for reforestation."},
  {id:'p26',cat:'positive',text:"The global literacy rate has risen from 42% in 1960 to 87% today — the highest in human history."},
  {id:'p27',cat:'positive',text:"Wild tiger populations are rising for the first time in a century, from 3,200 in 2010 to about 4,500 today."},
  {id:'p28',cat:'positive',text:"The ozone hole over Antarctica has shrunk by 4 million km² since its peak in the 2000s."},
  {id:'p29',cat:'positive',text:"Rwanda banned plastic bags in 2008 and has since become one of the cleanest countries in Africa."},
  {id:'p30',cat:'positive',text:"Global maternal mortality has been reduced by 34% since 2000, with spectacular improvements in Southeast Asia."},
  {id:'p31',cat:'positive',text:"Guinea worm disease has gone from 3.5 million cases in 1986 to just a handful today — on the verge of total eradication."},
  {id:'p32',cat:'positive',text:"In 2016, the giant panda was downgraded from 'endangered' to 'vulnerable': its wild populations are rising thanks to decades of protection."},
  {id:'p33',cat:'positive',text:"Mountain gorillas, once on the brink of extinction, have climbed back past 1,000 individuals — one of conservation's finest successes."},
  {id:'p34',cat:'positive',text:"Wild polio cases have dropped by more than 99% since 1988: the disease is now endemic in only two countries worldwide."},
  {id:'p35',cat:'positive',text:"Global life expectancy has nearly doubled in a century: from about 32 years in 1900 to over 70 today."},
  {id:'p36',cat:'positive',text:"The bald eagle, emblem of the United States, went from 417 pairs in 1963 to over 300,000 birds, leaving the endangered species list in 2007."},
  {id:'p37',cat:'positive',text:"In 2021, leaded petrol officially vanished from the planet: Algeria was the last country to sell it, ending a century of toxic pollution."},
  {id:'p38',cat:'positive',text:"The southern white rhino came back from the brink: only about fifty remained around 1900, and today there are roughly 20,000."},
  {id:'p39',cat:'positive',text:"The California condor went from just 22 birds in 1982 to over 500 today, thanks to a breeding and reintroduction program."},
  {id:'p40',cat:'positive',text:"AIDS-related deaths have more than halved since their 2004 peak, thanks to widespread access to antiretroviral treatment."},
  {id:'p41',cat:'positive',text:"Long incurable, hepatitis C can now be cured in over 95% of cases thanks to treatments introduced around 2014."},
  {id:'p42',cat:'positive',text:"Measles vaccination prevented about 60 million deaths worldwide between 2000 and 2023."},
  {id:'p43',cat:'positive',text:"Over 90% of the world's population now has access to electricity, up from about 73% in 1990."},
  {id:'p44',cat:'positive',text:"Doing a good deed literally makes you happier: helping others activates the brain's reward circuits, an effect nicknamed the 'helper's high.'"},
  {id:'p45',cat:'positive',text:"Studies show that spending money on others makes you happier than spending it on yourself."},
  {id:'p46',cat:'positive',text:"Hunted for its fur down to just a few thousand individuals, the sea otter has now bounced back to over 100,000."},
  {id:'p47',cat:'positive',text:"A simple cataract operation, sometimes in under fifteen minutes, restores sight to millions of people every year."},
  {id:'p48',cat:'positive',text:"The saiga antelope, with its trunk-like nose, moved from 'critically endangered' to 'near threatened' in 2023 after rebounding to nearly two million individuals."},
  {id:'p49',cat:'positive',text:"Przewalski's horse, the world's only truly wild horse, had vanished from the wild — it has been successfully reintroduced to the steppes of Mongolia."},
  {id:'p50',cat:'positive',text:"Costa Rica doubled its forest cover in a generation: down to about 25% of the territory in the 1980s, forest now covers more than half."},
  // <<< POSITIVE
  // >>> FUN (50 faits)
  {id:'u1',cat:'fun',text:"Bananas are naturally radioactive. You'd have to eat ten billion at once to reach a dangerous dose — and you'd die of something else first."},
  {id:'u2',cat:'fun',text:"A cockroach can survive an entire week after being decapitated — it doesn't die from losing its head, but from thirst, with no mouth to drink."},
  {id:'u3',cat:'fun',text:"The letter J is the only one absent from the periodic table of chemical elements."},
  {id:'u4',cat:'fun',text:"Liquid oxygen is pale blue — the colourless gas you breathe takes on a sky-blue tint the moment it changes state."},
  {id:'u5',cat:'fun',text:"A parasitic fungus called Ophiocordyceps takes over an ant's brain, forces it to climb a plant, then kills it to reproduce."},
  {id:'u6',cat:'fun',text:"Human stomach acid has a pH between 1 and 2 — as aggressive as car battery acid — and your stomach handles it just fine."},
  {id:'u7',cat:'fun',text:"There are more stars in the observable universe than grains of sand on all the beaches and deserts of Earth combined."},
  {id:'u8',cat:'fun',text:"The venom of the blue-ringed octopus can kill 26 adult humans in minutes — and there is no antidote."},
  {id:'u9',cat:'fun',text:"There are around 100 billion bacteria in your mouth right now, and 25,000 germs on every square centimetre of your phone."},
  {id:'u10',cat:'fun',text:"An iceberg contains more total thermal energy than a lit match — because energy depends on mass, not temperature."},
  {id:'u11',cat:'fun',text:"The dot above the letters i and j has a name: the 'tittle'. Without it, these letters would be confused with others in medieval manuscripts."},
  {id:'u12',cat:'fun',text:"Chimpanzees outperform humans at memorising sequences of numbers displayed for a fraction of a second — their short-term photographic memory surpasses ours."},
  {id:'u13',cat:'fun',text:"Scientists created in 2022 an enzyme capable of breaking down PET plastic within hours — a process that takes nature centuries."},
  {id:'u14',cat:'fun',text:"Researchers have shown that cats recognise their own name — but deliberately choose not to respond when called by their owner, unlike dogs."},
  {id:'u15',cat:'fun',text:"A group of flamingos is called a 'flamboyance'. These birds are naturally white: their pink colour comes from carotenoid pigments in the shrimp and algae they eat."},
  {id:'u16',cat:'fun',text:"The pistol shrimp emits clicks at 160 decibels to stun its prey — the loudest sound produced by any animal relative to its body size in the entire animal kingdom."},
  {id:'u17',cat:'fun',text:"The mantis shrimp can strike with a force equivalent to a bullet at 23 m/s — its blows create cavitation bubbles that reach 4,000°C on impact."},
  {id:'u18',cat:'fun',text:"Herring use flatulence to communicate: they expel bubbles through their anus to stay in contact with each other in the dark. This discovery earned its authors the Ig Nobel Prize."},
  {id:'u19',cat:'fun',text:"The human belly button hosts an average of 67 different species of bacteria. In one documented case, researchers found a bacterium previously recorded only in Japan — in a man who had never been there."},
  {id:'u20',cat:'fun',text:"A lobster flees predators faster than it normally swims — it propels itself backwards by flapping its tail at speeds that can exceed 5 metres per second."},
  {id:'u21',cat:'fun',text:"Wombats produce cube-shaped poop — the only known species with this peculiarity, likely to prevent it from rolling away."},
  {id:'u22',cat:'fun',text:"A thundercloud weighs an average of 500,000 tons — the equivalent of 100,000 elephants floating above your head."},
  {id:'u23',cat:'fun',text:"Candle flames contain millions of tiny diamonds about 0.5 nanometers across that form and vanish almost instantly."},
  {id:'u24',cat:'fun',text:"Honey doesn't fall in a straight line: it forms spirals and loops as it drips — a phenomenon called 'liquid rope coiling.'"},
  {id:'u25',cat:'fun',text:"The probability that two people in a group of 23 share a birthday is over 50% — it's called the birthday paradox."},
  {id:'u26',cat:'fun',text:"Astronauts grow 3 to 5 cm taller in space because their spine stretches without gravity — they shrink back on return."},
  {id:'u27',cat:'fun',text:"The number 111,111,111 multiplied by itself equals 12,345,678,987,654,321 — a perfect palindrome."},
  {id:'u28',cat:'fun',text:"It rains diamonds on Jupiter and Saturn: atmospheric pressure transforms methane into pure carbon crystals."},
  {id:'u29',cat:'fun',text:"A human fart travels at about 11 km/h and is mostly nitrogen and CO₂ — hydrogen sulfide makes up only 1% but causes all the smell."},
  {id:'u30',cat:'fun',text:"Clownfish are all born male — the most dominant one changes sex to become female if the existing female disappears."},
  {id:'u31',cat:'fun',text:"An ostrich's eye is bigger than its brain: each eyeball measures about 5 cm across."},
  {id:'u32',cat:'fun',text:"A polar bear's fur isn't white but transparent, and the skin beneath it is entirely black."},
  {id:'u33',cat:'fun',text:"The mosquito is the deadliest animal in history: the diseases it spreads are thought to have killed more humans than all wars combined."},
  {id:'u34',cat:'fun',text:"There are more public libraries in the United States than McDonald's restaurants."},
  {id:'u35',cat:'fun',text:"In 18th-century Europe, pineapples were so rare and expensive that you could rent one to show off at a party, without ever eating it."},
  {id:'u36',cat:'fun',text:"An American, Charles Osborne, had the hiccups non-stop for 68 years, from 1922 to 1990."},
  {id:'u37',cat:'fun',text:"The world's shortest scheduled commercial flight lasts under two minutes: it links two Scottish islands, Westray and Papa Westray."},
  {id:'u38',cat:'fun',text:"Scotland's official national animal is... the unicorn, chosen for its purity and independence in Celtic legend."},
  {id:'u39',cat:'fun',text:"The # symbol has a real name: the 'octothorpe,' coined by telephone engineers in the 1960s."},
  {id:'u40',cat:'fun',text:"A group of pugs has its own special name: in English, it's called a 'grumble.'"},
  {id:'u41',cat:'fun',text:"A shrimp's heart is located in its head, just behind the brain, in the part called the cephalothorax."},
  {id:'u42',cat:'fun',text:"A 'jiffy' is a real unit of time: in electronics it often means a sixtieth of a second, and in physics, the time light takes to travel one centimeter."},
  {id:'u43',cat:'fun',text:"Three towns officially twinned over their names: Dull in Scotland, Boring in the United States, and Bland in Australia."},
  {id:'u44',cat:'fun',text:"According to often-cited statistics, vending machines kill more people each year than sharks do."},
  {id:'u45',cat:'fun',text:"There are about 20 quadrillion ants on Earth — together outweighing all wild birds and mammals combined."},
  {id:'u46',cat:'fun',text:"There's a punctuation mark that combines the question mark and the exclamation point: the interrobang, written '‽'."},
  {id:'u47',cat:'fun',text:"A 'baker's dozen' is thirteen: in the Middle Ages, bakers added an extra loaf to avoid harsh penalties for selling underweight bread."},
  {id:'u48',cat:'fun',text:"A 'murmuration' is a cloud of starlings that can number hundreds of thousands of birds, wheeling as a single moving body."},
  {id:'u49',cat:'fun',text:"The tomato has more genes than a human being: about 31,000, versus nearly 20,000 for us."},
  {id:'u50',cat:'fun',text:"There are more ways to shuffle a deck of 52 cards than there are atoms on Earth — a 68-digit number."},
  // <<< FUN
  // >>> HISTORY (50 faits)
  {id:'h1',cat:'history',text:"Romans used human urine as mouthwash and to bleach their clothes — the ammonia it contains is indeed an effective cleaning agent."},
  {id:'h2',cat:'history',text:"Cleopatra lived closer to us in time than to the construction of the Great Pyramid — she was 2,500 years away from it, we're only 2,000."},
  {id:'h3',cat:'history',text:"Greek fire, the Byzantine Empire's secret weapon, burned even on water — its exact composition remains an unsolved mystery to this day."},
  {id:'h4',cat:'history',text:"Vikings used a 'sun stone' — Icelandic calcite — to navigate in cloudy weather by locating the hidden Sun."},
  {id:'h5',cat:'history',text:"Oxford University is older than the Aztec Empire: teaching began there around 1096, some 300 years before Tenochtitlán was founded."},
  {id:'h6',cat:'history',text:"The Roman Colosseum could be partially flooded for miniature naval battles — naumachiae held right in the heart of Rome."},
  {id:'h7',cat:'history',text:"Roman gladiators were mostly vegetarian: their barley-and-legume diet earned them the nickname 'barley eaters'."},
  {id:'h8',cat:'history',text:"The Library of Alexandria was not destroyed in a single catastrophe — it declined gradually over several centuries through wars, fires, and funding cuts."},
  {id:'h9',cat:'history',text:"Napoleon was 5'7\" (1.69 m), above average for his era — the 'short Napoleon' legend stems from a mix-up between French and English measurement units."},
  {id:'h10',cat:'history',text:"The shortest war in history — the UK vs Zanzibar in 1896 — lasted exactly 38 minutes."},
  {id:'h11',cat:'history',text:"The pyramids were not built by slaves, but by free workers who were paid, fed, and housed — papyri confirm this."},
  {id:'h12',cat:'history',text:"There are more pyramids in Sudan (around 200) than in Egypt (around 130) — the Nubian pyramids of Meroe are far less famous but just as impressive."},
  {id:'h13',cat:'history',text:"Pharaoh Ramesses II signed with the Hittites the first written peace treaty in history, in 1259 BC."},
  {id:'h14',cat:'history',text:"The Great Wall of China is not visible from space with the naked eye. Astronauts have consistently debunked this popular myth."},
  {id:'h15',cat:'history',text:"Julius Caesar was kidnapped by pirates in 75 BC. He laughed at their ransom, demanded they double it, then had them crucified after his release."},
  {id:'h16',cat:'history',text:"Vikings did not have horns on their helmets. This was invented by a 19th-century theatrical costume designer with no archaeological basis."},
  {id:'h17',cat:'history',text:"Japanese samurai tested the quality of their katanas on condemned prisoners — a practice called 'tameshigiri'."},
  {id:'h18',cat:'history',text:"The first message sent over the internet's predecessor ARPANET in 1969 was 'lo'. The intended word 'login' was cut short by a system crash."},
  {id:'h19',cat:'history',text:"The Roman Empire had a road network of over 80,000 kilometers, some of which are still in use today."},
  {id:'h20',cat:'history',text:"During World War II, the British MI5 trained carrier pigeons to transport secret messages from occupied France."},
  {id:'h21',cat:'history',text:"Genghis Khan killed so many people that forests regrew and global CO₂ dropped — a measurable climate cooling effect."},
  {id:'h22',cat:'history',text:"During Prohibition, the US government deliberately poisoned industrial alcohol — an estimated 10,000 people died as a result."},
  {id:'h23',cat:'history',text:"The Incas had no writing, but used quipus — knotted strings — to record numerical and narrative data."},
  {id:'h24',cat:'history',text:"The last official duel in France took place in 1967, between deputies Gaston Defferre and René Ribière — with swords."},
  {id:'h25',cat:'history',text:"The Ottoman Empire lasted 623 years — longer than the Western Roman Empire, from the 14th to the 20th century."},
  {id:'h26',cat:'history',text:"The first McDonald's opened in 1940, but the real revolution came from Ray Kroc in 1955 with the franchise system."},
  {id:'h27',cat:'history',text:"Swiss women didn't gain the right to vote at the federal level until 1971 — one of the last European countries to do so."},
  {id:'h28',cat:'history',text:"Alexander the Great never lost a single battle in 15 years of military campaigns — he died at 32, probably of fever."},
  {id:'h29',cat:'history',text:"The Maya invented the concept of zero well before Europeans, as early as the 4th century — independently of India."},
  {id:'h30',cat:'history',text:"The Black Death killed between 30% and 60% of Europe's population in the 14th century — roughly 25 to 50 million people."},
  {id:'h31',cat:'history',text:"The Vikings reached North America around the year 1000, nearly five centuries before Christopher Columbus."},
  {id:'h32',cat:'history',text:"The guillotine was used in France until 1977 — the same year the first Star Wars film was released."},
  {id:'h33',cat:'history',text:"The Rosetta Stone made it possible to decipher Egyptian hieroglyphs: it bears the same text in three different scripts."},
  {id:'h34',cat:'history',text:"In 79 AD, the eruption of Vesuvius buried the city of Pompeii under ash, freezing it in time for nearly two millennia."},
  {id:'h35',cat:'history',text:"The Hundred Years' War actually lasted 116 years, from 1337 to 1453, between France and England."},
  {id:'h36',cat:'history',text:"Marie Curie's lab notebooks are still radioactive today — and will remain so for about 1,500 years."},
  {id:'h37',cat:'history',text:"Mansa Musa, emperor of Mali in the 14th century, is often considered the richest person in all of history."},
  {id:'h38',cat:'history',text:"In 1932, the Australian army declared war on emus to protect crops — and lost to the birds."},
  {id:'h39',cat:'history',text:"In its early days, in the late 19th century, Coca-Cola really did contain cocaine, extracted from the coca leaf."},
  {id:'h40',cat:'history',text:"The Statue of Liberty was originally a shiny copper brown: it was oxidation that gave it its famous green color."},
  {id:'h41',cat:'history',text:"Over 2,000 years ago, the Greeks built a geared 'computer,' the Antikythera mechanism, able to predict the positions of the stars."},
  {id:'h42',cat:'history',text:"In the 3rd century BCE, the Carthaginian general Hannibal crossed the Alps with war elephants to attack Rome by surprise."},
  {id:'h43',cat:'history',text:"Lady Jane Grey was queen of England for only nine days, in 1553, before being overthrown — one of the shortest reigns in history."},
  {id:'h44',cat:'history',text:"In the 17th-century Netherlands, some tulip bulbs sold for more than a house, before the market crashed brutally in 1637."},
  {id:'h45',cat:'history',text:"The Wright brothers' very first flight, in 1903, covered a distance shorter than the wingspan of a modern Boeing 747."},
  {id:'h46',cat:'history',text:"In 1215, the Magna Carta was the first document to limit the power of the king of England before the law."},
  {id:'h47',cat:'history',text:"The oldest surviving photograph, taken around 1826, required about eight hours of exposure time."},
  {id:'h48',cat:'history',text:"In 1922, the tomb of pharaoh Tutankhamun was found nearly intact, with over 5,000 objects, including his famous gold mask."},
  {id:'h49',cat:'history',text:"The Pony Express, the famous horseback mail service of the American West, actually operated for only about 18 months."},
  {id:'h50',cat:'history',text:"The Romans already heated some houses and baths from the floor, thanks to a system of hot air circulating beneath the floor: the hypocaust."},
  // <<< HISTORY
  // >>> SPACE (50 faits)
  {id:'sp1',cat:'space',text:"A day on Venus is longer than a year on Venus — the planet rotates so slowly that the Sun rises in the west."},
  {id:'sp2',cat:'space',text:"Saturn is so low-density that it would float on water if you could find an ocean large enough to place it in."},
  {id:'sp3',cat:'space',text:"The light you see when you look at the Sun took 100,000 years to travel from its core to its surface — then just 8 minutes to reach you."},
  {id:'sp4',cat:'space',text:"Voyager 1, launched in 1977, is more than 23 billion kilometres away — and is still sending signals we can receive."},
  {id:'sp5',cat:'space',text:"Mars has the largest volcano in the solar system: Olympus Mons stands 22 km tall — three times Everest — on a base as wide as France."},
  {id:'sp6',cat:'space',text:"It snows on Mars — but the snow is made of CO₂ and sublimes before reaching the ground, vanishing like magic mid-air."},
  {id:'sp7',cat:'space',text:"The Moon is moving 3.8 cm away from Earth each year — in a few billion years, total solar eclipses will no longer be possible."},
  {id:'sp8',cat:'space',text:"Space smells like burnt raspberries and rum, according to astronomers who analysed molecules in a gas cloud at the heart of our galaxy."},
  {id:'sp9',cat:'space',text:"A teaspoon of neutron star material would weigh around a billion tonnes — roughly the weight of Mount Fuji."},
  {id:'sp10',cat:'space',text:"Black holes don't 'suck' — they exert the same gravitational pull as a star of equivalent mass. It's the proximity that makes them deadly."},
  {id:'sp11',cat:'space',text:"On Jupiter's moon Europa, a liquid ocean hides beneath an ice crust — scientists believe it could harbor life."},
  {id:'sp12',cat:'space',text:"The Sun accounts for 99.86% of all the mass in the solar system."},
  {id:'sp13',cat:'space',text:"The coldest known place in the universe is the Boomerang Nebula at −272°C — just one degree above absolute zero."},
  {id:'sp14',cat:'space',text:"The Milky Way and Andromeda will collide in about 4.5 billion years, forming a giant galaxy nicknamed 'Milkomeda'."},
  {id:'sp15',cat:'space',text:"In 2019, a black hole was directly photographed for the first time using the Event Horizon Telescope network."},
  {id:'sp16',cat:'space',text:"Pluto has a heart-shaped glacier called Tombaugh Regio, made of frozen nitrogen."},
  {id:'sp17',cat:'space',text:"A day on the Moon lasts about 29.5 Earth days — the same duration as its orbit, which is why we always see the same side."},
  {id:'sp18',cat:'space',text:"Jupiter's Great Red Spot is a storm raging for at least 350 years. It is large enough to contain two planet Earths."},
  {id:'sp19',cat:'space',text:"Saturn's rings, though immense, are astonishingly thin: their average thickness is only about 10 meters."},
  {id:'sp20',cat:'space',text:"Sound cannot travel through space. Interstellar space is so empty there are no molecules to carry sound waves."},
  {id:'sp21',cat:'space',text:"The ISS moves at 28,000 km/h and orbits Earth every 90 minutes — its crew sees 16 sunrises every day."},
  {id:'sp22',cat:'space',text:"There are more stars in the observable universe than grains of sand on every beach on Earth — about 200 billion billion."},
  {id:'sp23',cat:'space',text:"The largest mountain in the solar system is Olympus Mons on Mars — but Saturn's moon Rhea has a rocky ring in orbit around it."},
  {id:'sp24',cat:'space',text:"Titan, Saturn's moon, has lakes and rivers — but filled with liquid methane, not water."},
  {id:'sp25',cat:'space',text:"Buzz Aldrin's footprint on the Moon is still intact — with no wind or rain, it could remain visible for millions of years."},
  {id:'sp26',cat:'space',text:"A year on Neptune lasts 165 Earth years — the planet has completed only one orbit since its discovery in 1846."},
  {id:'sp27',cat:'space',text:"The speed of light is so 'slow' on a cosmic scale that a signal sent to the nearest star would take 4.2 years to arrive."},
  {id:'sp28',cat:'space',text:"The James Webb telescope can see galaxies formed 300 million years after the Big Bang — 13.5 billion years ago."},
  {id:'sp29',cat:'space',text:"Venus rotates in the opposite direction from most planets — on Venus, the Sun rises in the west and sets in the east."},
  {id:'sp30',cat:'space',text:"There's an alcohol cloud in space, Sagittarius B2, containing enough ethanol to fill 400 trillion trillion pints of beer."},
  {id:'sp31',cat:'space',text:"Uranus rotates on its side, tilted nearly 98° — probably because of a colossal collision in its youth."},
  {id:'sp32',cat:'space',text:"Jupiter's moon Io is the most volcanic world in the solar system: its hundreds of volcanoes spew sulfur hundreds of kilometers high."},
  {id:'sp33',cat:'space',text:"The hottest planet in the solar system isn't Mercury but Venus: its thick atmosphere keeps it near 465 °C, day and night."},
  {id:'sp34',cat:'space',text:"Despite being so close to the Sun, Mercury holds water ice at the bottom of polar craters where light never reaches."},
  {id:'sp35',cat:'space',text:"The Sun loses about 4 million tons of mass every second, converted into light and energy by nuclear fusion."},
  {id:'sp36',cat:'space',text:"Some neutron stars, called pulsars, spin hundreds of times per second, sweeping space with a regular beam."},
  {id:'sp37',cat:'space',text:"Enceladus, a small moon of Saturn, shoots geysers of icy water into space from an ocean hidden beneath its surface."},
  {id:'sp38',cat:'space',text:"The largest known stars are so gigantic that billions of Suns could fit inside them."},
  {id:'sp39',cat:'space',text:"The planet Neptune was discovered through mathematics: its position was calculated before it was ever seen through a telescope, in 1846."},
  {id:'sp40',cat:'space',text:"The light you receive from the Andromeda galaxy left it about 2.5 million years ago: you see it as it was long before humanity."},
  {id:'sp41',cat:'space',text:"There are 'rogue planets' drifting alone through the galaxy, orbiting no star at all."},
  {id:'sp42',cat:'space',text:"At the center of our galaxy lurks a supermassive black hole, Sagittarius A*, with a mass about 4 million times that of the Sun."},
  {id:'sp43',cat:'space',text:"Despite its giant size, Jupiter spins in only about 10 hours: it's the fastest-rotating planet in the solar system."},
  {id:'sp44',cat:'space',text:"Halley's Comet only comes near Earth about once every 76 years: its next return is expected in 2061."},
  {id:'sp45',cat:'space',text:"Part of the 'snow' that appeared on old untuned TVs came from the leftover radiation of the Big Bang."},
  {id:'sp46',cat:'space',text:"Unlike in the movies, the asteroid belt is almost empty: space probes fly through it without ever having to dodge rocks."},
  {id:'sp47',cat:'space',text:"Mars's largest moon, Phobos, is slowly spiraling toward the planet and will eventually break apart into a ring of debris."},
  {id:'sp48',cat:'space',text:"On the exoplanet HD 189733b, it likely rains molten glass — blown sideways by winds of nearly 8,700 km/h."},
  {id:'sp49',cat:'space',text:"The Oort Cloud, the source of many comets, may surround the solar system out to a quarter of the way to the nearest star."},
  {id:'sp50',cat:'space',text:"The star Betelgeuse is so enormous that, placed where the Sun is, it would swallow Mercury, Venus, Earth, and Mars."},
  // <<< SPACE
  // >>> ANIMALS (50 faits)
  {id:'a1',cat:'animals',text:"Octopuses have three hearts, blue blood, and nine brains — one central and one per tentacle, each capable of acting independently."},
  {id:'a2',cat:'animals',text:"Dolphins have names: they develop a unique whistle from birth and introduce themselves to each other using it."},
  {id:'a3',cat:'animals',text:"Tardigrades can survive in the vacuum of space, near absolute zero temperatures, and radiation doses lethal to every other living thing."},
  {id:'a4',cat:'animals',text:"Crows recognise human faces and remember them for years — they can even pass this information on to fellow crows."},
  {id:'a5',cat:'animals',text:"A snail can sleep for up to three years straight by entering hibernation during dry periods."},
  {id:'a6',cat:'animals',text:"The Turritopsis dohrnii jellyfish is biologically immortal: when it ages or is injured, it transforms back into a juvenile polyp."},
  {id:'a7',cat:'animals',text:"The pistol shrimp snaps its claw to generate a bubble at 4,700°C — briefly hotter than the surface of the Sun."},
  {id:'a8',cat:'animals',text:"Leafcutter ants have been farming fungi for 50 million years — long before human agriculture existed."},
  {id:'a9',cat:'animals',text:"Cows have best friends and suffer measurable stress when separated from them — their heart rate rises noticeably."},
  {id:'a10',cat:'animals',text:"Sea otters hold paws while sleeping so they don't drift apart in the current."},
  {id:'a11',cat:'animals',text:"Butterflies taste food with their feet — taste receptors let them know if a plant is edible before they even land."},
  {id:'a12',cat:'animals',text:"Elephants are the only land mammals physically incapable of jumping — their mass and skeleton simply don't allow it."},
  {id:'a13',cat:'animals',text:"A blue whale's heart is so large that a human could swim through its main arteries."},
  {id:'a14',cat:'animals',text:"Bees can recognise and remember human faces — a remarkable ability for an insect with a brain the size of a sesame seed."},
  {id:'a15',cat:'animals',text:"African grey parrots can learn over 1,000 words and understand concepts like color, shape, and the number zero."},
  {id:'a16',cat:'animals',text:"The whale shark is the largest fish in the world — it can reach up to 12 meters — but feeds mainly on plankton."},
  {id:'a17',cat:'animals',text:"Crocodiles cannot stick out their tongues. Their tongues are attached to the lower jaw by a ligament along their entire length."},
  {id:'a18',cat:'animals',text:"Lobsters don't die of old age biologically — they keep growing throughout their lives and typically die of exhaustion during moulting."},
  {id:'a19',cat:'animals',text:"Dolphins sleep with only one brain hemisphere at a time — the other stays awake for breathing and watching for predators."},
  {id:'a20',cat:'animals',text:"Sharks are older than trees. The first sharks appeared around 450 million years ago, while trees only evolved 350 million years ago."},
  {id:'a21',cat:'animals',text:"Elephants can sense seismic vibrations through their feet — they 'hear' the ground from kilometers away."},
  {id:'a22',cat:'animals',text:"The hummingbird is the only bird that can fly backward. Its wings beat up to 80 times per second."},
  {id:'a23',cat:'animals',text:"Rats laugh when tickled — an ultrasonic sound inaudible to humans, discovered by neuroscientist Jaak Panksepp."},
  {id:'a24',cat:'animals',text:"The axolotl can regenerate an entire limb, including bones, muscles, and nerves — in just a few weeks."},
  {id:'a25',cat:'animals',text:"Cats have a vomeronasal organ that lets them 'taste' smells. That's why they sometimes make that open-mouth grimace called flehmen."},
  {id:'a26',cat:'animals',text:"The archerfish spits a jet of water with remarkable precision to knock insects off branches above the water surface."},
  {id:'a27',cat:'animals',text:"Hippos secrete a red 'sweat' that acts as natural sunscreen and antibiotic against bacteria."},
  {id:'a28',cat:'animals',text:"New Caledonian crows craft and use tools — a cognitive ability long thought exclusive to primates."},
  {id:'a29',cat:'animals',text:"The mimic octopus can imitate the appearance and behavior of more than 15 different species to escape predators."},
  {id:'a30',cat:'animals',text:"Emperor penguins can dive to 500 meters deep and hold their breath for 22 minutes."},
  {id:'a31',cat:'animals',text:"The electric eel can produce a discharge of over 600 volts — enough to stun a horse or light dozens of bulbs."},
  {id:'a32',cat:'animals',text:"The mantis shrimp has the most complex vision in the animal kingdom: up to 16 types of photoreceptors, where the human eye has only three."},
  {id:'a33',cat:'animals',text:"Sloths can hold their breath for up to 40 minutes by slowing their heart rate — longer than most dolphins."},
  {id:'a34',cat:'animals',text:"Honeybees communicate by dancing: a 'waggle dance' tells their hive-mates the exact direction and distance of a food source."},
  {id:'a35',cat:'animals',text:"The naked mole-rat barely feels pain, resists cancer, and can live over 30 years — ten times a mouse's lifespan."},
  {id:'a36',cat:'animals',text:"The pangolin is the only mammal in the world entirely covered in scales; when threatened, it rolls into a ball so tight no predator can open it."},
  {id:'a37',cat:'animals',text:"Tigers aren't just striped in fur: their skin itself carries the stripes, and each pattern is unique like a fingerprint."},
  {id:'a38',cat:'animals',text:"The platypus is one of the few venomous mammals, detects prey through the electricity of their muscles, and glows green under ultraviolet light."},
  {id:'a39',cat:'animals',text:"Despite its towering neck, the giraffe has exactly seven neck vertebrae — the same number as humans and nearly all mammals."},
  {id:'a40',cat:'animals',text:"Owls can't move their eyes in their sockets: to compensate, they rotate their heads up to 270 degrees without rupturing their blood vessels."},
  {id:'a41',cat:'animals',text:"Koalas have fingerprints so similar to humans' that they can fool even a microscope."},
  {id:'a42',cat:'animals',text:"The starfish has no brain and no blood: it moves using a seawater hydraulic system and 'sees' with eyes at the tips of its arms."},
  {id:'a43',cat:'animals',text:"Reindeer eyes change color with the seasons: golden in summer, they turn deep blue in winter to better capture the faint polar light."},
  {id:'a44',cat:'animals',text:"The wood frog can freeze solid in winter — heart stopped, no breathing — then thaw and come back to life in spring."},
  {id:'a45',cat:'animals',text:"The narwhal's tusk isn't a horn but a giant spiraled tooth, riddled with millions of nerve endings that sense the water's salinity."},
  {id:'a46',cat:'animals',text:"The Greenland shark is the longest-living vertebrate known: it can live between 250 and 500 years, and only reaches maturity at 150."},
  {id:'a47',cat:'animals',text:"The Australian lyrebird perfectly mimics almost any sound it hears: other birds, chainsaws, car alarms, and even camera shutters."},
  {id:'a48',cat:'animals',text:"The star-nosed mole has 22 tentacles on its snout and eats faster than any other mammal: it identifies and swallows prey in a quarter of a second."},
  {id:'a49',cat:'animals',text:"Vampire bats share their meal of blood: a female regurgitates part of her haul to feed a starving roost-mate — and remembers who shares back."},
  {id:'a50',cat:'animals',text:"The chameleon's tongue shoots out faster than a race car: it goes from 0 to 100 km/h in a hundredth of a second to snatch its prey."},
  // <<< ANIMALS
  // >>> BODY (50 faits)
  {id:'b1',cat:'body',text:"The DNA in just one of your cells measures about two metres long; the DNA in your entire body stretches more than 1,000 times the Earth-Sun distance."},
  {id:'b2',cat:'body',text:"Your brain generates around 70,000 thoughts a day and uses 20% of your total body energy — yet it makes up only 2% of your mass."},
  {id:'b3',cat:'body',text:"Human bones are stronger than steel by weight — a 2.5 cm cube of bone can withstand nine tonnes of pressure."},
  {id:'b4',cat:'body',text:"Your stomach produces a new mucous lining every two weeks — otherwise it would digest itself with the acid it produces."},
  {id:'b5',cat:'body',text:"The human heart generates enough pressure to shoot blood 8 metres into the air — and beats 100,000 times a day without ever resting."},
  {id:'b6',cat:'body',text:"The corneas of your eyes are the only tissues in the human body that receive no blood — they absorb oxygen directly from tears and air."},
  {id:'b7',cat:'body',text:"The liver is the only human organ capable of fully regenerating from just 25% of its original mass."},
  {id:'b8',cat:'body',text:"You are about 1 cm taller in the morning than in the evening — the gradual compression of intervertebral cartilage throughout the day is the cause."},
  {id:'b9',cat:'body',text:"Babies are born with around 300 bones, but some fuse as they grow — an adult retains only 206."},
  {id:'b10',cat:'body',text:"It's impossible to tickle yourself: your brain anticipates the sensation and cancels the signal before it reaches your consciousness."},
  {id:'b11',cat:'body',text:"The total surface area of your lungs, if unfolded, would cover about 70 square meters — the size of a small apartment."},
  {id:'b12',cat:'body',text:"Fingernails grow four times faster than toenails. The dominant hand's nails grow slightly faster than the other hand's."},
  {id:'b13',cat:'body',text:"The human nose can detect more than one trillion different smells — 10,000 times more than scientists believed two decades ago."},
  {id:'b14',cat:'body',text:"The human body contains enough iron to forge a 7 cm nail. Almost all of it is found in haemoglobin inside red blood cells."},
  {id:'b15',cat:'body',text:"Your skeleton completely renews itself every 10 years — by age 30, you don't have a single bone from birth."},
  {id:'b16',cat:'body',text:"Fingerprints form as early as week 17 of pregnancy, shaped by random pressures on the fingers inside the womb."},
  {id:'b17',cat:'body',text:"The human body produces about 25 million new cells every second — faster than you can count them."},
  {id:'b18',cat:'body',text:"Human tooth enamel is as hard as shark teeth. Enamel is the hardest tissue in the human body, as resistant as some minerals."},
  {id:'b19',cat:'body',text:"The human brain contains around 86 billion neurons, each capable of forming up to 10,000 synaptic connections."},
  {id:'b20',cat:'body',text:"Bone is four times stronger than reinforced concrete by volume. The femur can withstand up to 1,700 kg of pressure before breaking."},
  {id:'b21',cat:'body',text:"The human brain uses 20% of the body's oxygen but makes up only 2% of its mass — it's the most energy-hungry organ."},
  {id:'b22',cat:'body',text:"Your body contains enough carbon to make about 9,000 pencils."},
  {id:'b23',cat:'body',text:"Tears of sadness, joy, and onion-cutting have different chemical compositions — emotional tears contain more stress proteins."},
  {id:'b24',cat:'body',text:"The human gut hosts about 100 trillion bacteria — ten times more than the total number of human cells in your body."},
  {id:'b25',cat:'body',text:"The strongest muscle in the human body relative to its size is the masseter — the jaw muscle, capable of exerting 70 kg of force."},
  {id:'b26',cat:'body',text:"Your eyes process 36,000 pieces of information per hour. Over a lifetime, they'll see the equivalent of 24 million images."},
  {id:'b27',cat:'body',text:"The human body emits a very faint bioluminescent glow — 1,000 times too weak to be seen by the naked eye."},
  {id:'b28',cat:'body',text:"Brain neurons communicate at speeds up to 430 km/h — as fast as a Formula 1 car."},
  {id:'b29',cat:'body',text:"Blood travels about 19,000 km per day through your body — nearly half the circumference of the Earth."},
  {id:'b30',cat:'body',text:"Your tongue has a unique print, just like your fingerprints — no other person in the world has the same one."},
  {id:'b31',cat:'body',text:"Your stomach acid is strong enough to dissolve metal — but a constantly renewed layer of mucus stops the stomach from digesting itself."},
  {id:'b32',cat:'body',text:"You can't breathe and swallow at the same time: your body automatically switches between the two so food never goes into your lungs."},
  {id:'b33',cat:'body',text:"The human eye can distinguish about 10 million different colors, thanks to three types of sensors tuned to red, green, and blue."},
  {id:'b34',cat:'body',text:"A large part of the dust in your home is you: the human body sheds tens of thousands of dead skin cells every minute."},
  {id:'b35',cat:'body',text:"Hiccups are a sudden, involuntary contraction of the diaphragm, the large muscle separating the lungs from the belly."},
  {id:'b36',cat:'body',text:"The smallest bone in the human body is in the ear: the stapes is only about 3 millimeters long."},
  {id:'b37',cat:'body',text:"Goosebumps are a reflex inherited from our furry ancestors: the hairs stand up to puff out the fur — useless in now nearly hairless humans."},
  {id:'b38',cat:'body',text:"Your ears and nose seem never to stop growing: the cartilage they're made of keeps changing throughout life."},
  {id:'b39',cat:'body',text:"The brain feels no pain: it has no pain receptors, which is why surgery can be done on a patient who is awake."},
  {id:'b40',cat:'body',text:"Humans are among the only animals to have a chin: even our cousins like the Neanderthals lacked one."},
  {id:'b41',cat:'body',text:"Without saliva, you'd taste almost nothing: a food's molecules must first dissolve in the liquid of your mouth to reach your taste buds."},
  {id:'b42',cat:'body',text:"The appendix may not be useless: it could act as a safe house for the gut's good bacteria, reseeding them after illness."},
  {id:'b43',cat:'body',text:"You blink between 15 and 20 times a minute, which adds up to spending several hours a day with your eyes closed."},
  {id:'b44',cat:'body',text:"The femur, the thigh bone, is both the longest and strongest bone in the human body: it can bear up to 30 times the body's weight."},
  {id:'b45',cat:'body',text:"An adult carries about 5 liters of blood, roughly 8% of their total body weight."},
  {id:'b46',cat:'body',text:"Earwax is actually a form of sweat: it's produced by glands related to those that make perspiration."},
  {id:'b47',cat:'body',text:"Your heart is roughly the size of your clenched fist, and beats about 100,000 times a day without ever stopping."},
  {id:'b48',cat:'body',text:"Yawning may help cool the brain: by drawing in a big gulp of air, it could lower the brain's temperature by a fraction of a degree."},
  {id:'b49',cat:'body',text:"The largest organ of the human body isn't internal: it's the skin, covering about 2 m² and weighing up to 4 kg."},
  {id:'b50',cat:'body',text:"The human body is about 60% water — and the brain itself is nearly 75% water."},
  // <<< BODY
  // >>> ARTS (50 faits)
  {id:'ar1',cat:'arts',text:"Salvador Dalí would often draw on the back of his restaurant cheques, knowing the owners would never cash them rather than give up the original artwork."},
  {id:'ar2',cat:'arts',text:"The Mona Lisa has no eyebrows — it was fashionable during the Renaissance to shave them completely off."},
  {id:'ar3',cat:'arts',text:"Victor Hugo wrote most of his works, including Les Misérables, standing at a lectern — a habit he kept his entire life."},
  {id:'ar4',cat:'arts',text:"Paranormal Activity cost $15,000 to make and grossed $193 million — one of the best returns on investment in cinema history."},
  {id:'ar5',cat:'arts',text:"Mozart composed his first symphony at age 8 — and his father had been taking him to perform at European royal courts since he was 6."},
  {id:'ar6',cat:'arts',text:"Ancient Greek statues were not white — they were painted in vivid colours. Time erased the pigments, leaving us to think they were always bare marble."},
  {id:'ar7',cat:'arts',text:"Michael Jackson tried to buy Marvel in the 1990s because he desperately wanted to play Spider-Man in a movie."},
  {id:'ar8',cat:'arts',text:"The Eiffel Tower was meant to be demolished 20 years after it was built — it was saved by its usefulness as a military radio antenna."},
  {id:'ar9',cat:'arts',text:"The Oscar statuette is called 'Oscar' because an Academy librarian thought it looked like her uncle of the same name."},
  {id:'ar10',cat:'arts',text:"In 1911, Picasso was arrested and questioned as a suspect in the theft of the Mona Lisa from the Louvre."},
  {id:'ar11',cat:'arts',text:"It was the 1911 theft of the Mona Lisa that made it world-famous — before that, it was largely unknown to the general public."},
  {id:'ar12',cat:'arts',text:"Minecraft is the best-selling video game in history with over 300 million copies — ahead of Tetris and GTA V."},
  {id:'ar13',cat:'arts',text:"Beethoven was deaf when he composed his Ninth Symphony — he never heard it, and reportedly wept upon seeing the audience applaud."},
  {id:'ar14',cat:'arts',text:"The most expensive painting ever sold at auction is da Vinci's 'Salvator Mundi', which fetched $450.3 million at Christie's in 2017."},
  {id:'ar15',cat:'arts',text:"Edvard Munch's The Scream was stolen twice from the same Oslo museum — in 1994 and 2004 — before being recovered each time."},
  {id:'ar16',cat:'arts',text:"Beethoven composed some of his greatest works, including the 9th Symphony, after becoming completely deaf."},
  {id:'ar17',cat:'arts',text:"The Louvre in Paris is the most visited museum in the world, welcoming around 9 million visitors per year."},
  {id:'ar18',cat:'arts',text:"Frida Kahlo painted 55 self-portraits out of her 143 paintings, saying she painted herself because she knew herself better than anyone."},
  {id:'ar19',cat:'arts',text:"International Klein Blue was patented by Yves Klein in 1960 — an ultramarine so intense he registered it as his own intellectual property."},
  {id:'ar20',cat:'arts',text:"Michelangelo painted the Sistine Chapel in four years, from 1508 to 1512. He stood on scaffolding — he did not lie on his back."},
  {id:'ar21',cat:'arts',text:"Van Gogh only sold one painting in his lifetime — The Red Vineyard — today his works are worth hundreds of millions."},
  {id:'ar22',cat:'arts',text:"Rodin's The Thinker doesn't depict a philosopher — it's Dante contemplating Hell, designed for the Museum of Decorative Arts."},
  {id:'ar23',cat:'arts',text:"Ultramarine blue cost more than gold in the Middle Ages — made from Afghan lapis lazuli, it was reserved for the Virgin Mary."},
  {id:'ar24',cat:'arts',text:"Banksy installed a shredder inside the frame of Girl with Balloon, which self-destructed mid-auction at Sotheby's in 2018."},
  {id:'ar25',cat:'arts',text:"Claude Monet painted over 250 water lily paintings in his garden at Giverny over the last 30 years of his life."},
  {id:'ar26',cat:'arts',text:"Picasso's Guernica measures 3.5m × 7.8m and was painted in response to the bombing of the Basque town in 1937."},
  {id:'ar27',cat:'arts',text:"The first film in history, Workers Leaving the Lumière Factory, lasts only 46 seconds — shot in 1895 in Lyon."},
  {id:'ar28',cat:'arts',text:"Michelangelo considered sculpture superior to painting — the Sistine Chapel was for him a chore imposed by the Pope."},
  {id:'ar29',cat:'arts',text:"The Starry Night was painted by Van Gogh from his window at the asylum in Saint-Rémy-de-Provence in 1889."},
  {id:'ar30',cat:'arts',text:"Street art was illegal everywhere 30 years ago — today, some works are protected by cities and worth millions."},
  {id:'ar31',cat:'arts',text:"Picasso's full name has 23 words: Pablo Diego José Francisco de Paula Juan Nepomuceno María de los Remedios Cipriano de la Santísima Trinidad Ruiz y Picasso."},
  {id:'ar32',cat:'arts',text:"Hokusai painted his famous 'Great Wave' around age 70 and changed his artist name more than 30 times over his career."},
  {id:'ar33',cat:'arts',text:"For centuries, painters used a color called 'mummy brown' — a pigment literally made from ground-up Egyptian mummies."},
  {id:'ar34',cat:'arts',text:"Rembrandt painted, drew, or etched nearly 80 self-portraits during his life — a unique chronicle of a face aging in art history."},
  {id:'ar35',cat:'arts',text:"The Venus de Milo lost her arms before she was even discovered in 1820 — and no one has ever found what she was holding."},
  {id:'ar36',cat:'arts',text:"One of the deepest blacks ever made, Vantablack, absorbs over 99.9% of light — and a single artist, Anish Kapoor, secured exclusive artistic rights to it, sparking a 'pigment war.'"},
  {id:'ar37',cat:'arts',text:"For 'The Kiss,' Gustav Klimt used real gold leaf, a legacy of his father who was a gold engraver."},
  {id:'ar38',cat:'arts',text:"Andy Warhol's 'Campbell's Soup Cans' consists of 32 canvases — one for each soup variety the brand sold at the time."},
  {id:'ar39',cat:'arts',text:"In 1917, Marcel Duchamp presented an upturned urinal as a work of art titled 'Fountain' — a gesture that upended all of 20th-century art."},
  {id:'ar40',cat:'arts',text:"The oldest known figurative cave painting is in Indonesia: a wild pig painted at least 45,500 years ago."},
  {id:'ar41',cat:'arts',text:"The master of chiaroscuro, Caravaggio, was also a murderer: sentenced to death for killing a man in 1606, he painted on the run until his death."},
  {id:'ar42',cat:'arts',text:"The Terracotta Army of China's first emperor numbers nearly 8,000 life-size soldiers — and no two have the same face."},
  {id:'ar43',cat:'arts',text:"Beneath a perfectly realistic pipe, René Magritte wrote 'This is not a pipe' — because it is indeed only an image of a pipe, not a real one."},
  {id:'ar44',cat:'arts',text:"It was Salvador Dalí who designed the Chupa Chups lollipop logo in 1969 — the yellow daisy we still know today."},
  {id:'ar45',cat:'arts',text:"Leonardo da Vinci's 'The Last Supper' began deteriorating in his own lifetime: he used an experimental technique that didn't hold on the wall."},
  {id:'ar46',cat:'arts',text:"In 2012, an amateur Spanish restorer botched the touch-up of a fresco of Christ so badly that the result, nicknamed 'Monkey Christ,' became a tourist attraction."},
  {id:'ar47',cat:'arts',text:"Michelangelo's 'David' was carved from a huge block of marble that two other sculptors had deemed unusable and abandoned for 25 years."},
  {id:'ar48',cat:'arts',text:"The Bayeux 'Tapestry' is not a tapestry but an embroidery nearly 70 meters long, telling the story of the 1066 conquest of England."},
  {id:'ar49',cat:'arts',text:"Japanese artist Yayoi Kusama, famous for her polka dots and 'infinity rooms,' has voluntarily lived in a psychiatric hospital since 1977."},
  {id:'ar50',cat:'arts',text:"Rembrandt's 'The Night Watch' was cut down in 1715 to fit between two doors in Amsterdam's town hall — figures were lost forever."},
  // <<< ARTS
  // >>> INVENTIONS (50 faits)
  {id:'inv1',cat:'inventions',text:"The microwave was invented by accident in 1945 when an engineer noticed his chocolate had melted in his pocket near a radar device."},
  {id:'inv2',cat:'inventions',text:"Post-it Notes were born from a failed glue — Spencer Silver was trying to make a super-strong adhesive and got one so weak it barely held anything, yet stuck indefinitely."},
  {id:'inv3',cat:'inventions',text:"Penicillin was discovered because Fleming left his Petri dishes unattended when he went on holiday — a mould had killed the bacteria in his absence."},
  {id:'inv4',cat:'inventions',text:"Velcro was invented after a Swiss engineer noticed burdock burrs stuck to his jacket and examined their hooks under a microscope."},
  {id:'inv5',cat:'inventions',text:"The Frisbee came from the metal pie tins of a bakery called the 'Frisbie Pie Company', which students would throw around for fun."},
  {id:'inv6',cat:'inventions',text:"Wi-Fi technology was developed from Australian research on radio signals from black holes — a space technology recycled for our home routers."},
  {id:'inv7',cat:'inventions',text:"The lighter was invented in 1823, three years before the friction match — instant fire preceded the humble matchstick."},
  {id:'inv8',cat:'inventions',text:"The first computer, ENIAC, weighed 30 tonnes and filled an entire 167 m² room — less powerful than a modern pocket calculator."},
  {id:'inv9',cat:'inventions',text:"Tarte Tatin was born from a mistake by the Tatin sisters, who forgot the pastry and added it on top of the already-caramelised apples."},
  {id:'inv10',cat:'inventions',text:"X-rays were discovered by accident in 1895: Röntgen noticed a photographic plate glowing at a distance through opaque objects."},
  {id:'inv11',cat:'inventions',text:"Bubble wrap was originally meant to be a textured 3D wallpaper — a total commercial flop that was repurposed as packaging material."},
  {id:'inv12',cat:'inventions',text:"The stethoscope was invented in 1816 by René Laennec who, embarrassed to press his ear to a female patient's chest, rolled a sheet of paper into a tube."},
  {id:'inv13',cat:'inventions',text:"The automatic washing machine was invented in 1937 — before that, doing laundry took an entire day of manual labor."},
  {id:'inv14',cat:'inventions',text:"Aspirin, synthesised in 1897, is one of the best-selling drugs in history. Egyptians already used willow bark — containing the same active compound."},
  {id:'inv15',cat:'inventions',text:"Alexander Graham Bell filed his telephone patent on 14 February 1876 — just two hours before his competitor Elisha Gray."},
  {id:'inv16',cat:'inventions',text:"The World Wide Web and the Internet are not the same thing. The web was invented by Tim Berners-Lee in 1989 and runs on top of the Internet."},
  {id:'inv17',cat:'inventions',text:"Kevlar, five times stronger than steel by weight, was discovered in 1965 by DuPont chemist Stephanie Kwolek."},
  {id:'inv18',cat:'inventions',text:"GPS was initially developed by the US military during the Cold War and was only made available to civilians in 2000."},
  {id:'inv19',cat:'inventions',text:"GPS is free for the world to use but maintained solely by the US military, which bears an estimated $2 billion annual operating cost."},
  {id:'inv20',cat:'inventions',text:"Eyeglasses were invented in Italy around 1286, but craftsmen kept the process secret for three centuries to protect their monopoly."},
  {id:'inv21',cat:'inventions',text:"The jet engine was independently invented by two men who didn't know each other — Frank Whittle in England and Hans von Ohain in Germany."},
  {id:'inv22',cat:'inventions',text:"The barcode was inspired by Morse code: its inventor, Norman Woodland, traced dots and dashes in the sand on a beach."},
  {id:'inv23',cat:'inventions',text:"The first safety elevator was demonstrated by Elisha Otis in 1854 — he stood inside and cut the cable in front of an audience."},
  {id:'inv24',cat:'inventions',text:"The pacemaker was invented by accident in 1956 when Wilson Greatbatch inserted the wrong resistor into a circuit."},
  {id:'inv25',cat:'inventions',text:"Lego plastic is so precise that two bricks made 60 years apart still fit together perfectly."},
  {id:'inv26',cat:'inventions',text:"The first SMS in history, sent in 1992, simply said 'Merry Christmas.'"},
  {id:'inv27',cat:'inventions',text:"The zipper took 20 years to catch on — invented in 1893, it didn't become common until after World War I."},
  {id:'inv28',cat:'inventions',text:"Teflon was discovered by accident in 1938 — chemist Roy Plunkett found a slippery white residue inside a gas canister."},
  {id:'inv29',cat:'inventions',text:"Dynamite was invented by Alfred Nobel, who then created the Nobel Prize to offset the destruction caused by his invention."},
  {id:'inv30',cat:'inventions',text:"The first digital camera, created by Kodak in 1975, weighed 3.6 kg and took 0.01 megapixel images."},
  {id:'inv31',cat:'inventions',text:"The Slinky, the spring that 'walks' down stairs, was born by accident in 1943 when a spring fell off a table in front of a naval engineer."},
  {id:'inv32',cat:'inventions',text:"Play-Doh modeling clay was originally sold as a product to clean wallpaper."},
  {id:'inv33',cat:'inventions',text:"Super Glue was discovered by accident, deemed useless, then forgotten — it took two 'rediscoveries' before it became a commercial adhesive."},
  {id:'inv34',cat:'inventions',text:"Charles Goodyear discovered how to make rubber strong and durable by accident, dropping a mixture onto a hot stove."},
  {id:'inv35',cat:'inventions',text:"Saccharin, the first artificial sweetener, was discovered because a chemist forgot to wash his hands before eating."},
  {id:'inv36',cat:'inventions',text:"The ice pop (Popsicle) was invented by an 11-year-old, who left a soda with its stirring stick outside on a freezing night."},
  {id:'inv37',cat:'inventions',text:"The automatic dishwasher was invented in 1886 by a woman, Josephine Cochrane, tired of her servants chipping her fine china."},
  {id:'inv38',cat:'inventions',text:"Braille, the raised writing for the blind, was inspired by a secret military code designed to read messages in the dark."},
  {id:'inv39',cat:'inventions',text:"The QWERTY keyboard layout was designed in part to slow typing and keep the bars of old typewriters from jamming."},
  {id:'inv40',cat:'inventions',text:"The world's very first webcam was created to watch... a coffee pot, so people could remotely check if it was full, at the University of Cambridge."},
  {id:'inv41',cat:'inventions',text:"Bluetooth is named after a Viking king, Harald 'Bluetooth,' and its logo combines his initials written in runic letters."},
  {id:'inv42',cat:'inventions',text:"The safety pin was invented in just a few hours, in 1849, by a man simply trying to pay off a 15-dollar debt."},
  {id:'inv43',cat:'inventions',text:"The very first vaccine, against smallpox in 1796, used cowpox — which is where the word 'vaccine' comes from, the Latin vacca, meaning cow."},
  {id:'inv44',cat:'inventions',text:"The cash register was invented by a saloon owner to stop his employees from stealing money from him."},
  {id:'inv45',cat:'inventions',text:"The inventor of roller skates made a memorable debut: at his first public demonstration, around 1760, he crashed straight into a large mirror."},
  {id:'inv46',cat:'inventions',text:"The very first computer program in history was written in the 1840s by Ada Lovelace — long before any computer existed."},
  {id:'inv47',cat:'inventions',text:"The QR code was invented in 1994 in Japan to track car parts in automobile factories."},
  {id:'inv48',cat:'inventions',text:"The first public demonstration of anesthesia took place in 1846: a patient was operated on painlessly thanks to ether."},
  {id:'inv49',cat:'inventions',text:"The inventor of Vaseline was so convinced of his product that he ate a spoonful of it every day — he lived to 96."},
  {id:'inv50',cat:'inventions',text:"The automatic pop-up toaster was invented before sliced bread: for years, you had to slice your own bread before toasting it."},
  // <<< INVENTIONS
  // >>> WORLD (50 faits)
  {id:'w1',cat:'world',text:"In Switzerland, it is illegal to own just one guinea pig — the law requires at least two, as isolation is considered animal cruelty for such social animals."},
  {id:'w2',cat:'world',text:"Canada has more lakes than all other countries in the world combined — about 60% of the planet's lakes lie within its borders."},
  {id:'w3',cat:'world',text:"In France, it is legally possible to marry a deceased person — under certain conditions and with the President's authorisation."},
  {id:'w4',cat:'world',text:"Australia is wider than the Moon — the continent spans 4,000 km from east to west, while the Moon's diameter is only 3,474 km."},
  {id:'w5',cat:'world',text:"Russia spans 11 time zones — when it's noon in Moscow, it's already 11 pm at the country's eastern tip."},
  {id:'w6',cat:'world',text:"Nepal's flag is the only national flag in the world that is neither square nor rectangular — it's two stacked triangles."},
  {id:'w7',cat:'world',text:"There are statistically more plastic flamingos than real flamingos on the planet."},
  {id:'w8',cat:'world',text:"Russia's land area is larger than the dwarf planet Pluto — 17 million km² vs 16.6 million for Pluto."},
  {id:'w9',cat:'world',text:"Iceland is one of the few places on Earth with absolutely no mosquitoes — the climate and geology simply don't support them."},
  {id:'w10',cat:'world',text:"On Japan's island of Okunoshima, the entire island is populated by friendly wild rabbits — former lab animals abandoned after World War II."},
  {id:'w11',cat:'world',text:"Liechtenstein and Uzbekistan are the only two doubly landlocked countries — surrounded entirely by other landlocked countries."},
  {id:'w12',cat:'world',text:"France has more time zones than any other country — 12 in total — thanks to its overseas territories spread across every continent."},
  {id:'w13',cat:'world',text:"Mongolia is the least densely populated country in the world, with only 2 inhabitants per square kilometer."},
  {id:'w14',cat:'world',text:"In Norway, there is a village called Å — the shortest place name in the world. Just one letter, meaning 'river' in Old Norse."},
  {id:'w15',cat:'world',text:"Lake Baikal in Russia contains about 20% of the world's unfrozen fresh water."},
  {id:'w16',cat:'world',text:"Mount Chimborazo in Ecuador is the point on Earth farthest from the planet's centre, surpassing Everest thanks to the equatorial bulge."},
  {id:'w17',cat:'world',text:"The Amazon River accounts for about 20% of all freshwater that flows into the world's oceans each day."},
  {id:'w18',cat:'world',text:"The Gambia is almost entirely surrounded by Senegal — it stretches inland like a long tongue, with only a short Atlantic coastline."},
  {id:'w19',cat:'world',text:"Antarctica is the world's largest and driest desert, with average annual precipitation under 200 mm — drier than the Sahara."},
  {id:'w20',cat:'world',text:"The Dead Sea is 430 metres below sea level. Its salinity is so high that swimmers float effortlessly without any effort."},
  {id:'w21',cat:'world',text:"North Korea and Finland are separated by just one country — Russia is so vast it connects them."},
  {id:'w22',cat:'world',text:"Japan has over 6,800 islands, but only 421 are inhabited — the rest are left to nature."},
  {id:'w23',cat:'world',text:"The town of Whittier, Alaska, houses nearly all its 300 residents in a single building — the school, police, and clinic are also inside."},
  {id:'w24',cat:'world',text:"There are more pyramids in Sudan than in Egypt — about 200 Nubian pyramids versus 130 Egyptian ones."},
  {id:'w25',cat:'world',text:"The Vatican is the smallest country in the world at 0.44 km² — but it has its own post office, radio station, and pharmacy."},
  {id:'w26',cat:'world',text:"Lake Baikal in Russia is so deep (1,642 m) that it alone contains 20% of the world's unfrozen freshwater."},
  {id:'w27',cat:'world',text:"Ethiopia has its own calendar with 13 months — it's about 7 years behind the Gregorian calendar."},
  {id:'w28',cat:'world',text:"There's a village in Norway called 'Hell' — it freezes over in winter, literally making 'Hell freeze over.'"},
  {id:'w29',cat:'world',text:"The Netherlands is so flat that its highest point, the Vaalserberg, is only 322 meters — some buildings elsewhere are taller."},
  {id:'w30',cat:'world',text:"Bhutan measures its development with a Gross National Happiness indicator rather than traditional GDP."},
  {id:'w31',cat:'world',text:"Lesotho is one of only three countries in the world entirely surrounded by a single other country — here, South Africa."},
  {id:'w32',cat:'world',text:"The Sahara Desert was green and dotted with lakes about 6,000 years ago, home to hippos, giraffes, and humans."},
  {id:'w33',cat:'world',text:"Istanbul is the only major city in the world spanning two continents: part in Europe, part in Asia, separated by a strait."},
  {id:'w34',cat:'world',text:"Mount Everest grows about 4 millimeters taller each year: the collision of tectonic plates keeps pushing the Himalayas up."},
  {id:'w35',cat:'world',text:"Africa is so vast that the United States, China, India, and much of Europe could all fit inside its borders."},
  {id:'w36',cat:'world',text:"In the twin villages of Baarle, on the Belgian-Dutch border, the boundary winds through houses, gardens, and even cafés."},
  {id:'w37',cat:'world',text:"The Trans-Siberian Railway is the longest railway line in the world: nearly 9,300 km and eight time zones crossed."},
  {id:'w38',cat:'world',text:"Greenland is the world's largest island, yet nearly 80% of its surface is covered by an ice sheet."},
  {id:'w39',cat:'world',text:"In Turkmenistan, a gas crater nicknamed the 'Door to Hell' has been burning non-stop since 1971."},
  {id:'w40',cat:'world',text:"La Rinconada, in Peru, is the highest permanently inhabited town in the world, perched at about 5,100 meters."},
  {id:'w41',cat:'world',text:"Two islands, one American and one Russian, are only about 4 km apart — yet the date line means there's nearly a full day between them."},
  {id:'w42',cat:'world',text:"Kiribati, in the Pacific, straddles the date line: it's the first country in the world to celebrate each new year."},
  {id:'w43',cat:'world',text:"The Maldives is the lowest-lying country in the world: its average elevation is only about 1.5 meters above the sea."},
  {id:'w44',cat:'world',text:"The Danakil Depression in Ethiopia is one of the hottest inhabited places on Earth, with an average annual temperature near 35 °C."},
  {id:'w45',cat:'world',text:"Bir Tawil, a strip of land between Egypt and Sudan, is one of the only territories on the planet that no country wants to claim."},
  {id:'w46',cat:'world',text:"The world's largest cave, Son Doong in Vietnam, is so vast it holds its own jungle, river, and even clouds."},
  {id:'w47',cat:'world',text:"The Caspian Sea isn't really a sea: it's the largest lake in the world, a huge body of water with no link to the oceans."},
  {id:'w48',cat:'world',text:"Measured from its base on the ocean floor, the Hawaiian mountain Mauna Kea is far taller than Everest: over 10,000 meters in all."},
  {id:'w49',cat:'world',text:"Norway's coastline is so carved up by fjords that, stretched out in a straight line, it could circle the Earth more than twice."},
  {id:'w50',cat:'world',text:"Nauru, a tiny Pacific island, was once the richest country per person in the world — thanks to mountains of bird droppings."},
  // <<< WORLD
  // >>> LANGUAGE (50 faits)
  {id:'l1',cat:'language',text:"The word 'robot' comes from the Czech 'robota', meaning 'forced labour' — coined by writer Karel Čapek in a 1920 play."},
  {id:'l2',cat:'language',text:"Japanese has a unique word for the light that filters through tree leaves: 'komorebi' — a concept so specific it has no direct English equivalent."},
  {id:'l3',cat:'language',text:"The word 'salary' comes from the Latin 'salarium' — the ration of salt given to Roman soldiers, salt being as precious as gold at the time."},
  {id:'l4',cat:'language',text:"The word 'berserk' comes from Viking warriors called berserkers — fighters who entered a battle rage, sometimes biting their own shield."},
  {id:'l5',cat:'language',text:"English borrowed more than 30% of its vocabulary from French following the Norman Conquest of 1066 — 'beef', 'pork', and 'justice' are all French-origin words."},
  {id:'l6',cat:'language',text:"'OK' may come from 'Oll Korrect', a deliberate misspelling that went viral in American newspapers as early as 1839."},
  {id:'l7',cat:'language',text:"The dot above the letters 'i' and 'j' in English has a name: it's called a 'tittle' — a word almost no one knows but that has existed since the Middle Ages."},
  {id:'l8',cat:'language',text:"The word 'emoji' comes from the Japanese 'e' (image) and 'moji' (letter/character) — it has no connection to the word 'emotion'."},
  {id:'l9',cat:'language',text:"The word 'whisky' literally means 'water of life' in Irish Gaelic — just like 'eau-de-vie' in French."},
  {id:'l10',cat:'language',text:"The word 'set' in English has the largest number of definitions in the Oxford Dictionary — more than 430 distinct meanings recorded."},
  {id:'l11',cat:'language',text:"Japanese uses at least four different writing systems simultaneously: hiragana, katakana, kanji and rōmaji."},
  {id:'l12',cat:'language',text:"Arabic is written right to left, except for numerals. The so-called Arabic numerals we use actually originated in India."},
  {id:'l13',cat:'language',text:"The word 'ketchup' comes from the Chinese 'kê-tsiap', a fermented fish sauce imported to Europe in the 17th century."},
  {id:'l14',cat:'language',text:"The language with the most native speakers is Mandarin Chinese, with around 920 million people. English ranks third, behind Spanish."},
  {id:'l15',cat:'language',text:"Whistling is a genuine language in mountain villages of the Canary Islands and Turkey. Silbo Gomero is listed as UNESCO intangible heritage."},
  {id:'l16',cat:'language',text:"The word 'quiz' reportedly appeared in Dublin in 1791, when a theatre manager bet he could introduce a new word overnight by chalking it across the city."},
  {id:'l17',cat:'language',text:"Pirahã, spoken by an Amazonian tribe, has no words for colours, no numbers, and no grammatical tense for past or future events."},
  {id:'l18',cat:'language',text:"French is the only language spoken on five continents as an official language, holding official status in 29 countries worldwide."},
  {id:'l19',cat:'language',text:"The Korean alphabet (hangul) was created in 1443 by King Sejong the Great so that common people could easily read and write."},
  {id:'l20',cat:'language',text:"Sign language is not universal. French Sign Language and American Sign Language are very different from each other."},
  {id:'l21',cat:'language',text:"The word 'pantaloon' comes from Pantalone, a commedia dell'arte character who wore tight-fitting hose."},
  {id:'l22',cat:'language',text:"In Finnish, 'kalsarikännit' means drinking alone at home in your underwear — a concept so common it has its own official emoji."},
  {id:'l23',cat:'language',text:"The word 'assassin' comes from the Arabic 'hashshashin' — members of a medieval sect who, legend says, consumed hashish."},
  {id:'l24',cat:'language',text:"There's no word for 'please' in Icelandic — politeness is conveyed through other sentence constructions."},
  {id:'l25',cat:'language',text:"The word 'muscle' comes from the Latin 'musculus' meaning 'little mouse' — Romans thought flexing biceps looked like a mouse under the skin."},
  {id:'l26',cat:'language',text:"Inuktitut, the Inuit language, has over 50 words to describe different types of snow and ice."},
  {id:'l27',cat:'language',text:"The word 'cravat' comes from 'Croat' — 17th-century Croatian mercenaries wore knotted scarves that started a fashion trend in France."},
  {id:'l28',cat:'language',text:"The 'lorem ipsum' used in typography is an altered Latin text by Cicero, deliberately garbled since the 16th century."},
  {id:'l29',cat:'language',text:"Basque (Euskara) is the only European language with no known relatives — its linguistic family remains a complete mystery."},
  {id:'l30',cat:'language',text:"The word 'chandelier' comes from the French 'chandelle' (candle) — borrowed directly into English with a French-style pronunciation."},
  {id:'l31',cat:'language',text:"The word 'avocado' comes from the Aztec word 'ahuacatl,' which also meant... testicle, because of the fruit's shape."},
  {id:'l32',cat:'language',text:"The word 'quarantine' comes from the Italian 'quaranta giorni,' the 40 days of isolation imposed on ships during plague epidemics."},
  {id:'l33',cat:'language',text:"The word 'Hello' only caught on as a greeting thanks to the telephone: Thomas Edison proposed it as a way to answer, beating Bell's 'Ahoy.'"},
  {id:'l34',cat:'language',text:"The English word 'goodbye' is a worn-down contraction of the phrase 'God be with ye.'"},
  {id:'l35',cat:'language',text:"The word 'disaster' literally means 'bad star': it dates from a time when misfortunes were blamed on the influence of the stars."},
  {id:'l36',cat:'language',text:"The word 'sinister' comes from the Latin 'sinister,' which simply meant 'left': the left side was considered a bad omen."},
  {id:'l37',cat:'language',text:"The English word 'nice' originally meant 'foolish' or 'ignorant,' from the Latin 'nescius.'"},
  {id:'l38',cat:'language',text:"The English word 'clue' comes from 'clew,' the ball of thread that let Theseus find his way out of the labyrinth."},
  {id:'l39',cat:'language',text:"The ampersand '&' was once treated as the 27th letter of the English alphabet."},
  {id:'l40',cat:'language',text:"The word 'jumbo,' meaning something gigantic, comes from the name of a famous 19th-century circus elephant, Jumbo."},
  {id:'l41',cat:'language',text:"The word 'companion' comes from the Latin 'cum panis': 'with bread.' A companion is someone with whom you share bread."},
  {id:'l42',cat:'language',text:"The word 'lunatic' comes from 'luna,' the Moon: people once believed its phases caused fits of madness."},
  {id:'l43',cat:'language',text:"The word 'sarcasm' comes from a Greek word meaning 'to tear flesh': a sarcastic remark 'bites' like a wound."},
  {id:'l44',cat:'language',text:"The fabric 'denim' takes its name from the French city of Nîmes ('de Nîmes'), and the word 'jeans' comes from Genoa, in Italy."},
  {id:'l45',cat:'language',text:"The Cherokee writing system was invented by a single man, Sequoyah, who could not read any language at all."},
  {id:'l46',cat:'language',text:"The word 'hippopotamus' literally means 'river horse' in ancient Greek."},
  {id:'l47',cat:'language',text:"Esperanto, a language invented from scratch in 1887 to unite peoples, may have up to two million speakers today."},
  {id:'l48',cat:'language',text:"The constructed language 'toki pona' has only about 120 root words — and yet allows real conversations."},
  {id:'l49',cat:'language',text:"The word 'tragedy' comes from the Greek 'tragoidia,' which literally means 'goat song.'"},
  {id:'l50',cat:'language',text:"The word 'noon' once meant something different: in Latin, 'nona hora' meant the ninth hour, around 3 p.m."},
  // <<< LANGUAGE
  // >>> FOOD (50 faits)
  {id:'f1',cat:'food',text:"Honey is one of the few foods that never expires — archaeologists have found 3,000-year-old honey in Egyptian tombs, still perfectly edible."},
  {id:'f2',cat:'food',text:"Chocolate was originally a cold, bitter, spiced drink consumed by the Maya and Aztecs — sugar was only added after Europeans arrived."},
  {id:'f3',cat:'food',text:"Carrots weren't always orange — Dutch growers selectively bred them orange in the 17th century, probably as a tribute to their royal House of Orange."},
  {id:'f4',cat:'food',text:"Coffee is the second most traded commodity in the world after oil — and half the world's adult population drinks at least one cup a day."},
  {id:'f5',cat:'food',text:"Strawberries are not berries in the botanical sense — but bananas, avocados, and watermelons are. Botany loves to disappoint people."},
  {id:'f6',cat:'food',text:"Spicy food doesn't actually burn — capsaicin tricks your tongue's pain receptors into sending a false heat signal to the brain."},
  {id:'f7',cat:'food',text:"Nutella was invented because there wasn't enough cocoa after the war — Pietro Ferrero added hazelnuts to 'stretch' the chocolate paste."},
  {id:'f8',cat:'food',text:"Europeans long believed tomatoes were poisonous — their acidity dissolved lead from tin plates, actually poisoning aristocrats who used them."},
  {id:'f9',cat:'food',text:"Fortune cookies have nothing Chinese about them — they were invented in Japan, then popularised in the US by Japanese immigrants in the early 20th century."},
  {id:'f10',cat:'food',text:"White chocolate is technically not chocolate — it contains no solid cocoa particles, only cocoa butter, sugar, and milk."},
  {id:'f11',cat:'food',text:"Honey is the only food that never spoils: 3,000-year-old honey found in Egyptian tombs was still perfectly edible."},
  {id:'f12',cat:'food',text:"Apples belong to the rose family, as do pears, cherries, apricots and almonds. The Rosaceae family includes many edible fruits."},
  {id:'f13',cat:'food',text:"Vanilla is the most cultivated orchid in the world. Outside Mexico, each flower must be hand-pollinated, as only a local bee can do it naturally."},
  {id:'f14',cat:'food',text:"Nutella uses about 25% of the world's hazelnut supply. Ferrero is the single largest buyer of hazelnuts on the planet."},
  {id:'f15',cat:'food',text:"Parmesan is so valuable in Italy that banks accept wheels as loan collateral — with climate-controlled vaults to store them."},
  {id:'f16',cat:'food',text:"Cheese is the most stolen food in the world, accounting for around 4% of all food products stolen globally each year."},
  {id:'f17',cat:'food',text:"The wasabi served in most restaurants outside Japan is actually colored horseradish — real wasabi costs about €250 per kilo."},
  {id:'f18',cat:'food',text:"The world's smelliest fruit, the durian, is banned on public transport and in hotels across Southeast Asia due to its odor."},
  {id:'f19',cat:'food',text:"Spices like cinnamon, pepper and nutmeg were once more valuable than gold. The spice trade drove global exploration in the 15th century."},
  {id:'f20',cat:'food',text:"Pizza Margherita was created in Naples in 1889 in honour of Queen Margherita of Savoy, with colours representing the Italian flag."},
  {id:'f21',cat:'food',text:"Saffron is the world's most expensive spice — 150,000 crocus flowers must be hand-picked to produce a single kilogram."},
  {id:'f22',cat:'food',text:"Cashews grow outside the fruit, on top of a cashew apple — and they're toxic when raw."},
  {id:'f23',cat:'food',text:"Ketchup was sold as medicine in the 1830s in the United States — it was believed to cure diarrhea."},
  {id:'f24',cat:'food',text:"The croissant isn't French — it was invented in Vienna, Austria, to celebrate victory over the Ottomans in 1683."},
  {id:'f25',cat:'food',text:"Champagne was perfected by Dom Pérignon, but he didn't invent the bubbles — they were considered a flaw before him."},
  {id:'f26',cat:'food',text:"Purple carrots were the norm before the 17th century — the orange carrot is a relatively recent genetic selection."},
  {id:'f27',cat:'food',text:"Cocoa contains theobromine, a compound toxic to dogs and cats but harmless to humans."},
  {id:'f28',cat:'food',text:"The potato was banned in France until 1772 — it was believed to cause leprosy before Parmentier rehabilitated it."},
  {id:'f29',cat:'food',text:"Himalayan pink salt gets its color from iron and over 80 minerals — but it actually comes from Pakistan, not Nepal."},
  {id:'f30',cat:'food',text:"Popcorn pops because each kernel contains a drop of water that turns to steam at 180°C, blowing the shell apart."},
  {id:'f31',cat:'food',text:"Pineapple contains bromelain, an enzyme that breaks down protein: as you eat it, it's a bit like the fruit 'eats' your mouth back."},
  {id:'f32',cat:'food',text:"Peanuts aren't really nuts: they're legumes, cousins of peas and lentils, and they grow underground."},
  {id:'f33',cat:'food',text:"The most expensive coffee in the world, kopi luwak, is made from beans eaten and then... passed by a small civet."},
  {id:'f34',cat:'food',text:"Botanically, the tomato is a fruit — but in 1893, the US Supreme Court ruled that, legally, it's a vegetable."},
  {id:'f35',cat:'food',text:"Ripe cranberries bounce: they're sometimes even sorted by bouncing them, since only the good berries spring back."},
  {id:'f36',cat:'food',text:"You can eat rhubarb stalks, but its leaves are poisonous: they contain high doses of oxalic acid."},
  {id:'f37',cat:'food',text:"Stored in bulk, pistachios can catch fire on their own: rich in fat, they release heat as they oxidize."},
  {id:'f38',cat:'food',text:"Lobster was once poor people's food: so abundant it was fed to prisoners and servants, sometimes to the point of disgust."},
  {id:'f39',cat:'food',text:"The almond is the seed of a fruit related to the peach — and wild 'bitter' almonds contain cyanide."},
  {id:'f40',cat:'food',text:"Chewing gum was originally chicle, the sap of a Central American tree, the sapodilla, chewed since the time of the Maya."},
  {id:'f41',cat:'food',text:"All true teas — black, green, white, oolong — come from one single plant: Camellia sinensis."},
  {id:'f42',cat:'food',text:"The red coloring 'carmine,' found in sweets and yogurts, is made from insects — the cochineal — ground into powder."},
  {id:'f43',cat:'food',text:"The banana we eat, the Cavendish, is a clone: every banana plant of this variety is genetically identical."},
  {id:'f44',cat:'food',text:"Apples float in water because about a quarter of their volume is air."},
  {id:'f45',cat:'food',text:"Caesar salad has nothing ancient or Roman about it: it was invented in 1924 in Tijuana, Mexico, by a restaurateur named Caesar Cardini."},
  {id:'f46',cat:'food',text:"In Europe, the table fork was long considered scandalous, even devilish: for centuries, people preferred to eat with their fingers."},
  {id:'f47',cat:'food',text:"The 'pound cake' takes its name from its recipe: originally, a pound each of butter, sugar, eggs, and flour."},
  {id:'f48',cat:'food',text:"Tonic water glows blue under an ultraviolet lamp, because of the quinine it contains."},
  {id:'f49',cat:'food',text:"Watermelon is about 92% water — its English name, 'watermelon,' says it all."},
  {id:'f50',cat:'food',text:"When bread browns, meat sears, or coffee roasts, it's the same chemical reaction creating the flavors: the Maillard reaction."},
  // <<< FOOD
  // >>> SPORTS (50 faits)
  {id:'sp01',cat:'sports',text:"Usain Bolt ran the 100 metres in 9.58 seconds in 2009 — a top speed of 44.72 km/h, faster than a galloping horse over short distances."},
  {id:'sp02',cat:'sports',text:"The 42.195 km marathon distance comes from an accident: at the 1908 London Olympics, the start was moved from Windsor so royal children could watch from their windows."},
  {id:'sp03',cat:'sports',text:"Michael Phelps won more Olympic gold medals on his own than 161 countries have won in their entire history."},
  {id:'sp04',cat:'sports',text:"Golf is the only sport ever played on the Moon — in 1971, astronaut Alan Shepard hit two golf balls on the lunar surface with a makeshift club."},
  {id:'sp05',cat:'sports',text:"Tug of war was an official Olympic discipline from 1900 to 1920 — five tournaments were held before it was dropped from the programme."},
  {id:'sp06',cat:'sports',text:"Tennis balls turned yellow in 1972 to be more visible on colour television screens — before that, they were white or black."},
  {id:'sp07',cat:'sports',text:"In the very early days of basketball, closed peach baskets were used — play had to stop after every basket so someone could climb a ladder to retrieve the ball."},
  {id:'sp08',cat:'sports',text:"Olympic gold medals today are 92.5% pure silver and merely gold-plated — the last solid gold medal was awarded at the 1912 Games."},
  {id:'sp09',cat:'sports',text:"The world speed record for a badminton shuttlecock is 493 km/h — struck during a competition smash, making it the fastest sports projectile on Earth."},
  {id:'spo10',cat:'sports',text:"The very first Olympic marathon in 1896 was won by a Greek shepherd, Spyridon Louis, who stopped along the way to drink a glass of wine offered by spectators."},
  {id:'sp011',cat:'sports',text:"The marathon was lengthened by 385 yards (352 m) at the 1908 London Olympics so the race would finish in front of the royal box."},
  {id:'sp012',cat:'sports',text:"Table tennis is the most widely played sport in the world by number of registered players, ahead of badminton and volleyball."},
  {id:'sp013',cat:'sports',text:"Cricket is the second most-watched sport in the world with 2.5 billion fans, mainly in India, Pakistan, and Australia."},
  {id:'sp014',cat:'sports',text:"The Tour de France is the most-watched annual sporting event in the world, with a cumulative audience of around 3.5 billion viewers."},
  {id:'sp015',cat:'sports',text:"A golf ball has between 300 and 500 dimples. These indentations reduce drag and can effectively double the distance the ball travels."},
  {id:'sp016',cat:'sports',text:"The modern Olympic Games were revived in 1896 in Athens by Pierre de Coubertin. Only 14 nations participated — compared to over 200 today."},
  {id:'sp017',cat:'sports',text:"A cricket Test match can last up to five days. This longest format is considered the most demanding and prestigious in the sport."},
  {id:'sp018',cat:'sports',text:"Serena Williams is widely regarded as the greatest female tennis player of all time, with 23 Grand Slam singles titles in the Open Era."},
  {id:'sp019',cat:'sports',text:"Football is the only sport played in every UN-recognised country. FIFA actually has more member nations than the UN itself."},
  {id:'sp020',cat:'sports',text:"The fastest tennis serve ever recorded was 263.4 km/h by Sam Groth in 2012. The ball takes just 0.2 seconds to cross the court."},
  {id:'sp021',cat:'sports',text:"Pelé scored over 1,200 career goals — a total no one has ever come close to in professional football."},
  {id:'sp022',cat:'sports',text:"The first official women's football match drew 53,000 spectators in England in 1920 — the FA then banned it for 50 years."},
  {id:'sp023',cat:'sports',text:"An American football field is covered with 40 million blades of synthetic grass — each about 5 cm tall."},
  {id:'sp024',cat:'sports',text:"The speed record on a bicycle is 280 km/h — set by Denise Mueller-Korenek in 2018, drafting behind a dragster."},
  {id:'sp025',cat:'sports',text:"Sumo wrestlers eat a special stew called chankonabe containing 10,000 calories — but they only eat two meals a day."},
  {id:'sp026',cat:'sports',text:"Tennis was invented in France in the 12th century as 'jeu de paume' — players hit the ball with their bare hands."},
  {id:'sp027',cat:'sports',text:"Wilt Chamberlain scored 100 points in a single NBA game in 1962 — a record that still stands after 60+ years."},
  {id:'sp028',cat:'sports',text:"Swimming wasn't taught to sailors until the 19th century — it was believed that not knowing would discourage them from falling overboard."},
  {id:'sp029',cat:'sports',text:"Ancient Olympic athletes competed completely nude — the word 'gymnasium' comes from the Greek 'gymnos' (naked)."},
  {id:'sp030',cat:'sports',text:"Parachuting was invented by André-Jacques Garnerin in 1797 — he jumped from a balloon at 900 meters above Paris."},
  {id:'sp031',cat:'sports',text:"The Olympic torch relay as we know it is not ancient: it was invented for the 1936 Berlin Games."},
  {id:'sp032',cat:'sports',text:"The longest tennis match in history lasted over 11 hours, spread across three days, at Wimbledon in 2010."},
  {id:'sp033',cat:'sports',text:"Formula 1 cars generate so much downforce that they could, in theory, drive upside down on the ceiling of a tunnel."},
  {id:'sp034',cat:'sports',text:"The colors of the Olympic rings were chosen so that at least one of them, with the white background, appears on every nation's flag."},
  {id:'sp035',cat:'sports',text:"Almost all the world's curling stones come from one tiny uninhabited Scottish island: Ailsa Craig."},
  {id:'sp036',cat:'sports',text:"In tennis, 'zero' is called 'love' in English: the word may come from the French 'l'œuf' (the egg), whose shape suggests a zero."},
  {id:'sp037',cat:'sports',text:"At the very first ancient Olympic Games, in 776 BCE, there was only one event: a single footrace."},
  {id:'sp038',cat:'sports',text:"In 1976, gymnast Nadia Comăneci scored the first perfect 10 in Olympic history — but the scoreboard, not built for it, displayed '1.00.'"},
  {id:'sp039',cat:'sports',text:"The 'Fosbury Flop,' clearing the bar on your back, revolutionized the high jump after 1968."},
  {id:'sp040',cat:'sports',text:"Bowling is over 5,000 years old: objects resembling pins have been found in tombs of ancient Egypt."},
  {id:'sp041',cat:'sports',text:"The men's javelin was redesigned in 1986 because athletes were throwing it so far it endangered spectators."},
  {id:'sp042',cat:'sports',text:"Japan's 'marathon monks' undertake an extreme challenge: running the equivalent of about 1,000 marathons in seven years."},
  {id:'sp043',cat:'sports',text:"The 'Ashes' trophy, one of cricket's oldest rivalries, is a tiny urn said to hold the ashes of a burnt cricket bail."},
  {id:'sp044',cat:'sports',text:"A basketball hoop's height is set at 3.05 meters (10 feet) — and has never changed since the game's invention in 1891."},
  {id:'sp045',cat:'sports',text:"The Olympic motto is 'Citius, Altius, Fortius' — Latin for 'Faster, Higher, Stronger.'"},
  {id:'sp046',cat:'sports',text:"The Stanley Cup, ice hockey's trophy, has many names engraved with spelling mistakes — and they're left as they are."},
  {id:'sp047',cat:'sports',text:"The winner of the decathlon is traditionally hailed as the 'world's greatest athlete.'"},
  {id:'sp048',cat:'sports',text:"The very first football World Cup was held in Uruguay in 1930 — and the host country won it."},
  {id:'sp049',cat:'sports',text:"The fastest ball game in the world is jai alai (Basque pelota): the ball can fly at over 300 km/h."},
  {id:'sp050',cat:'sports',text:"Wimbledon's grass courts are mown to a precise height of 8 millimeters throughout the tournament."},
  // <<< SPORTS
  // >>> CELEBRITIES (50 faits)
  {id:'cel1',cat:'celebrities',text:"Before becoming an actor, Christopher Walken worked as a lion tamer in a travelling circus."},
  {id:'cel2',cat:'celebrities',text:"Steve Buscemi was a New York City firefighter before becoming an actor. After the September 11 attacks, he voluntarily returned to his old station to help for several days."},
  {id:'cel3',cat:'celebrities',text:"Tom Hanks collects vintage typewriters and owns more than 250 of them from around the world."},
  {id:'cel4',cat:'celebrities',text:"Dolly Parton once entered a Dolly Parton look-alike contest anonymously — and lost."},
  {id:'cel5',cat:'celebrities',text:"Margot Robbie trained herself to hold her breath for 5 minutes for her role in Suicide Squad."},
  {id:'cel6',cat:'celebrities',text:"Keanu Reeves gifted personalised Rolex watches to every member of the stunt crew on John Wick 4 as a thank-you."},
  {id:'cel7',cat:'celebrities',text:"Bill Murray has no agent. Directors who want to work with him must leave a message on a secret answerphone that he checks only rarely."},
  {id:'cel8',cat:'celebrities',text:"Barack Obama is a huge comic book fan, particularly of Spider-Man and Conan the Barbarian."},
  {id:'cel9',cat:'celebrities',text:"Nicolas Cage once owned a pet octopus, claiming it helped him become a better actor by expanding his consciousness."},
  {id:'cel10',cat:'celebrities',text:"Elvis Presley was a black belt in karate — a martial art he began practising during his military service in Germany."},
  {id:'cel11',cat:'celebrities',text:"Johnny Depp always travels with his Jack Sparrow costume so he can make surprise visits to children in hospitals."},
  {id:'cel12',cat:'celebrities',text:"Oprah Winfrey's real name is Orpah, after a biblical character — but everyone mispronounced it, so 'Oprah' stuck."},
  {id:'cel13',cat:'celebrities',text:"Angelina Jolie holds a private pilot's licence and owns her own plane, a Cirrus SR22."},
  {id:'cel14',cat:'celebrities',text:"Jackie Chan holds the Guinness World Record for the most stunts performed by a living actor."},
  {id:'cel15',cat:'celebrities',text:"Harrison Ford is a trained rescue helicopter pilot and has personally rescued several lost hikers in remote areas."},
  {id:'cel16',cat:'celebrities',text:"Samuel L. Jackson has a clause in every contract allowing him to play golf twice a week during filming."},
  {id:'cel17',cat:'celebrities',text:"Bryan Cranston worked as a certified minister officiating weddings to make ends meet before the success of Breaking Bad."},
  {id:'cel18',cat:'celebrities',text:"Ryan Gosling built the kitchen table used in The Notebook himself — the director asked what he could do and he said carpentry."},
  {id:'cel19',cat:'celebrities',text:"Matthew McConaughey has not used deodorant in over 30 years. His on-screen partners confirmed this without complaint."},
  {id:'cel20',cat:'celebrities',text:"Keanu Reeves secretly donated a large portion of his Matrix trilogy salary to the film's technical crew."},
  {id:'cel21',cat:'celebrities',text:"Dwayne 'The Rock' Johnson was arrested eight or nine times before age 17 for fights and petty offenses."},
  {id:'cel22',cat:'celebrities',text:"Natalie Portman co-authored two neuroscience papers in scientific journals during her studies at Harvard."},
  {id:'cel23',cat:'celebrities',text:"Rowan Atkinson (Mr. Bean) holds a master's in electrical engineering from Oxford and wrote his thesis on self-adaptive control systems."},
  {id:'cel24',cat:'celebrities',text:"Lady Gaga learned piano at age 4 and was accepted to the Juilliard School before joining NYU's Tisch School of the Arts."},
  {id:'cel25',cat:'celebrities',text:"Elon Musk coded and sold his first video game, Blastar, at age 12 for $500."},
  {id:'cel26',cat:'celebrities',text:"Hedy Lamarr, 1940s Hollywood star, co-invented a frequency-hopping system that is the basis of Wi-Fi and Bluetooth."},
  {id:'cel27',cat:'celebrities',text:"Arnold Schwarzenegger was already a millionaire through real estate before becoming a Hollywood actor."},
  {id:'cel28',cat:'celebrities',text:"Tim Cook (Apple CEO) wakes up at 3:45 AM every day to read customer emails and exercise."},
  {id:'cel29',cat:'celebrities',text:"J.K. Rowling was rejected by 12 publishers before Bloomsbury accepted Harry Potter — on the advice of the chairman's 8-year-old daughter."},
  {id:'cel30',cat:'celebrities',text:"Shakira speaks six languages fluently: Spanish, English, Portuguese, Italian, French, and Arabic."},
  {id:'cel31',cat:'celebrities',text:"Albert Einstein was offered the presidency of Israel in 1952 — and he politely declined."},
  {id:'cel32',cat:'celebrities',text:"Comic actor Ken Jeong, who became famous through the comedy 'The Hangover,' is actually a fully qualified medical doctor who practiced before making it on screen."},
  {id:'cel33',cat:'celebrities',text:"Fred Rogers, creator and host of the famous children's show 'Mister Rogers' Neighborhood,' was also an ordained Presbyterian minister."},
  {id:'cel34',cat:'celebrities',text:"Action actor Dolph Lundgren holds a master's degree in chemical engineering and won a Fulbright scholarship to study at MIT."},
  {id:'cel35',cat:'celebrities',text:"Mayim Bialik, one of the actresses on 'The Big Bang Theory,' holds a real PhD in neuroscience."},
  {id:'cel36',cat:'celebrities',text:"As a child, actress Audrey Hepburn helped the Dutch resistance during the Second World War."},
  {id:'cel37',cat:'celebrities',text:"A calligraphy class Steve Jobs took by chance directly inspired the beautiful fonts of the first Macintosh computer."},
  {id:'cel38',cat:'celebrities',text:"Before starring in the series 'The X-Files,' David Duchovny was working on a PhD in English literature at Yale — which he never finished."},
  {id:'cel39',cat:'celebrities',text:"Before becoming an actress on the series 'Friends,' Lisa Kudrow studied biology and co-authored a genuine scientific study on headaches."},
  {id:'cel40',cat:'celebrities',text:"Before becoming a director, Quentin Tarantino worked in a video rental store."},
  {id:'cel41',cat:'celebrities',text:"Actress Geena Davis nearly made the US Olympic archery team: she was a semifinalist at the trials in 1999."},
  {id:'cel42',cat:'celebrities',text:"Before becoming a movie star, Sean Connery was a milkman and even entered the Mr. Universe contest in 1953."},
  {id:'cel43',cat:'celebrities',text:"Whoopi Goldberg belongs to the very select club of artists who have won all four major American awards: Emmy, Grammy, Oscar, and Tony (an 'EGOT')."},
  {id:'cel44',cat:'celebrities',text:"Puppeteer Frank Oz brought to life two very different cult characters: Yoda in Star Wars and Miss Piggy in The Muppet Show."},
  {id:'cel45',cat:'celebrities',text:"Before he was famous, Jim Carrey wrote himself a 10-million-dollar check 'for acting services rendered,' dated a few years into the future."},
  {id:'cel46',cat:'celebrities',text:"Before becoming an actor, Mr. T worked as a bodyguard for public figures and stars."},
  {id:'cel47',cat:'celebrities',text:"In 2005, actor Benedict Cumberbatch survived a kidnapping while filming in South Africa."},
  {id:'cel48',cat:'celebrities',text:"Singer Rihanna has been named an official ambassador and national hero of her country, Barbados."},
  {id:'cel49',cat:'celebrities',text:"Before breaking through as an actor, Danny DeVito trained and worked as a hairdresser."},
  {id:'cel50',cat:'celebrities',text:"Hugh Jackman holds a world record for the longest career playing a live-action Marvel superhero: Wolverine, for about 17 years."},
  // <<< CELEBRITIES
  // >>> FICTION (50 faits)
  {id:'fic1',cat:'fiction',text:"Sherlock Holmes never wears a deerstalker hat in Conan Doyle's books. It was added by an illustrator for The Strand magazine, and it stuck forever."},
  {id:'fic2',cat:'fiction',text:"Winnie the Pooh was inspired by a real bear named Winnipeg, brought to London Zoo by a Canadian soldier. Author A.A. Milne took his son there regularly."},
  {id:'fic3',cat:'fiction',text:"Kryptonite was invented in 1943 for the Superman radio serial because the lead actor wanted a holiday and needed a justification for Superman's absence."},
  {id:'fic4',cat:'fiction',text:"J.K. Rowling came up with the names of the four Hogwarts houses by scribbling them on a paper bag during a plane journey."},
  {id:'fic5',cat:'fiction',text:"In the original Dr. Seuss book, the Grinch is not green — he is white with pink spots. The 1966 TV adaptation made him green."},
  {id:'fic6',cat:'fiction',text:"Walt Disney wanted to name his famous mouse 'Mortimer', but his wife found it too pompous and suggested Mickey instead."},
  {id:'fic7',cat:'fiction',text:"In Carlo Collodi's original Pinocchio novel, the puppet accidentally kills Jiminy Cricket in the very first chapters — far from the gentle tale we imagine."},
  {id:'fic8',cat:'fiction',text:"Ian Fleming chose the name James Bond because he wanted the most bland and ordinary name possible — which he found on a book about Caribbean birds."},
  {id:'fic9',cat:'fiction',text:"In The Walking Dead comic series, the word 'zombie' is almost never used. Characters refer to them as 'roamers' instead."},
  {id:'fic10',cat:'fiction',text:"J.M. Barrie donated all royalties from Peter Pan to Great Ormond Street Children's Hospital in London — a gift that still generates income today."},
  {id:'fic11',cat:'fiction',text:"The name Gotham came from a jeweller's called 'Gotham Jewelers' that Batman's creator spotted in a phone directory while looking for a dark, urban name."},
  {id:'fic12',cat:'fiction',text:"In Yiddish, the word 'Shrek' means 'fear' or 'terror'. The filmmakers had no idea when they chose the name."},
  {id:'fic13',cat:'fiction',text:"Edgar Rice Burroughs created Tarzan without ever setting foot in Africa. He never left North America throughout his entire life."},
  {id:'fic14',cat:'fiction',text:"Agatha Christie grew to despise her own detective Hercule Poirot, calling him a 'detestable, bombastic, tiresome, ego-centric little creep' — but could not abandon him."},
  {id:'fic15',cat:'fiction',text:"George R.R. Martin writes all his books on an old computer with no internet connection running under DOS, to avoid any distraction."},
  {id:'fic16',cat:'fiction',text:"P.L. Travers, the author of Mary Poppins, hated Disney's adaptation so much that she wept at the premiere and refused further adaptations for decades."},
  {id:'fic17',cat:'fiction',text:"Stephenie Meyer got the idea for Twilight from a very specific dream about a sparkling vampire in a meadow, which she transcribed the very next morning."},
  {id:'fic18',cat:'fiction',text:"Bram Stoker never visited Transylvania. All his research for Dracula was done at the public library in Whitby, England."},
  {id:'fic19',cat:'fiction',text:"The character of Dracula, created by Bram Stoker in 1897, was inspired by a real 15th-century Romanian prince, Vlad III — known as 'the Impaler' for his brutal methods."},
  {id:'fic20',cat:'fiction',text:"The Hobbit was written by Tolkien for his children. He reportedly scrawled on a blank exam paper: 'In a hole in the ground there lived a hobbit.'"},
  {id:'fic21',cat:'fiction',text:"Tolkien invented the Elvish languages first — the Middle-earth universe was created to give them context."},
  {id:'fic22',cat:'fiction',text:"Frankenstein's monster has no name — 'Frankenstein' is the name of the doctor who creates it, not the creature."},
  {id:'fic23',cat:'fiction',text:"Stephen King threw the Carrie manuscript in the trash — his wife Tabitha rescued it and convinced him to finish it."},
  {id:'fic24',cat:'fiction',text:"The Little Prince by Antoine de Saint-Exupéry is the most translated book in the world after the Bible — in over 500 languages and dialects."},
  {id:'fic25',cat:'fiction',text:"Arthur Conan Doyle killed Sherlock Holmes in The Final Problem — but reader outrage forced him to revive the detective ten years later."},
  {id:'fic26',cat:'fiction',text:"Homer's Odyssey, written about 2,800 years ago, is considered the first adventure novel in Western literary history."},
  {id:'fic27',cat:'fiction',text:"The board game Clue (Cluedo) was invented in 1943 by an English musician, Anthony Pratt, during WWII blackouts."},
  {id:'fic28',cat:'fiction',text:"In the original Brothers Grimm version, Rapunzel gets pregnant in her tower — a detail removed from children's editions."},
  {id:'fic29',cat:'fiction',text:"The word 'utopia' was coined by Thomas More in 1516 — it comes from Greek and literally means 'a place that doesn't exist.'"},
  {id:'fic30',cat:'fiction',text:"Don Quixote by Cervantes, published in 1605, is considered the first modern novel — it already mocked chivalry clichés."},
  {id:'fic31',cat:'fiction',text:"The English word 'nerd' first appeared in print in a Dr. Seuss book, in 1950."},
  {id:'fic32',cat:'fiction',text:"In the original 'Wizard of Oz' book, Dorothy's magic shoes are not ruby red, but silver."},
  {id:'fic33',cat:'fiction',text:"Robinson Crusoe was inspired by a real castaway, the sailor Alexander Selkirk, who survived alone for over four years on a desert island."},
  {id:'fic34',cat:'fiction',text:"The very first modern detective story was written by Edgar Allan Poe in 1841, long before Sherlock Holmes."},
  {id:'fic35',cat:'fiction',text:"The novel 'Fahrenheit 451' takes its title from the temperature at which paper is said to catch fire on its own."},
  {id:'fic36',cat:'fiction',text:"Jules Verne imagined submarines and trips to the Moon decades before they became reality."},
  {id:'fic37',cat:'fiction',text:"George Orwell's novel '1984' gave the world expressions like 'Big Brother' and 'newspeak.'"},
  {id:'fic38',cat:'fiction',text:"The novel 'Treasure Island' invented many of the pirate clichés we know today: the map with an X, the wooden leg, the parrot on the shoulder."},
  {id:'fic39',cat:'fiction',text:"Jane Austen's famous novel 'Pride and Prejudice' was first written under the title 'First Impressions.'"},
  {id:'fic40',cat:'fiction',text:"'Moby-Dick,' today considered a masterpiece, was a commercial failure during its author Herman Melville's lifetime."},
  {id:'fic41',cat:'fiction',text:"Lewis Carroll, the author of 'Alice in Wonderland,' was also a mathematician and lecturer at Oxford."},
  {id:'fic42',cat:'fiction',text:"Joseph Heller's novel 'Catch-22' gave English a phrase for a no-win situation, a vicious circle."},
  {id:'fic43',cat:'fiction',text:"In 1938, a radio drama based on 'The War of the Worlds' reportedly alarmed listeners who believed it was real."},
  {id:'fic44',cat:'fiction',text:"'Gulliver's Travels' is often taken for a children's tale, when it was originally a sharp political satire of 18th-century society."},
  {id:'fic45',cat:'fiction',text:"Charles Dickens often published his novels in monthly installments, ending each one on a cliffhanger to keep readers hooked."},
  {id:'fic46',cat:'fiction',text:"Despite its title, 'The Three Musketeers' features four heroes: the three musketeers plus the young d'Artagnan."},
  {id:'fic47',cat:'fiction',text:"It's said the shortest telegram exchange in history took place between Victor Hugo and his publisher: '?' from one, '!' from the other."},
  {id:'fic48',cat:'fiction',text:"Writer Roald Dahl invented hundreds of whimsical words for his stories, so many that a dictionary was made of them."},
  {id:'fic49',cat:'fiction',text:"Marcel Proust's 'In Search of Lost Time' is one of the longest novels ever written: about 1.2 million words."},
  {id:'fic50',cat:'fiction',text:"Crushed by debt and an impossible deadline, Dostoevsky dictated his novel 'The Gambler' in only about 26 days."},
  // <<< FICTION
  // >>> GAMING (50 faits)
  {id:'gam1',cat:'gaming',text:"Mario was named after Mario Segale, the landlord of Nintendo of America's warehouse, who kept showing up to demand overdue rent."},
  {id:'gam2',cat:'gaming',text:"Pac-Man was inspired by a pizza with a slice missing — confirmed by its creator Toru Iwatani in multiple interviews."},
  {id:'gam3',cat:'gaming',text:"Tetris is the first video game ever played in space: cosmonaut Aleksandr Serebrov played it on a Game Boy during his 1993 mission."},
  {id:'gam4',cat:'gaming',text:"Princess Zelda was named after Zelda Fitzgerald, wife of F. Scott Fitzgerald — a connection confirmed by Shigeru Miyamoto himself."},
  {id:'gam5',cat:'gaming',text:"Before becoming a blue hedgehog, Sonic's early designs included an armadillo, a rabbit, and a dog in Sega's internal brainstorming sessions."},
  {id:'gam6',cat:'gaming',text:"Final Fantasy was named as such because its creator Hironobu Sakaguchi believed it would be his last game before leaving the industry."},
  {id:'gam7',cat:'gaming',text:"The first playable version of Minecraft was developed in just six days by Markus Persson, before he had any intention of releasing it publicly."},
  {id:'gam8',cat:'gaming',text:"The sounds of the Grunts in Halo are recordings of the Bungie development team making strange noises with their mouths in the studio."},
  {id:'gam9',cat:'gaming',text:"Space Invaders was originally meant to run faster, but the processors of the time couldn't keep up. The gradual speed-up as enemies are eliminated became one of the most iconic gameplay mechanics in history."},
  {id:'gam10',cat:'gaming',text:"World of Warcraft helped epidemiologists model how diseases spread: a 2005 in-game plague outbreak was studied and published in The Lancet."},
  {id:'gam11',cat:'gaming',text:"The multiplayer mode in GoldenEye 007 for Nintendo 64 — now legendary — was secretly added at the very end of development without management's approval."},
  {id:'gam12',cat:'gaming',text:"The Sims almost launched under the name 'Tactical Domestic Simulator' — a name its creator Will Wright himself acknowledged was catastrophic."},
  {id:'gam13',cat:'gaming',text:"Grand Theft Auto was born from a bug in a racing game where the police suddenly went haywire and crashed into everything. The developers found it so fun they built a whole game around it."},
  {id:'gam14',cat:'gaming',text:"Nintendo was founded in 1889 to manufacture playing cards — 70 years before computers were part of everyday Japanese life."},
  {id:'gam15',cat:'gaming',text:"In Japanese, 'Pika' is the sound of a spark and 'Chu' is the sound a mouse makes. Pikachu literally means 'sparkling mouse'."},
  {id:'gam16',cat:'gaming',text:"Polish author Andrzej Sapkowski sold The Witcher rights for a flat fee, not believing in video game potential. He has publicly regretted this decision ever since."},
  {id:'gam17',cat:'gaming',text:"Lara Croft was originally called Laura Cruz, but Core Design's developers wanted a more British name and found 'Croft' in a phone directory."},
  {id:'gam18',cat:'gaming',text:"PlayStation was originally a joint project between Nintendo and Sony to create a CD add-on for the Super Nintendo. When the partnership collapsed, Sony launched its own console."},
  {id:'gam19',cat:'gaming',text:"Donkey Kong literally means 'stupid gorilla': 'Donkey' for foolish and 'Kong' for ape. Miyamoto wanted a name that would be memorable in English."},
  {id:'gam20',cat:'gaming',text:"Tetris was created in 1984 by Soviet engineer Alexey Pajitnov on an Elektronika 60 computer."},
  {id:'gam21',cat:'gaming',text:"Dark Souls popularized the 'die and retry' genre and the 'You Died' screen has become one of gaming's most iconic images."},
  {id:'gam22',cat:'gaming',text:"The first video game easter egg is in Adventure (Atari, 1979) — the developer hid his name because Atari didn't credit creators."},
  {id:'gam23',cat:'gaming',text:"The original Game Boy survived a bombing during the Gulf War — burnt on the outside, it still worked perfectly."},
  {id:'gam24',cat:'gaming',text:"The first esports event was held at Stanford in 1972 — the Spacewar tournament prize was a one-year Rolling Stone subscription."},
  {id:'gam25',cat:'gaming',text:"Animal Crossing runs in real time — seasons, time, and events follow the player's actual calendar and clock."},
  {id:'gam26',cat:'gaming',text:"The Konami Code (↑↑↓↓←→←→BA) first appeared in Gradius in 1986 — the programmer created it to make testing easier."},
  {id:'gam27',cat:'gaming',text:"The Pac-Man world record is a perfect score of 3,333,360 — eating every dot, fruit, and ghost across 256 levels without dying."},
  {id:'gam28',cat:'gaming',text:"Red Dead Redemption 2 cost about $500 million to develop and took over 2,000 people eight years to make."},
  {id:'gam29',cat:'gaming',text:"Minecraft's Creepers were born from a bug — Notch accidentally swapped the dimensions of a pig model, creating a weird vertical creature."},
  {id:'gam30',cat:'gaming',text:"The most played game in the world is currently Roblox, with over 200 million monthly active users, most under 16."},
  {id:'gam31',cat:'gaming',text:"The arcade game 'Breakout' (Atari's brick-breaker) was designed in 1976 by the two future founders of Apple, Steve Wozniak and Steve Jobs."},
  {id:'gam32',cat:'gaming',text:"In 1983, Atari buried millions of unsold cartridges of its flop game 'E.T.' in a New Mexico desert."},
  {id:'gam33',cat:'gaming',text:"Pokémon is the highest-grossing entertainment franchise in the world, ahead of Star Wars, Marvel, or Hello Kitty."},
  {id:'gam34',cat:'gaming',text:"The famous Windows Solitaire was added partly to teach people how to use a computer mouse."},
  {id:'gam35',cat:'gaming',text:"The very first home video game console, the Magnavox Odyssey, came out in 1972 — and it used plastic overlays stuck on the screen as scenery."},
  {id:'gam36',cat:'gaming',text:"The PlayStation 2 is the best-selling game console of all time, with over 155 million units sold."},
  {id:'gam37',cat:'gaming',text:"The old 1993 game 'Doom' has been made to run on just about anything: ATMs, printers, calculators, and even pregnancy tests."},
  {id:'gam38',cat:'gaming',text:"In the United States, pinball was banned in many cities for decades, because it was seen as gambling."},
  {id:'gam39',cat:'gaming',text:"The combo system (chains of attacks) in 'Street Fighter II' began as a bug that the developers decided to keep."},
  {id:'gam40',cat:'gaming',text:"A teenager became a professional racing driver simply by being the best at the video game 'Gran Turismo.'"},
  {id:'gam41',cat:'gaming',text:"Shigeru Miyamoto came up with 'The Legend of Zelda' by remembering his childhood, exploring caves and forests near his home."},
  {id:'gam42',cat:'gaming',text:"One of the very first video games in history, 'Tennis for Two,' was created in 1958 on an oscilloscope, a laboratory device."},
  {id:'gam43',cat:'gaming',text:"The game 'Minesweeper,' bundled with Windows, quietly taught a whole generation to use the left and right mouse clicks."},
  {id:'gam44',cat:'gaming',text:"The famous phrase 'the cake is a lie' comes from the video game 'Portal.'"},
  {id:'gam45',cat:'gaming',text:"Tamagotchi, the little virtual pets you had to raise, were so distracting that some schools banned them in the 1990s."},
  {id:'gam46',cat:'gaming',text:"The prototype of the game 'Pong' broke down during its first public test... because it was completely jammed full of coins."},
  {id:'gam47',cat:'gaming',text:"The largest prize pool in esports history exceeded 40 million dollars, at a tournament for the game 'Dota 2.'"},
  {id:'gam48',cat:'gaming',text:"The game 'Duke Nukem Forever' stayed in development for nearly fifteen years, becoming the symbol of never-ending video game projects."},
  {id:'gam49',cat:'gaming',text:"Limited 'lives' and the 'Game Over' screen come from the arcade era, designed to push players to insert another coin."},
  {id:'gam50',cat:'gaming',text:"The record for the longest non-stop video game marathon exceeds 138 hours — nearly six days of playing in a row."},
  // <<< GAMING
  // >>> CINEMA (50 faits)
  {id:'cin1',cat:'cinema',text:"The sound of Star Wars lightsabers was created by Ben Burtt by blending the hum of an old film projector with the sound of a metal cable being struck."},
  {id:'cin2',cat:'cinema',text:"For the shower scene in Psycho, Hitchcock used chocolate syrup instead of blood — it photographed better in black and white than real blood."},
  {id:'cin3',cat:'cinema',text:"The cat Marlon Brando holds in The Godfather was a stray that wandered onto the set. Coppola let Brando keep it for the scene."},
  {id:'cin4',cat:'cinema',text:"The Velociraptor's cry in Jurassic Park is actually a recording of tortoises mating, discovered by sound designer Gary Rydstrom."},
  {id:'cin5',cat:'cinema',text:"In Titanic, the hands sketching Rose are not Leonardo DiCaprio's — they belong to director James Cameron himself, hidden just off-screen."},
  {id:'cin6',cat:'cinema',text:"Christopher Lee, who played Saruman in The Lord of the Rings, was the only cast member who had personally met J.R.R. Tolkien."},
  {id:'cin7',cat:'cinema',text:"Sylvester Stallone was so broke before Rocky that he sold his dog for $40. Once paid for the film, he bought it back for $15,000."},
  {id:'cin8',cat:'cinema',text:"Heath Ledger locked himself alone in a hotel room for a month to prepare for his role as the Joker in The Dark Knight."},
  {id:'cin9',cat:'cinema',text:"The time machine in Back to the Future was originally meant to be a refrigerator. The idea was dropped for fear children would lock themselves inside real fridges."},
  {id:'cin10',cat:'cinema',text:"Toy Story, released in 1995 by Pixar, is the first feature film in history to be made entirely with computer-generated imagery."},
  {id:'cin11',cat:'cinema',text:"For Interstellar, Christopher Nolan planted 500 acres of corn for a single scene — and then sold it for a profit after filming wrapped."},
  {id:'cin12',cat:'cinema',text:"In Alien, the actors had no idea the creature would burst from John Hurt's chest. Their horror reactions on camera are completely genuine."},
  {id:'cin13',cat:'cinema',text:"The mechanical shark in Jaws broke down so often that the crew nicknamed it 'Bruce'. Spielberg ended up showing it as little as possible — making the film far more terrifying."},
  {id:'cin14',cat:'cinema',text:"The film Kevin watches in Home Alone (Angels with Filthy Souls) does not exist. It was shot specifically for the movie."},
  {id:'cin15',cat:'cinema',text:"The green code falling in The Matrix is actually a sequence of sushi recipes, digitised by designer Simon Whiteley from his wife's cookbook."},
  {id:'cin16',cat:'cinema',text:"Tony Todd put real live bees in his mouth for the final scene of Candyman (1992). He was stung multiple times and negotiated a bonus per sting."},
  {id:'cin17',cat:'cinema',text:"The sounds of E.T.'s footsteps were created by the sound designer squeezing gelatine with his hands into a tray."},
  {id:'cin18',cat:'cinema',text:"Truman's birthday in The Truman Show is April 30th — the exact same birthday as actor Jim Carrey."},
  {id:'cin19',cat:'cinema',text:"Disney's Snow White in 1937 was the first feature-length animated film in cinema history. It cost $1.5 million — an extraordinary sum at the time."},
  {id:'cin20',cat:'cinema',text:"Filming Titanic cost more than building the actual Titanic, even adjusting for inflation."},
  {id:'cin21',cat:'cinema',text:"Stanley Kubrick used only candlelight for Barry Lyndon's interior scenes — he had Zeiss build a special lens."},
  {id:'cin22',cat:'cinema',text:"The word 'Rosebud' in Citizen Kane refers to Kane's childhood sled — it's one of cinema's most famous spoilers."},
  {id:'cin23',cat:'cinema',text:"In Fight Club, a Starbucks cup appears in nearly every scene — director David Fincher did it on purpose as a comment on consumerism."},
  {id:'cin24',cat:'cinema',text:"Viggo Mortensen actually deflected the knife thrown at him in The Lord of the Rings — the unplanned take was kept in the final cut."},
  {id:'cin25',cat:'cinema',text:"Pixar nearly lost Toy Story 2 when someone accidentally ran a delete command — an employee on maternity leave had a backup copy at home."},
  {id:'cin26',cat:'cinema',text:"The dinosaur bellowing sound in Jurassic Park is a slowed-down baby elephant mixed with a tiger and an alligator."},
  {id:'cin27',cat:'cinema',text:"Alfred Hitchcock was so terrified of eggs that he developed a genuine phobia — ovophobia — without ever understanding why."},
  {id:'cin28',cat:'cinema',text:"Shrek was originally voiced by Chris Farley, who recorded 80% of the film before passing away — Mike Myers took over the role."},
  {id:'cin29',cat:'cinema',text:"Bong Joon-ho's Parasite was the first non-English-language film to win the Academy Award for Best Picture, in 2020."},
  {id:'cin30',cat:'cinema',text:"The hospital explosion in The Dark Knight was filmed in one take — Heath Ledger's hesitation was completely unscripted."},
  {id:'cin31',cat:'cinema',text:"The 'Wilhelm Scream' is a single yell recorded in 1951 that gets reused, as an in-joke, in hundreds of films."},
  {id:'cin32',cat:'cinema',text:"For over thirty years, a very strict censorship code governed Hollywood: it even forbade saying certain words or showing a couple sharing a bed."},
  {id:'cin33',cat:'cinema',text:"The famous 'HOLLYWOOD' sign originally read 'HOLLYWOODLAND': it was just an advertisement for a housing development."},
  {id:'cin34',cat:'cinema',text:"In the musical 'Singin' in the Rain,' milk was added to the artificial rain so it would show up clearly on camera."},
  {id:'cin35',cat:'cinema',text:"The silver makeup of the Tin Man, in 'The Wizard of Oz,' made the first actor in the role seriously ill."},
  {id:'cin36',cat:'cinema',text:"During the filming of 'Casablanca,' the actors largely did not know how the story would end."},
  {id:'cin37',cat:'cinema',text:"In the late 19th century, a short Lumière brothers film of a train pulling into a station reportedly made early audiences jump."},
  {id:'cin38',cat:'cinema',text:"'The Blair Witch Project' was marketed so cleverly as a real documentary that some viewers believed the footage was genuine."},
  {id:'cin39',cat:'cinema',text:"Bollywood, India's film industry, produces far more films each year than Hollywood."},
  {id:'cin40',cat:'cinema',text:"As early as 1902, the film 'A Trip to the Moon' amazed audiences with its famous image of a rocket lodged in the Moon's eye."},
  {id:'cin41',cat:'cinema',text:"In the film 'Cast Away,' a volleyball named Wilson becomes one of the most moving characters in cinema."},
  {id:'cin42',cat:'cinema',text:"The film 'The Jazz Singer,' released in 1927, brought spoken and sung dialogue to feature films for the first time."},
  {id:'cin43',cat:'cinema',text:"The making of 'Apocalypse Now' was such chaos — a typhoon, an actor's heart attack, endless delays — that it nearly was never finished."},
  {id:'cin44',cat:'cinema',text:"In Disney's 'Frozen,' the character of Elsa was originally written as a villain, before becoming a heroine."},
  {id:'cin45',cat:'cinema',text:"The 'Bechdel test' rates a film with a very simple question: do two female characters talk to each other about something other than a man?"},
  {id:'cin46',cat:'cinema',text:"The German film 'Metropolis,' released in 1927, shaped the look of science fiction in cinema for an entire century."},
  {id:'cin47',cat:'cinema',text:"The giant ape of 'King Kong,' in 1933, was animated frame by frame using small models only a few dozen centimeters tall."},
  {id:'cin48',cat:'cinema',text:"In 'Forrest Gump,' the feather floating through the air at the start of the film is entirely computer-generated."},
  {id:'cin49',cat:'cinema',text:"The lion that roars at the start of MGM studio films is a real lion, filmed specially for this famous logo."},
  {id:'cin50',cat:'cinema',text:"The longest-running film series in history is James Bond, whose adventures have continued since 1962."},
  // <<< CINEMA
  // >>> MUSIC (50 faits)
  {id:'mus1',cat:'music',text:"Queen guitarist Brian May built his own guitar, the 'Red Special', from an old Victorian fireplace mantelpiece. He still uses it on stage today."},
  {id:'mus2',cat:'music',text:"None of the four Beatles could read or write sheet music in any conventional way. Everything was conveyed by ear or hummed to arrangers."},
  {id:'mus3',cat:'music',text:"'Smells Like Teen Spirit' takes its name from a teen deodorant brand worn by Kurt Cobain's ex-girlfriend — he discovered it written on a wall."},
  {id:'mus4',cat:'music',text:"Michael Jackson patented special shoes with hidden clamps in the heel that connected to bolts in the stage floor, allowing him to lean forward at 45 degrees without falling."},
  {id:'mus5',cat:'music',text:"Eminem wrote 'Lose Yourself' in a single writing session on the set of 8 Mile, between takes."},
  {id:'mus6',cat:'music',text:"Daft Punk's iconic helmets cost more than €65,000 each and contained built-in cooling systems to prevent overheating."},
  {id:'mus7',cat:'music',text:"Prince played 27 different instruments on his debut album — recorded when he was just 19 years old."},
  {id:'mus8',cat:'music',text:"Keith Richards claims he found the riff of Satisfaction in his sleep, and had the presence of mind to record it on a cassette before dozing off again."},
  {id:'mus9',cat:'music',text:"David Bowie's permanently dilated pupil was not genetic — it was caused by a punch in a school fight that permanently paralysed his eye muscles."},
  {id:'mus10',cat:'music',text:"Ed Sheeran slept in the corridors of the London Underground for several months before becoming famous, unable to afford rent."},
  {id:'mus11',cat:'music',text:"Pink Floyd's The Dark Side of the Moon spent 741 consecutive weeks on the Billboard 200 chart — more than 14 years in a row."},
  {id:'mus12',cat:'music',text:"Adele names her albums after the age she was when she started writing them: 19, 21, 25, and 30."},
  {id:'mus13',cat:'music',text:"Lady Gaga wrote 'Just Dance' in just 10 minutes — a song that went on to reach number one in more than 10 countries."},
  {id:'mus14',cat:'music',text:"'I Will Always Love You' is a cover of a song written by Dolly Parton in 1973. Whitney Houston made it a global hit, but Dolly Parton collected all the royalties."},
  {id:'mus15',cat:'music',text:"Jay-Z never writes his lyrics down on paper. He composes everything in his head, memorises verses, then walks into the studio and records them straight."},
  {id:'mus16',cat:'music',text:"Britney Spears was not the first choice for '...Baby One More Time'. TLC had already turned the song down, finding it too childish."},
  {id:'mus17',cat:'music',text:"Guns N' Roses' Appetite for Destruction is the best-selling debut album of all time in the United States, with over 18 million copies sold."},
  {id:'mus18',cat:'music',text:"Elvis Presley never wrote a single song he performed. Every track in his catalogue was composed by other artists."},
  {id:'mus19',cat:'music',text:"Freddie Mercury had a vocal range of four octaves, one of the greatest ever recorded in rock music."},
  {id:'mus20',cat:'music',text:"The reference 'A' note used to tune instruments has been standardised at 440 Hz since 1939. Before this international standard, every country used a different frequency."},
  {id:'mus21',cat:'music',text:"Mozart had a well-documented scatological humor — he wrote a canon titled 'Leck mich im Arsch' (Lick me in the behind)."},
  {id:'mus22',cat:'music',text:"Vinyl has made a spectacular comeback: in 2023, vinyl record sales surpassed CD sales for the first time since 1987."},
  {id:'mus23',cat:'music',text:"The song Happy Birthday was under copyright until 2016 — Warner earned about $2 million a year in royalties from it."},
  {id:'mus24',cat:'music',text:"The Australian didgeridoo sound is produced by continuous lip vibration — players use circular breathing to never stop."},
  {id:'mus25',cat:'music',text:"Billie Eilish recorded her first hit album, When We All Fall Asleep, in her brother Finneas's bedroom in Los Angeles."},
  {id:'mus26',cat:'music',text:"Metallica won their first Grammy for a thrash metal album... in the Best Metal Performance category — the Grammys didn't have a metal category before 1990."},
  {id:'mus27',cat:'music',text:"The theremin, invented in 1920, is played without touching it — the musician's hands alter electromagnetic fields to produce sound."},
  {id:'mus28',cat:'music',text:"Bob Marley was buried with his Gibson Les Paul guitar, a soccer ball, a Bible, and a sprig of marijuana."},
  {id:'mus29',cat:'music',text:"The earliest known sound recording dates from 1860 — a phonautogram of 'Au Clair de la Lune' by Édouard-Léon Scott de Martinville."},
  {id:'mus30',cat:'music',text:"Hans Zimmer often starts composing film scores from a single note — the 'BWAAAA' from Inception became a movie trailer cliché."},
  {id:'mus31',cat:'music',text:"Composer John Cage's piece '4′33″' is made entirely of silence: the performers stay still without playing a single note."},
  {id:'mus32',cat:'music',text:"The oldest known written melody, the 'Hurrian Hymn,' is about 3,400 years old: it was carved on a clay tablet."},
  {id:'mus33',cat:'music',text:"The oldest known musical instrument is a flute carved from bone, over 40,000 years old."},
  {id:'mus34',cat:'music',text:"Beethoven kept composing as he went deaf: he is said to have sawed the legs off his piano to better feel the vibrations through the floor."},
  {id:'mus35',cat:'music',text:"A few seconds of drumming, known as the 'Amen break,' are among the most sampled sounds in all of music history."},
  {id:'mus36',cat:'music',text:"Auto-Tune, the software that corrects and transforms voices, was invented by an engineer who first used the math to search for oil."},
  {id:'mus37',cat:'music',text:"The Roland TR-808 drum machine was first a commercial flop — before becoming the sonic heart of decades of pop and hip-hop."},
  {id:'mus38',cat:'music',text:"Benjamin Franklin invented an instrument made of glass bowls — once suspected of driving its players mad."},
  {id:'mus39',cat:'music',text:"The world's largest musical instrument is built inside a cave: it makes stalactites resonate like the pipes of an organ."},
  {id:'mus40',cat:'music',text:"The famous 'Nokia tune' ringtone is actually a snippet of a guitar piece composed by a Spaniard in the early 20th century."},
  {id:'mus41',cat:'music',text:"Tchaikovsky's '1812 Overture' calls, in its score, for real cannon fire."},
  {id:'mus42',cat:'music',text:"Spain's national anthem, the 'Marcha Real,' has no official lyrics: it's one of the few anthems in the world with no words."},
  {id:'mus43',cat:'music',text:"The harmonica is one of the best-selling musical instruments in the world — small, cheap, and easy to carry."},
  {id:'mus44',cat:'music',text:"In the Middle Ages, a particularly dissonant musical interval, the tritone, was nicknamed 'the devil in music.'"},
  {id:'mus45',cat:'music',text:"When the members of a choir sing together, their heartbeats can synchronize."},
  {id:'mus46',cat:'music',text:"The first musical instrument played in space was a harmonica, smuggled aboard by an astronaut in 1965."},
  {id:'mus47',cat:'music',text:"The 'Mozart effect,' the idea that his music makes you smarter, was greatly exaggerated compared with what the original study actually said."},
  {id:'mus48',cat:'music',text:"Composer Erik Satie wrote a short piano piece meant to be repeated 840 times in a row."},
  {id:'mus49',cat:'music',text:"The piano was invented around 1700 by an Italian, Bartolomeo Cristofori, who wanted a keyboard able to play both loud and soft."},
  {id:'mus50',cat:'music',text:"The world's largest pipe organ has tens of thousands of pipes, from smaller than a pencil to taller than a building."},
  // <<< MUSIC
  // >>> MYTHOLOGY (50 faits)
  {id:'myth1',cat:'mythology',text:"In Greek mythology, Athena was born fully armored from Zeus's skull after a splitting headache."},
  {id:'myth2',cat:'mythology',text:"Thor's hammer Mjölnir has a short handle because a gadfly stung the dwarf blacksmith during its forging."},
  {id:'myth3',cat:'mythology',text:"Anubis, the jackal-headed Egyptian god, weighed the hearts of the dead on a scale against a feather of truth."},
  {id:'myth4',cat:'mythology',text:"In Japanese mythology, the Sun is a goddess — Amaterasu — who once hid in a cave, plunging the world into darkness."},
  {id:'myth5',cat:'mythology',text:"The Minotaur, half man half bull, lived at the center of a labyrinth built by the architect Daedalus in Crete."},
  {id:'myth6',cat:'mythology',text:"Loki, the Norse trickster god, once turned into a mare and gave birth to Sleipnir, Odin's eight-legged horse."},
  {id:'myth7',cat:'mythology',text:"Prometheus was chained to a rock for stealing fire from the gods. Each day an eagle ate his liver, which grew back overnight."},
  {id:'myth8',cat:'mythology',text:"In Hindu mythology, the universe rests on the backs of four elephants, standing on a giant turtle."},
  {id:'myth9',cat:'mythology',text:"Medusa was so terrifying that a single glance turned anyone to stone. Perseus used a mirror shield to defeat her."},
  {id:'myth10',cat:'mythology',text:"In Celtic mythology, the Cauldron of Dagda could feed an entire army without ever emptying."},
  {id:'myth11',cat:'mythology',text:"The Styx is the river of the Greek Underworld. Bathing in it made one invincible — that's how Achilles was dipped, except for his heel."},
  {id:'myth12',cat:'mythology',text:"Fenrir, the giant wolf of Norse mythology, was so powerful the gods bound him with a magical ribbon made from cat noise and mountain roots."},
  {id:'myth13',cat:'mythology',text:"Orpheus played the lyre so divinely that even rocks and trees moved to listen."},
  {id:'myth14',cat:'mythology',text:"In Aztec mythology, Quetzalcóatl, the feathered serpent, created humanity by sprinkling his own blood on bones stolen from the Underworld."},
  {id:'myth15',cat:'mythology',text:"Norse Valkyries flew over battlefields to choose the bravest warriors and carry them to Valhalla."},
  {id:'myth16',cat:'mythology',text:"Sisyphus was condemned by Zeus to push a boulder up a mountain for eternity, only to watch it roll back down each time."},
  {id:'myth17',cat:'mythology',text:"In Chinese mythology, Pan Gu created the world by smashing the cosmic egg with an axe, separating sky from earth."},
  {id:'myth18',cat:'mythology',text:"Icarus flew with wax wings crafted by his father Daedalus, but flew too close to the Sun and fell into the sea."},
  {id:'myth19',cat:'mythology',text:"Cerberus, the three-headed dog, guarded the gates of the Greek Underworld. Heracles captured him bare-handed as his twelfth labor."},
  {id:'myth20',cat:'mythology',text:"In Māori mythology, Māui fished up the North Island of New Zealand using a magical fishhook made from his grandmother's jawbone."},
  {id:'myth21',cat:'mythology',text:"Cerberus, the three-headed dog, guarded the Greek underworld — his only known weakness was music, which put him to sleep."},
  {id:'myth22',cat:'mythology',text:"In Egyptian mythology, the Sun is swallowed every evening by the goddess Nut and reborn every morning from her womb."},
  {id:'myth23',cat:'mythology',text:"Ragnarök, the Norse end of the world, foretells the death of nearly all gods — but also the rebirth of a new, green world."},
  {id:'myth24',cat:'mythology',text:"The god Hermes stole Apollo's cattle on the very day he was born — as a baby, he invented the lyre to make amends."},
  {id:'myth25',cat:'mythology',text:"In Polynesian mythology, Maui fished the Pacific islands out of the ocean with a magical fishhook."},
  {id:'myth26',cat:'mythology',text:"The Minotaur ate only young Athenians — seven boys and seven girls sent as tribute every nine years."},
  {id:'myth27',cat:'mythology',text:"Icarus didn't just die because he flew too high — the wax melted in the sun, but his father Daedalus survived the flight."},
  {id:'myth28',cat:'mythology',text:"The goddess Kali in Hindu mythology represents both destruction and rebirth — she wears a necklace of skulls and dances on Shiva."},
  {id:'myth29',cat:'mythology',text:"Norse Valkyries didn't choose the strongest warriors — they chose those who were meant to die and join Valhalla."},
  {id:'myth30',cat:'mythology',text:"The Phoenix rises from its ashes in Egyptian, Greek, and Chinese mythologies — but in very different forms."},
  {id:'myth31',cat:'mythology',text:"In Norse mythology, the world tree Yggdrasil links nine different realms, from gods to giants to the dead."},
  {id:'myth32',cat:'mythology',text:"The famous 'Pandora's box' was really a large jar: a mistranslation turned it into a box."},
  {id:'myth33',cat:'mythology',text:"The word 'narcissism' comes from Narcissus, a figure in Greek mythology who fell in love with his own reflection in the water."},
  {id:'myth34',cat:'mythology',text:"In Egyptian mythology, the god Osiris is cut into pieces by his brother, then patiently reassembled by his wife, the goddess Isis."},
  {id:'myth35',cat:'mythology',text:"In Norse mythology, the god Odin sacrificed one of his eyes in exchange for wisdom."},
  {id:'myth36',cat:'mythology',text:"In Hindu mythology, the god Ganesha got his elephant head after losing his original one."},
  {id:'myth37',cat:'mythology',text:"King Midas, in Greek mythology, was granted the power to turn everything he touched into gold — to the point of no longer being able to eat or drink."},
  {id:'myth38',cat:'mythology',text:"The 'Epic of Gilgamesh,' one of the oldest stories in the world, contains a flood tale strikingly similar to Noah's ark."},
  {id:'myth39',cat:'mythology',text:"The verb 'tantalize' (to torment with an unfulfilled desire) comes from Tantalus, condemned to eternal hunger and thirst."},
  {id:'myth40',cat:'mythology',text:"In Greek mythology, the titan Atlas carries the vault of the sky on his shoulders — not the Earth, as is often wrongly depicted."},
  {id:'myth41',cat:'mythology',text:"In Greek mythology, the seasons are explained by the pomegranate seeds eaten by Persephone in the underworld."},
  {id:'myth42',cat:'mythology',text:"In Greek mythology, the ferryman Charon takes the dead across the underworld river — but only for the price of a coin."},
  {id:'myth43',cat:'mythology',text:"In Egyptian mythology, the cat-headed goddess Bastet protected homes — and cats were so sacred that killing one could be punishable by death."},
  {id:'myth44',cat:'mythology',text:"In Chinese mythology, dragons are benevolent creatures, tied to water, rain, and luck — far from the fire-breathing European dragon."},
  {id:'myth45',cat:'mythology',text:"In Norse mythology, a squirrel runs along the world tree to carry insults between an eagle at the top and a dragon at the bottom."},
  {id:'myth46',cat:'mythology',text:"In Greek mythology, the Sirens lured sailors to their deaths with an irresistible song."},
  {id:'myth47',cat:'mythology',text:"In Japanese folklore, kitsune are fox spirits said to gain an extra tail every century they live, up to nine."},
  {id:'myth48',cat:'mythology',text:"The month of January is named after the Roman god Janus, shown with two faces: one looking to the past, the other to the future."},
  {id:'myth49',cat:'mythology',text:"In Greek mythology, the Lernaean Hydra grew two new heads for each one that was cut off."},
  {id:'myth50',cat:'mythology',text:"In Norse mythology, the gods stayed young thanks to the magical golden apples kept by the goddess Idun."},
  // <<< MYTHOLOGY
  // >>> PSYCHOLOGY (50 faits)
  {id:'psy1',cat:'psychology',text:"The Dunning-Kruger effect shows that the less competent someone is, the more they overestimate their abilities."},
  {id:'psy2',cat:'psychology',text:"The human brain more easily holds about 7 items in working memory at once — that's why phone numbers are split into small groups."},
  {id:'psy3',cat:'psychology',text:"Milgram's 1961 experiment showed that 65% of participants were willing to deliver lethal electric shocks when ordered by an authority figure."},
  {id:'psy4',cat:'psychology',text:"Confirmation bias makes us seek and remember only information that supports our existing beliefs."},
  {id:'psy5',cat:'psychology',text:"Simply being exposed to something repeatedly is enough to make us like it more — this is the mere exposure effect."},
  {id:'psy6',cat:'psychology',text:"The Barnum effect explains why horoscopes seem accurate: we accept vague descriptions as personally relevant."},
  {id:'psy7',cat:'psychology',text:"A forced smile can still improve your mood — the mere act of contracting smile muscles sends a positive signal to the brain."},
  {id:'psy8',cat:'psychology',text:"The 1971 Stanford experiment showed that ordinary students could become cruel in just 6 days when assigned the role of prison guards."},
  {id:'psy9',cat:'psychology',text:"The paradox of choice: the more options we have, the harder it is to decide and the less satisfied we are with our final choice."},
  {id:'psy10',cat:'psychology',text:"The halo effect makes us judge someone as more intelligent, kind, and competent simply because they're physically attractive."},
  {id:'psy11',cat:'psychology',text:"You remember information better if you learn it just before sleeping — sleep consolidates memory."},
  {id:'psy12',cat:'psychology',text:"Fear of missing out (FOMO) activates the same brain areas as physical pain."},
  {id:'psy13',cat:'psychology',text:"The Zeigarnik effect shows we remember unfinished tasks better than completed ones — the brain hates unresolved things."},
  {id:'psy14',cat:'psychology',text:"Simply holding a warm object (like a coffee cup) makes us warmer and more generous toward others."},
  {id:'psy15',cat:'psychology',text:"Synesthesia makes some people 'see' sounds as colors or 'taste' words — about 4% of the population experiences it."},
  {id:'psy16',cat:'psychology',text:"The IKEA effect: we place more value on something we assembled ourselves, even if it's lower quality."},
  {id:'psy17',cat:'psychology',text:"The tip-of-the-tongue phenomenon hits the average adult about once a week — and increases with age."},
  {id:'psy18',cat:'psychology',text:"People consistently overestimate how much others notice them — this is the spotlight effect."},
  {id:'psy19',cat:'psychology',text:"Listening to music releases dopamine in the brain, just like eating chocolate or falling in love."},
  {id:'psy20',cat:'psychology',text:"Anchoring bias means the first number you see influences all your following estimates, even if it's completely arbitrary."},
  {id:'psy21',cat:'psychology',text:"Confirmation bias drives the brain to seek only information that supports what it already believes — and to ignore the rest."},
  {id:'psy22',cat:'psychology',text:"People systematically overestimate how long their future emotions will last — this is the impact bias, discovered by Daniel Gilbert."},
  {id:'psy23',cat:'psychology',text:"Simply smiling, even without reason, can activate neural circuits of well-being — this is the facial feedback hypothesis."},
  {id:'psy24',cat:'psychology',text:"Writer's block isn't laziness — it's a creative block tied to fear of judgment and perfectionism."},
  {id:'psy25',cat:'psychology',text:"People remember unfinished tasks better than completed ones — this is the Zeigarnik effect, discovered in 1927."},
  {id:'psy26',cat:'psychology',text:"The human brain doesn't distinguish social rejection from physical pain — the same brain areas activate for both."},
  {id:'psy27',cat:'psychology',text:"The 'paradox of choice' is real: the more options you have, the less able you are to decide — and the less satisfied you are with your final choice."},
  {id:'psy28',cat:'psychology',text:"'Priming' shows that words or images briefly shown can unconsciously influence your next decisions."},
  {id:'psy29',cat:'psychology',text:"Bilingual children develop better selective attention — their brain constantly trains itself to filter information."},
  {id:'psy30',cat:'psychology',text:"The Barnum effect explains why horoscopes seem accurate — the brain interprets vague descriptions as personal."},
  {id:'psy31',cat:'psychology',text:"The bystander effect: the more people present during an emergency, the less likely any one of them is to step in, assuming someone else will."},
  {id:'psy32',cat:'psychology',text:"The placebo effect is so powerful that a fake treatment can ease real symptoms — and it sometimes works even when you know it's a placebo."},
  {id:'psy33',cat:'psychology',text:"Loss aversion: losing something hurts us about twice as much as gaining the same thing pleases us."},
  {id:'psy34',cat:'psychology',text:"Cognitive dissonance: holding two contradictory ideas at once is so uncomfortable that our brain alters its beliefs to restore harmony."},
  {id:'psy35',cat:'psychology',text:"The frequency illusion: once you notice something new, you suddenly seem to see it everywhere."},
  {id:'psy36',cat:'psychology',text:"The peak-end rule: we judge a memory mostly by its most intense moment and its very end, rather than by its total length."},
  {id:'psy37',cat:'psychology',text:"The 'cocktail party effect': in a noisy room, your brain filters out the din — yet instantly catches your name if it's spoken across the room."},
  {id:'psy38',cat:'psychology',text:"Pareidolia: our brain is so tuned to spot faces that it sees them in clouds, power sockets, or a slice of toast."},
  {id:'psy39',cat:'psychology',text:"The negativity bias: an unpleasant event affects us far more strongly than an equally pleasant one."},
  {id:'psy40',cat:'psychology',text:"The sunk cost fallacy: we keep pursuing something just because we've already invested time or money in it."},
  {id:'psy41',cat:'psychology',text:"Inattentional blindness: focused on one task, people can fail to see a person in a gorilla suit walk across the scene."},
  {id:'psy42',cat:'psychology',text:"The Hawthorne effect: people change their behavior simply because they know they're being watched."},
  {id:'psy43',cat:'psychology',text:"The Benjamin Franklin effect: doing someone a favor paradoxically makes us like them more."},
  {id:'psy44',cat:'psychology',text:"Hedonic adaptation: after great happiness or great misfortune, we gradually drift back to our usual level of satisfaction."},
  {id:'psy45',cat:'psychology',text:"Dunbar's number: a human being can maintain only about 150 stable social relationships at once."},
  {id:'psy46',cat:'psychology',text:"The misinformation effect: a memory can be reshaped simply by how a question about it is phrased."},
  {id:'psy47',cat:'psychology',text:"The Stroop effect: it's surprisingly hard to name the ink color of a word when the word spells a different color."},
  {id:'psy48',cat:'psychology',text:"Decision fatigue: making many decisions over a day gradually wears down our willpower and the quality of our choices."},
  {id:'psy49',cat:'psychology',text:"The 'Proust effect': a single smell can bring back a distant memory far more vividly and emotionally than a sight or a sound."},
  {id:'psy50',cat:'psychology',text:"Social loafing: in a group, each person tends to put in a little less effort than if working alone."},
  // <<< PSYCHOLOGY
  // >>> OCEANS (50 faits)
  {id:'ocean1',cat:'oceans',text:"Over 80% of the oceans have never been explored — we know the surface of Mars better than our own sea floors."},
  {id:'ocean2',cat:'oceans',text:"The Mariana Trench plunges to 10,994 meters — if Mount Everest were placed inside, its peak would still be over a kilometer underwater."},
  {id:'ocean3',cat:'oceans',text:"Jellyfish have existed for over 500 million years — they predate dinosaurs and even fish."},
  {id:'ocean4',cat:'oceans',text:"A colossal squid can reach 14 meters long and has the largest eyes in the animal kingdom, the size of a basketball."},
  {id:'ocean5',cat:'oceans',text:"The blue whale is the largest animal to have ever lived — its heart is the size of a small car."},
  {id:'ocean6',cat:'oceans',text:"There are over 3 million shipwrecks on the ocean floor, most of which have never been found."},
  {id:'ocean7',cat:'oceans',text:"Coral, though it looks like a plant, is actually an animal — and coral reefs support 25% of all marine life."},
  {id:'ocean8',cat:'oceans',text:"The ocean produces over 50% of the oxygen we breathe, mainly through microscopic phytoplankton."},
  {id:'ocean9',cat:'oceans',text:"The pressure at the bottom of the Mariana Trench is 1,086 bars — the equivalent of 50 jumbo jets stacked on one person."},
  {id:'ocean10',cat:'oceans',text:"The Gulf Stream carries more water than all the world's rivers combined — it warms the climate of Western Europe."},
  {id:'ocean11',cat:'oceans',text:"Some deep-sea fish produce their own light through bioluminescence — 90% of deep-ocean creatures are luminescent."},
  {id:'ocean12',cat:'oceans',text:"If extracted and spread, the salt in the oceans would cover all continents with a layer 150 meters thick."},
  {id:'ocean13',cat:'oceans',text:"Australia's Great Barrier Reef is so vast it can be seen from space — it stretches over 2,300 kilometers."},
  {id:'ocean14',cat:'oceans',text:"Seahorses are the only animals where the male carries the babies — he can give birth to 2,000 young at once."},
  {id:'ocean15',cat:'oceans',text:"The stonefish is the most venomous marine animal in the world — it camouflages perfectly on rocky ocean floors."},
  {id:'ocean16',cat:'oceans',text:"Underwater currents form an 'ocean conveyor belt' that circulates water around the globe in about 1,000 years."},
  {id:'ocean17',cat:'oceans',text:"The coelacanth, a fish thought extinct for 65 million years, was rediscovered alive in 1938 off South Africa."},
  {id:'ocean18',cat:'oceans',text:"Ocean waves can travel thousands of kilometers without losing energy — swells born in Antarctica can reach Alaska."},
  {id:'ocean19',cat:'oceans',text:"Sea turtles return to lay eggs on the exact beach where they were born, even after 30 years at sea — they navigate using Earth's magnetic field."},
  {id:'ocean20',cat:'oceans',text:"Point Nemo in the South Pacific is the farthest point from any land — the nearest humans are astronauts on the ISS."},
  {id:'ocean21',cat:'oceans',text:"Ocean currents move more heat than the atmosphere — without them, Europe would be as cold as Canada."},
  {id:'ocean22',cat:'oceans',text:"The ocean floor is only about 25% mapped — we know the surface of Mars better than the bottom of our own seas."},
  {id:'ocean23',cat:'oceans',text:"Coral reefs cover less than 1% of the ocean floor but shelter 25% of all known marine species."},
  {id:'ocean24',cat:'oceans',text:"The brine pool at the bottom of the Gulf of Mexico is a 'lake within the ocean' — so salty and dense that fish entering it die of toxic shock."},
  {id:'ocean25',cat:'oceans',text:"Rogue waves can reach 30 meters — their existence was long dismissed as a sailor's myth."},
  {id:'ocean26',cat:'oceans',text:"The Pacific Ocean is so vast it contains a point (the Oceanic Pole of Inaccessibility) farther from any land than the ISS is from Earth."},
  {id:'ocean27',cat:'oceans',text:"Sea sponges are the simplest and oldest animals — they have no brain, no heart, and no muscles."},
  {id:'ocean28',cat:'oceans',text:"The Gulf Stream carries 30 times more water than all the world's rivers combined — at speeds up to 9 km/h."},
  {id:'ocean29',cat:'oceans',text:"Bioluminescence in the ocean is so common that 76% of deep-sea creatures produce their own light."},
  {id:'ocean30',cat:'oceans',text:"The salt from all the oceans could cover the entire Earth in a layer 152 meters thick — a 50-story building."},
  {id:'ocean31',cat:'oceans',text:"Earth's longest mountain range is almost entirely underwater: the mid-ocean ridge stretches about 65,000 km."},
  {id:'ocean32',cat:'oceans',text:"The largest waterfall in the world is invisible: it lies underwater, in the Denmark Strait, where masses of cold water plunge downward."},
  {id:'ocean33',cat:'oceans',text:"When a whale dies and sinks, its body feeds an entire ecosystem for decades: this is called a 'whale fall.'"},
  {id:'ocean34',cat:'oceans',text:"One species of jellyfish can, in danger, revert to its youthful stage — making it nearly 'immortal.'"},
  {id:'ocean35',cat:'oceans',text:"In some places, like the Bay of Fundy in Canada, the tide can rise and fall by nearly 16 meters — the height of a five-story building."},
  {id:'ocean36',cat:'oceans',text:"A few million years ago, the Mediterranean Sea almost completely dried up, leaving only a vast desert of salt."},
  {id:'ocean37',cat:'oceans',text:"The Atlantic Ocean is slowly widening, by a few centimeters each year, as new plates spread apart at its center."},
  {id:'ocean38',cat:'oceans',text:"In deep water, a tsunami can race as fast as an airliner — up to about 800 km/h."},
  {id:'ocean39',cat:'oceans',text:"Manatees and dugongs, the gentle 'sea cows,' are distant cousins... of the elephant."},
  {id:'ocean40',cat:'oceans',text:"The blue blood of the horseshoe crab, a very ancient sea animal, is used to check the safety of medicines and vaccines."},
  {id:'ocean41',cat:'oceans',text:"To defend themselves, some sea cucumbers expel their own internal organs out the back — then simply let them grow back."},
  {id:'ocean42',cat:'oceans',text:"Antarctic icefish have transparent, colorless blood: they have no red pigment at all."},
  {id:'ocean43',cat:'oceans',text:"There is gold dissolved in seawater — but in such tiny amounts that it could never be collected profitably."},
  {id:'ocean44',cat:'oceans',text:"The distant ancestors of whales were four-legged animals that walked on dry land."},
  {id:'ocean45',cat:'oceans',text:"The ocean is, on average, cold and pitch dark: its mean depth is around 3,700 meters."},
  {id:'ocean46',cat:'oceans',text:"Tuna are partly 'warm-blooded': they can heat their muscles above the surrounding water, which makes them very fast."},
  {id:'ocean47',cat:'oceans',text:"Some glass sponges, on the ocean floor, can live for thousands of years — among the longest-lived animals on the planet."},
  {id:'ocean48',cat:'oceans',text:"The blobfish only looks 'melted' and misshapen because it's brought up from the depths: in its habitat, under pressure, it has a normal fish shape."},
  {id:'ocean49',cat:'oceans',text:"The ocean makes up over 95% of all the living space on Earth, measured by volume."},
  {id:'ocean50',cat:'oceans',text:"Sunlight reaches only the top 200 meters of the ocean: below lies a world of permanent night."},
  // <<< OCEANS
  // >>> RECORDS (50 faits)
  {id:'rec1',cat:'records',text:"The world plank record is 9 hours, 30 minutes and 1 second, held by Daniel Scali in 2021."},
  {id:'rec2',cat:'records',text:"The tallest man ever measured, Robert Wadlow, was 2.72 meters at his death in 1940 — and still growing."},
  {id:'rec3',cat:'records',text:"A Rubik's Cube can be solved in just 3.13 seconds — the current world record. There are 43 quintillion possible combinations."},
  {id:'rec4',cat:'records',text:"The longest Monopoly game lasted 70 consecutive days — and the longest in a bathtub, 99 hours."},
  {id:'rec5',cat:'records',text:"The loudest animal is the sperm whale: its clicks can reach 230 decibels, enough to deafen a human."},
  {id:'rec6',cat:'records',text:"The largest jigsaw puzzle ever assembled had 551,232 pieces and measured 15 meters long."},
  {id:'rec7',cat:'records',text:"The highest temperature ever recorded on Earth was 56.7°C at Furnace Creek, Death Valley, in 1913."},
  {id:'rec8',cat:'records',text:"The most hot dogs eaten in 10 minutes is 76, a record set by Joey Chestnut in 2021."},
  {id:'rec9',cat:'records',text:"The oldest known tree, a Bristlecone Pine in California, is over 5,000 years old — it was ancient when the pyramids were built."},
  {id:'rec10',cat:'records',text:"Felix Baumgartner jumped from 39 km altitude in 2012, reaching Mach 1.25 in freefall — the first human to break the sound barrier without a vehicle."},
  {id:'rec11',cat:'records',text:"The longest non-stop flight lasted 19 hours and 16 minutes, from Singapore to New York, covering 15,349 km."},
  {id:'rec12',cat:'records',text:"The largest rubber duck collection belongs to Charlotte Lee: over 9,000 ducks."},
  {id:'rec13',cat:'records',text:"The longest word in French is 'anticonstitutionnellement' at 25 letters — but chemists can do far worse."},
  {id:'rec14',cat:'records',text:"The static breath-holding record is 24 minutes and 37 seconds, held by Budimir Šobat — underwater without breathing."},
  {id:'rec15',cat:'records',text:"The smallest frog in the world, found in Papua, measures 7.7 mm — it fits on a fingernail."},
  {id:'rec16',cat:'records',text:"The largest gathering of people dressed as Smurfs had 3,549 participants in Germany in 2019."},
  {id:'rec17',cat:'records',text:"The domino chain toppling record is over 5 million, set up by a Dutch team."},
  {id:'rec18',cat:'records',text:"The longest lightning bolt ever recorded stretched 768 kilometers from Mississippi to Texas in 2020."},
  {id:'rec19',cat:'records',text:"The tallest snowman ever built was 37 meters tall, in Bethel, Maine in 2008."},
  {id:'rec20',cat:'records',text:"The most stolen book from libraries worldwide is the Guinness World Records itself."},
  {id:'rec21',cat:'records',text:"The tallest house of cards ever built stood 7.86 meters — the work of Bryan Berg, who uses no glue or tape."},
  {id:'rec22',cat:'records',text:"The longest concert in history lasted 639 hours (26 days), played by an organist who was relieved every few hours."},
  {id:'rec23',cat:'records',text:"The person who has held the most simultaneous Guinness records is Ashrita Furman, with over 600 records broken in total."},
  {id:'rec24',cat:'records',text:"The most people in a Mini Cooper is 28 — a record set in 2014 by students in the UK."},
  {id:'rec25',cat:'records',text:"The fastest Rubik's Cube solve is 3.13 seconds — a record that keeps dropping every year."},
  {id:'rec26',cat:'records',text:"The fastest animal isn't the cheetah but the peregrine falcon — it dives at over 380 km/h."},
  {id:'rec27',cat:'records',text:"The longest distance covered by skateboard in 24 hours is 501 km — by New Zealander Andrew Andras."},
  {id:'rec28',cat:'records',text:"The largest diamond ever found is the Cullinan — 3,106 raw carats, cut into several stones, some of which adorn the British Crown Jewels."},
  {id:'rec29',cat:'records',text:"The record for the longest human glider flight is 764 km — set by Klaus Ohlmann in Argentina in 2003."},
  {id:'rec30',cat:'records',text:"The tallest wave ever surfed was 26.21 meters — by Sebastian Steudtner at Nazaré, Portugal, in 2020."},
  {id:'rec31',cat:'records',text:"The tallest building in the world, the Burj Khalifa in Dubai, exceeds 828 meters — more than twice the Eiffel Tower."},
  {id:'rec32',cat:'records',text:"The fastest car in history, ThrustSSC, broke the sound barrier on land in 1997, at over 1,200 km/h."},
  {id:'rec33',cat:'records',text:"The longest human beard ever measured reached about 5.3 meters — longer than a car."},
  {id:'rec34',cat:'records',text:"The longest fingernails ever measured on one person totaled more than 8 meters end to end."},
  {id:'rec35',cat:'records',text:"One American has eaten over 34,000 Big Macs in his lifetime — on average several a day, for decades."},
  {id:'rec36',cat:'records',text:"The fastest roller coaster in the world reaches about 240 km/h in under five seconds."},
  {id:'rec37',cat:'records',text:"The heaviest hailstone ever recorded weighed nearly a kilogram: it fell in Bangladesh in 1986."},
  {id:'rec38',cat:'records',text:"The world's largest ball of twine wound by a single man was built over 29 years and weighs nearly 8 tons."},
  {id:'rec39',cat:'records',text:"The longest a person has stayed awake without sleep, in an experiment, is about 11 days."},
  {id:'rec40',cat:'records',text:"The largest snowflake ever reported was said to measure 38 centimeters across — observed in the United States in 1887."},
  {id:'rec41',cat:'records',text:"The most gifted 'hyperpolyglots' can speak dozens of languages — some claim more than fifty."},
  {id:'rec42',cat:'records',text:"The longest officially recognized marriage lasted more than 90 years."},
  {id:'rec43',cat:'records',text:"The fastest wind gust ever measured at Earth's surface topped 400 km/h, during a cyclone in Australia in 1996."},
  {id:'rec44',cat:'records',text:"The most tattooed person in the world has 100% of their body covered in ink — including the inside of the eyelids and ears."},
  {id:'rec45',cat:'records',text:"The tallest sandcastle ever built stood over 21 meters tall — it took thousands of tons of sand."},
  {id:'rec46',cat:'records',text:"The largest bubblegum bubble ever blown measured about 51 centimeters across — almost as wide as an adult's shoulders."},
  {id:'rec47',cat:'records',text:"The largest pizza ever made covered over 1,200 square meters — enough to fill an entire field."},
  {id:'rec48',cat:'records',text:"The deepest scuba dive ever made by a human, with tanks, reached over 332 meters."},
  {id:'rec49',cat:'records',text:"The longest recorded flight by a chicken lasted about 13 seconds."},
  {id:'rec50',cat:'records',text:"The longest known sneezing fit lasted more than 970 days in a row — over two and a half years of sneezing."},
  // <<< RECORDS
  // >>> QUOTES (50 faits)
  {id:'quote1',cat:'quotes',text:"'Insanity is doing the same thing over and over expecting different results' — often attributed to Einstein, this quote has no verified source."},
  {id:'quote2',cat:'quotes',text:"'Imagination is more important than knowledge.' — Albert Einstein believed knowledge is limited to the known, while imagination embraces the entire universe."},
  {id:'quote3',cat:'quotes',text:"Winston Churchill napped every afternoon and often worked in his pajamas. His motto: 'You have enemies? Good. That means you've stood up for something.'"},
  {id:'quote4',cat:'quotes',text:"'I think, therefore I am.' — René Descartes summarized the foundation of modern philosophy in five words in 1637."},
  {id:'quote5',cat:'quotes',text:"Nelson Mandela said: 'It always seems impossible until it's done' — he spent 27 years in prison before becoming president."},
  {id:'quote6',cat:'quotes',text:"Marie Curie said: 'Nothing in life is to be feared, it is only to be understood.' She remains the only person to win a Nobel in two different sciences."},
  {id:'quote7',cat:'quotes',text:"'Be the change you wish to see in the world.' — Gandhi never actually said this exact phrase, but a longer and more nuanced version."},
  {id:'quote8',cat:'quotes',text:"Oscar Wilde told the American customs officer: 'I have nothing to declare except my genius.' He lived on wit as much as literature."},
  {id:'quote9',cat:'quotes',text:"'Creativity is intelligence having fun.' — often attributed to Einstein, this quote appears in none of his writings."},
  {id:'quote10',cat:'quotes',text:"Simone de Beauvoir wrote: 'One is not born, but rather becomes, a woman.' — a 1949 phrase that founded modern feminism."},
  {id:'quote11',cat:'quotes',text:"'Eureka!' — Archimedes allegedly shouted this word while running naked from his bath after discovering the principle of buoyancy."},
  {id:'quote12',cat:'quotes',text:"Mark Twain said: 'The two most important days in your life are the day you are born and the day you find out why.'"},
  {id:'quote13',cat:'quotes',text:"Steve Jobs started his career in a garage and ended a famous Stanford speech with: 'Stay hungry, stay foolish.'"},
  {id:'quote14',cat:'quotes',text:"Voltaire wrote standing up and drank up to 40 cups of coffee a day. He said: 'I have decided to be happy because it's good for my health.'"},
  {id:'quote15',cat:'quotes',text:"Coco Chanel revolutionized fashion and declared: 'Fashion fades, only style remains.' She freed women from the corset."},
  {id:'quote16',cat:'quotes',text:"Bruce Lee said: 'Be water, my friend.' His philosophy blended martial arts with Taoist wisdom."},
  {id:'quote17',cat:'quotes',text:"Frida Kahlo painted from her hospital bed and said: 'Feet, what do I need them for, if I have wings to fly?'"},
  {id:'quote18',cat:'quotes',text:"Leonardo da Vinci wrote right to left in mirror script. He noted: 'Simplicity is the ultimate sophistication.'"},
  {id:'quote19',cat:'quotes',text:"Muhammad Ali proclaimed himself 'the greatest' before he was. His motto: 'He who is not courageous enough to take risks will accomplish nothing.'"},
  {id:'quote20',cat:'quotes',text:"Marie Antoinette probably never said 'Let them eat cake' — the phrase was already circulating decades before her."},
  {id:'quote21',cat:'quotes',text:"Confucius said: 'The man who moves a mountain begins by carrying away small stones.' He was teaching 2,500 years ago."},
  {id:'quote22',cat:'quotes',text:"Nikola Tesla predicted in 1926: 'When wireless is perfectly applied, the whole earth will be converted into a huge brain.' He was describing the smartphone."},
  {id:'quote23',cat:'quotes',text:"Maya Angelou wrote: 'People will forget what you said, forget what you did, but they will never forget how you made them feel.'"},
  {id:'quote24',cat:'quotes',text:"Darwin never said 'Only the strongest survive' — he spoke of the most adapted, which is very different."},
  {id:'quote25',cat:'quotes',text:"Picasso said: 'Good artists copy, great artists steal.' Steve Jobs later quoted him to justify innovation at Apple."},
  {id:'quote26',cat:'quotes',text:"Lao Tzu wrote: 'A journey of a thousand miles begins with a single step.' The Tao Te Ching is one of the most translated texts in the world."},
  {id:'quote27',cat:'quotes',text:"Hannah Arendt theorized the 'banality of evil' — the idea that ordinary people can commit atrocities without seeing any wrongdoing."},
  {id:'quote28',cat:'quotes',text:"'After me, the flood' is attributed to Louis XV or Madame de Pompadour — it reflects the court's indifference before the Revolution."},
  {id:'quote29',cat:'quotes',text:"Hemingway wrote: 'We are all broken, that's how the light gets in.' He practiced a minimalist style that became legendary."},
  {id:'quote30',cat:'quotes',text:"Desmond Tutu said: 'If you are neutral in situations of injustice, you have chosen the side of the oppressor.' He received the Nobel Peace Prize in 1984."},
  {id:'quote31',cat:'quotes',text:"Socrates is remembered for a paradoxical idea: 'All I know is that I know nothing.'"},
  {id:'quote32',cat:'quotes',text:"Julius Caesar reportedly summed up a victory in just three words: 'Veni, vidi, vici' — 'I came, I saw, I conquered.'"},
  {id:'quote33',cat:'quotes',text:"Isaac Newton wrote that he had seen further 'by standing on the shoulders of giants,' paying tribute to the scholars before him."},
  {id:'quote34',cat:'quotes',text:"Galileo is said to have muttered 'And yet it moves' about the Earth, after being forced to recant his ideas."},
  {id:'quote35',cat:'quotes',text:"'To be, or not to be' opens the most famous speech in all of Shakespeare's theater."},
  {id:'quote36',cat:'quotes',text:"The philosopher Friedrich Nietzsche wrote: 'What does not kill me makes me stronger.'"},
  {id:'quote37',cat:'quotes',text:"Thomas Edison defined genius as '1% inspiration and 99% perspiration.'"},
  {id:'quote38',cat:'quotes',text:"The famous line 'We are what we repeatedly do' is not by Aristotle: it's a summary written by the historian Will Durant."},
  {id:'quote39',cat:'quotes',text:"Theodore Roosevelt's foreign-policy motto came down to one phrase: 'Speak softly and carry a big stick.'"},
  {id:'quote40',cat:'quotes',text:"Eleanor Roosevelt is said to have remarked: 'No one can make you feel inferior without your consent.'"},
  {id:'quote41',cat:'quotes',text:"Sun Tzu's treatise 'The Art of War' advises: 'Know your enemy and know yourself.'"},
  {id:'quote42',cat:'quotes',text:"Countless quotes are falsely attributed to Abraham Lincoln — including, as a joke, sayings about... the internet."},
  {id:'quote43',cat:'quotes',text:"Actress Mae West quipped: 'You only live once, but if you do it right, once is enough.'"},
  {id:'quote44',cat:'quotes',text:"Comedian Groucho Marx joked: 'I refuse to belong to any club that would have me as a member.'"},
  {id:'quote45',cat:'quotes',text:"Helen Keller, deaf and blind, wrote: 'Alone we can do so little; together we can do so much.'"},
  {id:'quote46',cat:'quotes',text:"Baseball player Yogi Berra is famous for his tangled phrases, like 'It ain't over till it's over.'"},
  {id:'quote47',cat:'quotes',text:"American revolutionary Patrick Henry reportedly rallied his countrymen with the words: 'Give me liberty, or give me death.'"},
  {id:'quote48',cat:'quotes',text:"The phrase 'the ends justify the means' sums up — while distorting — the thought of Machiavelli, who never wrote it that way."},
  {id:'quote49',cat:'quotes',text:"The proverb 'Necessity is the mother of invention' is very old: the idea appears as far back as Plato's writings."},
  {id:'quote50',cat:'quotes',text:"Physicist Niels Bohr reputedly said: 'Prediction is very difficult, especially about the future.'"},
  // <<< QUOTES
  // >>> LAWS (50 faits)
  {id:'law1',cat:'laws',text:"In Switzerland, it's illegal to flush the toilet after 10 PM in an apartment building — to preserve neighbors' rest."},
  {id:'law2',cat:'laws',text:"In Singapore, chewing gum sales have been banned since 1992 — except with a doctor or dentist prescription."},
  {id:'law3',cat:'laws',text:"In France, it's technically illegal to name a pig 'Napoleon' — a law that was never officially repealed."},
  {id:'law4',cat:'laws',text:"In Thailand, stepping on a banknote is a crime — it bears the king's portrait, and insulting it can lead to prison."},
  {id:'law5',cat:'laws',text:"In Italy, a man was fined for wearing flip-flops while driving — considered dangerous driving."},
  {id:'law6',cat:'laws',text:"In Japan, it's illegal to be excessively overweight: the 'Metabo Law' requires companies to do waist measurements."},
  {id:'law7',cat:'laws',text:"In Australia, it's illegal to disturb a carrier pigeon — a WWII-era law that's still in effect."},
  {id:'law8',cat:'laws',text:"In Germany, running out of gas on the highway is a traffic offense — it's considered an avoidable voluntary stop."},
  {id:'law9',cat:'laws',text:"In England, it's technically illegal to die in Parliament — because it would require a state funeral."},
  {id:'law10',cat:'laws',text:"In Canada, it's illegal to pay for a purchase over 25 dollars entirely in pennies — to protect shopkeepers."},
  {id:'law11',cat:'laws',text:"In Greece, wearing stiletto heels at archaeological sites is banned — to protect ancient surfaces."},
  {id:'law12',cat:'laws',text:"In Scotland, if someone knocks on your door to use the toilet, you're legally obligated to let them in."},
  {id:'law13',cat:'laws',text:"In Venice, feeding pigeons in St. Mark's Square is banned — with fines up to 700 euros."},
  {id:'law14',cat:'laws',text:"In Sweden, it's illegal to repaint your house without government approval — even the color must be approved."},
  {id:'law15',cat:'laws',text:"In Portugal, urinating in the sea is technically illegal — rarely enforced but still on the books."},
  {id:'law16',cat:'laws',text:"In Finland, traffic fines are proportional to income — a Finnish millionaire once received a €100,000 speeding ticket."},
  {id:'law17',cat:'laws',text:"In Alabama, it's illegal to wear a fake mustache in church if it causes laughter — a law still in effect."},
  {id:'law18',cat:'laws',text:"In Bhutan, tobacco sales have been completely banned since 2004 — the first country in the world to do so."},
  {id:'law19',cat:'laws',text:"In Turkey, men aged 65 or older can legally refuse to wait in line — respect for elders is written into law."},
  {id:'law20',cat:'laws',text:"In New Zealand, every citizen has the right to refuse drone flights over their property — a very strict privacy law."},
  {id:'law21',cat:'laws',text:"In Thailand, leaving home without underwear is technically illegal — though the law is rarely enforced."},
  {id:'law22',cat:'laws',text:"In France, bakers aren't allowed to go on vacation at the same time as the baker next door — to guarantee bread access."},
  {id:'law23',cat:'laws',text:"In Milan, citizens are legally required to smile at all times in public places — under threat of a theoretical fine."},
  {id:'law24',cat:'laws',text:"In Oregon, it's illegal to hunt while riding a whale — an unlikely but technically valid law."},
  {id:'law25',cat:'laws',text:"In the UK, a 1986 law makes it illegal to handle a salmon under suspicious circumstances — the Salmon Act, Section 32."},
  {id:'law26',cat:'laws',text:"In Florida, if an elephant is tied to a parking meter, its owner must pay the parking fee as if it were a car."},
  {id:'law27',cat:'laws',text:"In Denmark, parents must choose a first name from an official list of 7,000 government-approved names."},
  {id:'law28',cat:'laws',text:"In France, photographing the illuminated Eiffel Tower at night without permission is technically illegal — the light display is copyrighted."},
  {id:'law29',cat:'laws',text:"In Japan, being too overweight is technically an offense: the Metabo Law requires companies to measure the waist of employees over 40."},
  {id:'law30',cat:'laws',text:"In Switzerland, it's illegal to mow your lawn on Sundays — the noise is considered a violation of Sunday rest."},
  {id:'law31',cat:'laws',text:"In France, a law requires large supermarkets to donate their still-edible unsold food rather than throw it away."},
  {id:'law32',cat:'laws',text:"In the United Kingdom, an old law makes being 'drunk in charge of a cow' a genuine offense."},
  {id:'law33',cat:'laws',text:"In the United States, the state of Indiana nearly passed a law in 1897 setting the value of pi to 3.2."},
  {id:'law34',cat:'laws',text:"In Japan, dancing in clubs after midnight was technically illegal until 2015, because of a postwar law."},
  {id:'law35',cat:'laws',text:"In England, a centuries-old rule reportedly still forbids wearing a full suit of armor in Parliament."},
  {id:'law36',cat:'laws',text:"In Canada, the law requires radio stations to broadcast a minimum share of Canadian music."},
  {id:'law37',cat:'laws',text:"In China, a 2007 regulation states that Tibetan monks must obtain official permission to... reincarnate."},
  {id:'law38',cat:'laws',text:"In Italy, the small town of Eraclea has banned the building of sandcastles on its beach."},
  {id:'law39',cat:'laws',text:"In Samoa, it has reportedly been illegal for a man to forget his wife's birthday."},
  {id:'law40',cat:'laws',text:"In the state of Victoria, Australia, it was long said that only a licensed electrician could change a lightbulb."},
  {id:'law41',cat:'laws',text:"In France, a law forbidding women from wearing trousers, dating from the Napoleonic era, was only officially repealed in 2013."},
  {id:'law42',cat:'laws',text:"In Greece, a 2002 law briefly banned all electronic games — because of a text written far too broadly."},
  {id:'law43',cat:'laws',text:"In Ohio, in the United States, it is reportedly illegal to get a fish drunk."},
  {id:'law44',cat:'laws',text:"In the United Kingdom, it is technically illegal to be drunk... in a pub."},
  {id:'law45',cat:'laws',text:"In Arizona, in the United States, an old law reportedly forbids donkeys from sleeping in a bathtub."},
  {id:'law46',cat:'laws',text:"In Switzerland, you can be denied citizenship for being judged 'too annoying' by your neighbors."},
  {id:'law47',cat:'laws',text:"In France, a 1910 law banned kissing on railway platforms — to avoid delaying the trains."},
  {id:'law48',cat:'laws',text:"In the United Kingdom, sturgeon, whales, and dolphins caught near the coast are technically 'royal fish' belonging to the Crown."},
  {id:'law49',cat:'laws',text:"In the United States, the image of the mascot 'Smokey Bear,' the fire-prevention bear, is protected by a special federal law."},
  {id:'law50',cat:'laws',text:"In the United Kingdom, it's often believed to be 'forbidden' to stick a stamp bearing the monarch upside down — but that's really a myth, not an actual law."},
  // <<< LAWS
  // >>> TALES (50 faits)
  {id:'tale1',cat:'tales',text:"Little Red Riding Hood was published by Perrault in 1697 — in the original, the wolf eats both grandmother AND child, with no rescue."},
  {id:'tale2',cat:'tales',text:"The Yeti legend comes from Nepali Sherpas. In 2017, DNA analysis of 'evidence' revealed it was Himalayan brown bear hair."},
  {id:'tale3',cat:'tales',text:"Bluebeard, Perrault's tale, may have been inspired by Gilles de Rais, Joan of Arc's companion turned serial killer in the 15th century."},
  {id:'tale4',cat:'tales',text:"The Kraken, the Scandinavian sea monster, was probably inspired by sightings of giant squid — which actually exist."},
  {id:'tale5',cat:'tales',text:"Cinderella exists in over 500 versions worldwide. The oldest, Rhodopis, is an Egyptian tale from the 1st century BC."},
  {id:'tale6',cat:'tales',text:"The Loch Ness Monster was first 'seen' in 565 AD by an Irish monk, Saint Columba."},
  {id:'tale7',cat:'tales',text:"Sleeping Beauty sleeps 100 years in Perrault's tale — but 500 years in Basile's 1634 Italian version."},
  {id:'tale8',cat:'tales',text:"The Brothers Grimm collected their tales from German oral sources — but they substantially rewrote and darkened them."},
  {id:'tale9',cat:'tales',text:"The legend of the Golem of Prague tells of a 16th-century rabbi who created a living clay being to protect the Jewish ghetto."},
  {id:'tale10',cat:'tales',text:"In Andersen's original Little Mermaid, she doesn't end up with the prince — she turns into sea foam."},
  {id:'tale11',cat:'tales',text:"Dragons appear in the myths of nearly every civilization — from Europe to China to the Americas."},
  {id:'tale12',cat:'tales',text:"Robin Hood is first mentioned in 1377 in an English poem — his historical existence has never been proven."},
  {id:'tale13',cat:'tales',text:"The Chupacabra, a legendary Latin American creature, was 'invented' in 1995 in Puerto Rico — analyses revealed diseased coyotes."},
  {id:'tale14',cat:'tales',text:"In Collodi's original 1883 novel, Pinocchio is hanged and dies — the happy version was added after reader complaints."},
  {id:'tale15',cat:'tales',text:"The White Lady is a legend found in nearly every European country — a female ghost linked to a castle or road."},
  {id:'tale16',cat:'tales',text:"Hansel and Gretel may have originated during Europe's Great Famine of 1315, when child abandonment was a reality."},
  {id:'tale17',cat:'tales',text:"Werewolves appear in European texts since antiquity. The earliest written account is from Petronius in the 1st century."},
  {id:'tale18',cat:'tales',text:"King Arthur and Excalibur first appear in 9th-century Welsh texts — Camelot has never been located."},
  {id:'tale19',cat:'tales',text:"The Japanese legend of Kintarō tells of a child so strong he wrestled bears in the forest from age 5."},
  {id:'tale20',cat:'tales',text:"The Bermuda Triangle was popularized in the 1960s — statistics show no more accidents there than anywhere else."},
  {id:'tale21',cat:'tales',text:"The legend of the ghost ship, the Flying Dutchman, tells of a vessel doomed to sail the seas forever without ever docking."},
  {id:'tale22',cat:'tales',text:"The Wendigo legend, from the Algonquin peoples, speaks of a famine spirit that turns humans into cannibals."},
  {id:'tale23',cat:'tales',text:"The medieval Basilisk could kill with a single glance — only the crow of a rooster or a mirror could defeat it."},
  {id:'tale24',cat:'tales',text:"In the original stories, Tinker Bell is jealous, spiteful, and tries to have Wendy killed — far from the Disney version."},
  {id:'tale25',cat:'tales',text:"The Japanese legend of the Kappa describes a water creature that drowns children — it can be appeased by bowing, as it must return the gesture."},
  {id:'tale26',cat:'tales',text:"The Rougarou, a Cajun werewolf from Louisiana, descends from the French loup-garou brought by Acadian settlers."},
  {id:'tale27',cat:'tales',text:"The legend of the city of Ys in Brittany tells of a city swallowed by the sea — some say it inspired the name Paris (Par-Ys)."},
  {id:'tale28',cat:'tales',text:"The tale of Baba Yaga, a Slavic witch, describes her living in a house on chicken legs that moves through the forest."},
  {id:'tale29',cat:'tales',text:"The Australian Aboriginal Bunyip legend describes a swamp creature whose cry terrifies anyone who hears it — settlers thought it was a seal."},
  {id:'tale30',cat:'tales',text:"The original tale of Aladdin comes from One Thousand and One Nights but is set in China — a detail often forgotten."},
  {id:'tale31',cat:'tales',text:"The legend of the Pied Piper of Hamelin may rest on a real event: in the Middle Ages, many of the town's children reportedly vanished."},
  {id:'tale32',cat:'tales',text:"La Llorona, the 'weeping woman,' is a ghost of Latin American folklore who is said to wander near water searching for her children."},
  {id:'tale33',cat:'tales',text:"Anansi the spider, a clever trickster, passed from West African folklore into Caribbean tales, carried across the ocean with enslaved people."},
  {id:'tale34',cat:'tales',text:"The banshee, in Irish legend, is a female spirit whose wailing foretells a coming death in the family."},
  {id:'tale35',cat:'tales',text:"The Krampus is a demonic creature of the Alps who, during the winter holidays, punishes naughty children — the dark opposite of Santa Claus."},
  {id:'tale36',cat:'tales',text:"Mothman, a winged creature with red eyes, was reportedly seen several times in West Virginia in the 1960s."},
  {id:'tale37',cat:'tales',text:"The tale of 'Beauty and the Beast' may have been inspired by a real man whose whole body was covered in hair, at a 16th-century court."},
  {id:'tale38',cat:'tales',text:"In the tale of Rumpelstiltskin, everything hinges on one secret: guessing the hidden name of a strange little creature."},
  {id:'tale39',cat:'tales',text:"The famous headless horseman has its roots in older European legends, such as the Irish Dullahan."},
  {id:'tale40',cat:'tales',text:"The mischievous sprites of Irish folklore, leprechauns, are described as little shoemakers hiding a pot of gold at the foot of the rainbow."},
  {id:'tale41',cat:'tales',text:"Originally, 'El Dorado' was not a city of gold but a man: a king covered in gold dust during a ceremony."},
  {id:'tale42',cat:'tales',text:"The legendary sunken city of Atlantis probably never existed: the philosopher Plato invented it for the sake of a story."},
  {id:'tale43',cat:'tales',text:"The legend of the Fountain of Youth, said to restore youth, was wrongly tied to the explorer Ponce de León — after his death."},
  {id:'tale44',cat:'tales',text:"In Scottish and Irish folklore, selkies are seals able to shed their skin to become human on land."},
  {id:'tale45',cat:'tales',text:"The Japanese tale of Momotarō tells of a little boy born inside a giant peach found in a river."},
  {id:'tale46',cat:'tales',text:"In 1917, two English girls fooled the whole world with faked photos of 'fairies' — even convincing the author of Sherlock Holmes."},
  {id:'tale47',cat:'tales',text:"In Japanese legend, tengu are mountain spirits, part human, part bird, sometimes pranksters, sometimes protectors."},
  {id:'tale48',cat:'tales',text:"In many countries, it's not a fairy but a little mouse that comes to collect children's baby teeth."},
  {id:'tale49',cat:'tales',text:"Bigfoot, or Sasquatch, is a large ape-man said to be spotted in the forests of North America — with no solid evidence to date."},
  {id:'tale50',cat:'tales',text:"The will-o'-the-wisp, the ghostly glow that dances over marshes, actually has a natural explanation."},
  // <<< TALES
  // >>> DINOSAURS (50 faits)
  {id:'dino1',cat:'dinosaurs',text:"T-Rex had the most powerful bite of any land animal — about 6 tons of pressure, enough to crush a car."},
  {id:'dino2',cat:'dinosaurs',text:"Dinosaurs ruled Earth for 165 million years. Humanity has only existed for 300,000 years."},
  {id:'dino3',cat:'dinosaurs',text:"The real Velociraptor was turkey-sized and probably covered in feathers — far from the Jurassic Park version."},
  {id:'dino4',cat:'dinosaurs',text:"The asteroid that caused dinosaur extinction hit the Yucatán 66 million years ago, creating a 180 km wide crater."},
  {id:'dino5',cat:'dinosaurs',text:"Brachiosaurus weighed about 80 tons and was 25 meters long — it had to eat 400 kg of plants daily to survive."},
  {id:'dino6',cat:'dinosaurs',text:"Birds are direct descendants of theropod dinosaurs — a sparrow is technically a living dinosaur."},
  {id:'dino7',cat:'dinosaurs',text:"Stegosaurus had a brain the size of a walnut despite a 9-meter body — one of the smallest brain-to-body ratios known."},
  {id:'dino8',cat:'dinosaurs',text:"Spinosaurus is the only known dinosaur that lived semi-aquatically — larger than T-Rex, it fished like a giant heron."},
  {id:'dino9',cat:'dinosaurs',text:"T-Rex's arms, though ridiculously short, could each lift about 200 kg — they weren't useless."},
  {id:'dino10',cat:'dinosaurs',text:"Parasaurolophus used its hollow crest like a musical instrument to communicate with its herd from kilometers away."},
  {id:'dino11',cat:'dinosaurs',text:"The first scientifically described dinosaur fossil was a Megalosaurus, in 1824 in England, by William Buckland."},
  {id:'dino12',cat:'dinosaurs',text:"Quetzalcoatlus, a pterosaur (not a dinosaur), had a 12-meter wingspan — the size of a small airplane."},
  {id:'dino13',cat:'dinosaurs',text:"Some herbivorous dinosaurs swallowed stones (gastroliths) to help grind food in their stomachs."},
  {id:'dino14',cat:'dinosaurs',text:"The word 'dinosaur' means 'terrible lizard' in Greek — it was coined by Richard Owen in 1842."},
  {id:'dino15',cat:'dinosaurs',text:"Ankylosaurus had a tail ending in a bony club capable of breaking a T-Rex's bones."},
  {id:'dino16',cat:'dinosaurs',text:"The smallest known dinosaur, Microraptor, was 40 cm long and had four wings — it glided between trees like a flying squirrel."},
  {id:'dino17',cat:'dinosaurs',text:"Triceratops lived in herds and their horns served for both male combat and defense against predators."},
  {id:'dino18',cat:'dinosaurs',text:"In Argentina, the largest known dinosaur was found: Patagotitan, estimated at 70 tons and 37 meters long."},
  {id:'dino19',cat:'dinosaurs',text:"Dinosaurs laid eggs. The largest dinosaur egg ever found measures 60 cm — attributed to a titanosaur."},
  {id:'dino20',cat:'dinosaurs',text:"There were never dinosaurs in Antarctica... right? Actually, fossils have been found there — the continent was once temperate."},
  {id:'dino21',cat:'dinosaurs',text:"Therizinosaurus had the longest claws of any known animal — up to 1 meter long, probably used to strip leaves."},
  {id:'dino22',cat:'dinosaurs',text:"Dinosaurs likely had colorful feathers — fossils show melanosomes indicating red, black, and even iridescent hues."},
  {id:'dino23',cat:'dinosaurs',text:"Pachycephalosaurus had a skull 25 cm thick — paleontologists still debate whether it headbutted rivals."},
  {id:'dino24',cat:'dinosaurs',text:"Giganotosaurus, larger than T. rex, had a banana-shaped brain proportionally smaller than a cat's."},
  {id:'dino25',cat:'dinosaurs',text:"Pterosaurs weren't dinosaurs — they were flying reptiles that coexisted with dinosaurs for 150 million years."},
  {id:'dino26',cat:'dinosaurs',text:"Some sauropods had a 'second brain' in their hip — actually a nerve cluster for controlling their enormous tail."},
  {id:'dino27',cat:'dinosaurs',text:"The dinosaur extinction also wiped out 75% of all species on Earth — not just the giant reptiles."},
  {id:'dino28',cat:'dinosaurs',text:"Dreadnoughtus, discovered in Argentina, is one of the largest dinosaurs with a relatively complete skeleton — about 65 tons."},
  {id:'dino29',cat:'dinosaurs',text:"Marine dinosaurs didn't exist — plesiosaurs and mosasaurs were marine reptiles, not scientifically dinosaurs."},
  {id:'dino30',cat:'dinosaurs',text:"Carnotaurus had arms even smaller than T. rex — barely longer than a human hand on an 8-meter body."},
  {id:'dino31',cat:'dinosaurs',text:"Despite their colossal size, the great sauropods had partly hollow bones, like birds — which lightened their immense skeleton."},
  {id:'dino32',cat:'dinosaurs',text:"The fierce 'raptors' of Jurassic Park were inspired not by the small real Velociraptor, but by another, larger dinosaur: Deinonychus."},
  {id:'dino33',cat:'dinosaurs',text:"Diplodocus had a tail so long and thin that it may have cracked like a whip — perhaps even breaking the sound barrier."},
  {id:'dino34',cat:'dinosaurs',text:"When Iguanodon was first discovered, its thumb spike was mistakenly placed on its nose, like a little horn."},
  {id:'dino35',cat:'dinosaurs',text:"Some dinosaurs could run fast: based on tracks and models, the fastest probably reached 40 to 50 km/h."},
  {id:'dino36',cat:'dinosaurs',text:"In the 19th century, two rival scientists waged a 'Bone War': they raced to name the most dinosaurs, even sabotaging each other."},
  {id:'dino37',cat:'dinosaurs',text:"Maiasaura, whose name means 'good mother lizard,' raised its young in true colonies of nests."},
  {id:'dino38',cat:'dinosaurs',text:"The very first dinosaurs appeared around 230 million years ago, at a time when all the continents still formed a single block."},
  {id:'dino39',cat:'dinosaurs',text:"Archaeopteryx, which had feathers, teeth, and a long tail all at once, is a famous link between dinosaurs and birds."},
  {id:'dino40',cat:'dinosaurs',text:"The legend of the griffin, a creature with a lion's body and eagle's head, may have arisen from the discovery of beaked dinosaur skulls, like Protoceratops."},
  {id:'dino41',cat:'dinosaurs',text:"Some dinosaurs were cannibals: bones of their own species bear characteristic tooth marks."},
  {id:'dino42',cat:'dinosaurs',text:"Fossilized dinosaur droppings, called coprolites, are precious: they reveal what these animals really ate."},
  {id:'dino43',cat:'dinosaurs',text:"Fossil hunter Mary Anning made major discoveries in the early 19th century — but, being a woman, she received little credit in her lifetime."},
  {id:'dino44',cat:'dinosaurs',text:"Allosaurus was the great predator of the Jurassic period — long before T-Rex appeared, tens of millions of years later."},
  {id:'dino45',cat:'dinosaurs',text:"Despite their gigantic size, the largest sauropods hatched from surprisingly small eggs, no bigger than a handball."},
  {id:'dino46',cat:'dinosaurs',text:"Dinosaurs are split into 'bird-hipped' and 'lizard-hipped' — but, ironically, birds descend from the 'lizard-hipped' group."},
  {id:'dino47',cat:'dinosaurs',text:"Utahraptor was a 'raptor' the size of a bear — far larger and more fearsome than the ones shown in films."},
  {id:'dino48',cat:'dinosaurs',text:"A 'mummified' Edmontosaurus fossil preserved the impression of its skin, revealing what its surface really looked like."},
  {id:'dino49',cat:'dinosaurs',text:"Some duck-billed dinosaurs had hundreds of teeth packed into 'dental batteries' to grind the toughest plants."},
  {id:'dino50',cat:'dinosaurs',text:"The big plates on Stegosaurus's back probably weren't mainly armor, but served for display or to regulate its temperature."},
  // <<< DINOSAURS
  // >>> RELIGION (50 faits)
  {id:'rel1',cat:'religion',text:"Vatican City is the smallest country in the world (0.44 km²), yet it has its own postal system, railway station, and even a football team."},
  {id:'rel2',cat:'religion',text:"In Buddhism, the swastika (卍) is a sacred symbol of peace and good fortune used for over 3,000 years, long before it was misappropriated in the 20th century."},
  {id:'rel3',cat:'religion',text:"The Guru Granth Sahib, Sikhism's holy book, is treated as a living person: it is ceremonially put to bed each night and awakened every morning."},
  {id:'rel4',cat:'religion',text:"Islam, Christianity, and Judaism all revere Abraham as a founding patriarch, which is why they are called 'Abrahamic religions.'"},
  {id:'rel5',cat:'religion',text:"In Japan, it's common to be born Shinto, marry Christian, and have a Buddhist funeral — and nobody sees any contradiction in that."},
  {id:'rel6',cat:'religion',text:"The Golden Temple in Amritsar (Sikhism) serves around 100,000 free meals every day to anyone, regardless of their religion or background."},
  {id:'rel7',cat:'religion',text:"Zoroastrianism, founded in Persia over 3,500 years ago, was the first major religion to teach the existence of heaven, hell, and a final judgment."},
  {id:'rel8',cat:'religion',text:"Jain monks sometimes wear a cloth over their mouths to avoid accidentally swallowing an insect, out of respect for the principle of non-violence (ahimsa)."},
  {id:'rel9',cat:'religion',text:"The Bible is the best-selling book of all time with over 5 billion copies, but it's also the most shoplifted book from stores and hotels."},
  {id:'rel10',cat:'religion',text:"In Hinduism, the number 108 is sacred: a mala (prayer beads) has 108 beads, and there are 108 Upanishads (philosophical texts)."},
  {id:'rel11',cat:'religion',text:"The entire Quran has been memorized by millions of people called 'hafiz,' an unbroken oral tradition since the 7th century."},
  {id:'rel12',cat:'religion',text:"Mount Athos in Greece is an autonomous monastic republic where women — and even female animals — have been banned from entering for over 1,000 years."},
  {id:'rel13',cat:'religion',text:"Buddhism is the only major world religion not based on belief in a creator god — the Buddha himself did not consider himself divine."},
  {id:'rel14',cat:'religion',text:"The Western Wall in Jerusalem receives about one million small notes with prayers tucked between its stones every year."},
  {id:'rel15',cat:'religion',text:"Hinduism officially recognizes 33 million deities — but many theologians see them as 33 forms of one single divine principle."},
  {id:'rel16',cat:'religion',text:"The Whirling Dervishes of Sufism practice a meditative dance called 'sema,' spinning for hours to reach spiritual ecstasy."},
  {id:'rel17',cat:'religion',text:"The Ethiopian calendar, used by the Ethiopian Orthodox Church, has 13 months and is about 7 years behind the Gregorian calendar."},
  {id:'rel18',cat:'religion',text:"The concept of 'karma' is shared by Hinduism, Buddhism, Jainism, and Sikhism, but each religion interprets it differently."},
  {id:'rel19',cat:'religion',text:"In Tibet, 'sky burials' involve offering the bodies of the deceased to vultures, considered an act of ultimate generosity in Vajrayana Buddhism."},
  {id:'rel20',cat:'religion',text:"Mecca welcomes between 2 and 3 million pilgrims each year for the Hajj, the largest annual human gathering in the world."},
  {id:'rel21',cat:'religion',text:"Taoism teaches the concept of 'wu wei' (non-action): the idea that the best actions are those accomplished without effort or force."},
  {id:'rel22',cat:'religion',text:"Pope Francis is the first Jesuit pope, the first from the Americas, and the first to choose the name Francis, in honor of Saint Francis of Assisi."},
  {id:'rel23',cat:'religion',text:"The mandala, a sacred circle in Tibetan Buddhism, is sometimes created with colored sand over weeks, then destroyed in seconds to symbolize impermanence."},
  {id:'rel24',cat:'religion',text:"The Rigveda, a sacred Hindu text, is one of the oldest known religious texts in human history, composed between 1500 and 1200 BCE."},
  {id:'rel25',cat:'religion',text:"The Amish reject most modern technology, but each community decides its own rules — some allow phones in booths outside their homes."},
  {id:'rel26',cat:'religion',text:"In Judaism, Shabbat begins on Friday evening at sunset. In Israel, elevators automatically stop at every floor to avoid pressing buttons."},
  {id:'rel27',cat:'religion',text:"The Hindu Kumbh Mela, held every 12 years, is the world's largest pilgrimage, sometimes drawing over 100 million participants in just a few weeks."},
  {id:'rel28',cat:'religion',text:"Angkor Wat in Cambodia is the largest religious monument in the world. Built as a Hindu temple, it became Buddhist in the 12th century."},
  {id:'rel29',cat:'religion',text:"Rastafarianism considers former Ethiopian Emperor Haile Selassie a divine incarnation, even though he himself identified as an Orthodox Christian."},
  {id:'rel30',cat:'religion',text:"Gaudí's Sagrada Família in Barcelona has been under construction since 1882. It is expected to be completed in 2026, 144 years after the first stone was laid."},
  {id:'rel31',cat:'religion',text:"The Bahá'í Faith, founded in 19th-century Persia, teaches the underlying unity of all the world's major religions."},
  {id:'rel32',cat:'religion',text:"Baptized Sikhs wear the 'Five Ks,' five articles of faith, including uncut hair and a small comb."},
  {id:'rel33',cat:'religion',text:"In Japanese Shinto, sacred places are marked by gateways called 'torii,' and the spirits of nature are called 'kami.'"},
  {id:'rel34',cat:'religion',text:"During the month of Ramadan, many Muslims abstain from food and drink from dawn until sunset."},
  {id:'rel35',cat:'religion',text:"A Jewish Torah scroll is written entirely by hand by a scribe: a single mistake can render the whole text unusable."},
  {id:'rel36',cat:'religion',text:"Jain non-violence can be so strict that some monks gently sweep the ground in front of them as they walk, to avoid crushing any insect."},
  {id:'rel37',cat:'religion',text:"The title 'Dalai Lama' means roughly 'ocean of wisdom': 'dalai' means ocean in Mongolian."},
  {id:'rel38',cat:'religion',text:"During the Hajj pilgrimage, the faithful circle seven times around the Kaaba, a cube-shaped building in Mecca."},
  {id:'rel39',cat:'religion',text:"The great Shinto shrine at Ise, in Japan, is completely rebuilt from scratch every twenty years, and has been for over a thousand years."},
  {id:'rel40',cat:'religion',text:"Christianity and Islam are the world's two largest religions, with several billion followers between them."},
  {id:'rel41',cat:'religion',text:"When a new pope is elected, smoke from a Vatican chimney announces the result: black if nothing is decided, white if a pope is chosen."},
  {id:'rel42',cat:'religion',text:"Diwali, the 'festival of lights,' is celebrated by Hindus, Sikhs, and Jains alike."},
  {id:'rel43',cat:'religion',text:"In Tibetan Buddhism, spinning a 'prayer wheel' is seen by the faithful as equivalent to reciting the mantra it contains."},
  {id:'rel44',cat:'religion',text:"The Hindu epic Mahabharata is so long that it is, on its own, many times the length of the Iliad and the Odyssey combined."},
  {id:'rel45',cat:'religion',text:"The Bodhi tree, under which the Buddha is said to have awakened, still has living descendants today."},
  {id:'rel46',cat:'religion',text:"Many religions set aside a weekly day of rest — but not the same one: Saturday for Jews, Sunday for most Christians."},
  {id:'rel47',cat:'religion',text:"Jewish (kosher) and Muslim (halal) dietary rules resemble each other on several points, notably the ban on eating pork."},
  {id:'rel48',cat:'religion',text:"The Mormon religion was founded in the United States in 1830: on the scale of history, it is a very recent world religion."},
  {id:'rel49',cat:'religion',text:"The crescent-and-star symbol, now associated with Islam, actually comes from the Ottoman Empire, not from the religion's beginnings."},
  {id:'rel50',cat:'religion',text:"The Camino de Santiago, in Spain, has drawn Christian pilgrims for over a thousand years."},
  // <<< RELIGION
  // >>> FLORA (50 faits)
  {id:'flo1',cat:'flora',text:"Trees communicate with each other through an underground fungal network called the 'Wood Wide Web' — they exchange nutrients and warning signals."},
  {id:'flo2',cat:'flora',text:"The giant sequoia is the heaviest living organism on Earth: the specimen named General Sherman weighs approximately 1,385 tonnes."},
  {id:'flo3',cat:'flora',text:"Orchids are the most diverse family of flowering plants: over 28,000 species exist, representing 10% of all flowering plants."},
  {id:'flo4',cat:'flora',text:"Bamboo is the fastest-growing plant in the world: some species grow 91 cm in a single day."},
  {id:'flo5',cat:'flora',text:"Vanilla is the only orchid cultivated for food use — outside Mexico, its pollination must be done by hand."},
  {id:'flo6',cat:'flora',text:"Pando, a giant aspen in Utah, is considered the heaviest and oldest living organism: 80,000 years old and 6,000 tonnes."},
  {id:'flo7',cat:'flora',text:"Cacti store water in their fleshy stems — a saguaro can absorb up to 750 liters of water after a single rainfall."},
  {id:'flo8',cat:'flora',text:"Victoria amazonica, the giant Amazonian water lily, has leaves reaching 3 meters in diameter and can support the weight of a child."},
  {id:'flo9',cat:'flora',text:"The Bristlecone pine Methuselah is the oldest known living tree: 4,855 years old, predating the pyramids of Giza."},
  {id:'flo10',cat:'flora',text:"Cherry blossoms (sakura) last only 7 to 10 days — their ephemeral nature lies at the heart of the Japanese aesthetic of mono no aware."},
  {id:'flo11',cat:'flora',text:"Rafflesia arnoldii produces the world's largest flower (up to 1 meter in diameter) and emits the smell of rotting meat to attract flies."},
  {id:'flo12',cat:'flora',text:"Autumn leaves don't 'turn red' — they reveal pigments (anthocyanins, carotenoids) that were masked by green chlorophyll."},
  {id:'flo13',cat:'flora',text:"Fern spores are so light they can travel across oceans carried by the wind — some species colonize islands thousands of kilometers away."},
  {id:'flo14',cat:'flora',text:"The baobab can live over 2,000 years and store up to 120,000 liters of water in its sponge-like trunk — hence its nickname 'bottle tree'."},
  {id:'flo15',cat:'flora',text:"Carnivorous plants evolved independently at least 12 times — a convergent adaptation to nitrogen-poor soils."},
  {id:'flo16',cat:'flora',text:"Coffee comes from an Ethiopian plant discovered by a shepherd whose goats ate the berries and became hyperactive at night."},
  {id:'flo17',cat:'flora',text:"Mangroves store up to 10 times more carbon per hectare than tropical forests — and protect coastlines from tsunamis and cyclones."},
  {id:'flo18',cat:'flora',text:"The sensitive plant (Mimosa pudica) folds its leaves on contact within tenths of a second — a defensive mechanism against herbivores."},
  {id:'flo19',cat:'flora',text:"Amazon rainforest trees generate their own clouds: they transpire so much water (a single tree can emit 500 liters/day) that it influences regional weather."},
  {id:'flo20',cat:'flora',text:"Dandelion is one of the most complete medicinal plants: its flowers, leaves, and roots are all edible and used in herbal medicine for centuries."},
  {id:'flo21',cat:'flora',text:"Some plants like Ephedra produce seeds without flowers — they have survived for 250 million years before the appearance of angiosperms."},
  {id:'flo22',cat:'flora',text:"The Hallerbos forest in Belgium is covered with a carpet of bluebells every spring — a phenomenon that lasts only 2 to 3 weeks per year."},
  {id:'flo23',cat:'flora',text:"The roots of a single adult tree can extend 40 meters horizontally — four times the tree's height."},
  {id:'flo24',cat:'flora',text:"The truffle is the underground fruit of a fungus that lives in symbiosis with oaks, hazels, and hornbeams — it never grows without its host tree."},
  {id:'flo25',cat:'flora',text:"The sacred lotus (Nelumbo nucifera) is capable of thermoregulation: it maintains its flowers at 30-35°C even when the outside temperature drops to 10°C."},
  {id:'flo26',cat:'flora',text:"Lichens are actually two organisms in symbiosis (a fungus and an alga or cyanobacterium) — they have colonized rocky surfaces for 400 million years."},
  {id:'flo27',cat:'flora',text:"Welwitschia mirabilis from the Namib Desert has only two leaves that grow throughout its life — it can live more than 1,500 years."},
  {id:'flo28',cat:'flora',text:"Porcini mushrooms and chanterelles are not plants but fungi — a separate kingdom, evolutionarily closer to animals than plants."},
  {id:'flo29',cat:'flora',text:"Henna (Lawsonia inermis) has been used for body dyeing for over 5,000 years in Egypt, India, and North Africa."},
  {id:'flo30',cat:'flora',text:"Chlorophyll is green because it primarily absorbs red and blue light and reflects green — an 'inefficiency' that remains an evolutionary mystery."},
  {id:'flo31',cat:'flora',text:"The titan arum, nicknamed the 'corpse flower,' gives off a powerful smell of rotting meat and blooms only very rarely, sometimes every seven to ten years."},
  {id:'flo32',cat:'flora',text:"The Venus flytrap 'counts': it snaps shut only if its sensitive hairs are touched twice within a few seconds."},
  {id:'flo33',cat:'flora',text:"'Resurrection plants' can dry out almost entirely, appear dead for months, then turn green again within hours once watered."},
  {id:'flo34',cat:'flora',text:"Scientists have managed to grow a date palm from a seed about 2,000 years old, found at an archaeological site."},
  {id:'flo35',cat:'flora',text:"The tallest living tree in the world, a coast redwood named Hyperion, exceeds 115 meters — taller than the Statue of Liberty."},
  {id:'flo36',cat:'flora',text:"An underwater seagrass meadow can be a single plant, cloned over kilometers — one of the largest living organisms known."},
  {id:'flo37',cat:'flora',text:"The manchineel is a tree so toxic that sheltering under it in the rain can be enough to burn the skin — it's nicknamed the 'tree of death.'"},
  {id:'flo38',cat:'flora',text:"The dragon's blood tree of Socotra has an umbrella shape and produces a blood-red sap, long called 'dragon's blood' and used as a dye."},
  {id:'flo39',cat:'flora',text:"The strangler fig begins life on a branch of another tree, then slowly wraps it in its roots until it sometimes smothers it."},
  {id:'flo40',cat:'flora',text:"The world's smallest flowering plant, a watermeal of the genus Wolffia, is barely bigger than a grain of salt."},
  {id:'flo41',cat:'flora',text:"The tobacco plant makes nicotine not for smokers, but as a genuine natural insecticide to poison the insects that nibble it."},
  {id:'flo42',cat:'flora',text:"The fastest known movement in a plant is that of a small dogwood flower that catapults its pollen in under a thousandth of a second."},
  {id:'flo43',cat:'flora',text:"The ginkgo is a 'living fossil': this tree has changed very little for over 200 million years, since the age of the dinosaurs."},
  {id:'flo44',cat:'flora',text:"The Wollemi pine was known only from fossils... until, in 1994, a few living specimens were found in a canyon in Australia."},
  {id:'flo45',cat:'flora',text:"The 'Spanish moss' that hangs from trees in the southern United States is not a moss: it's a cousin of the pineapple."},
  {id:'flo46',cat:'flora',text:"Mistletoe is a parasitic plant: it sinks its roots into a tree's branches to steal its water and nutrients."},
  {id:'flo47',cat:'flora',text:"In Sweden, a spruce named Old Tjikko has a root system nearly 10,000 years old, even though its visible trunk is much younger."},
  {id:'flo48',cat:'flora',text:"Many bamboos flower all at once, only once after several decades — and then nearly all die together."},
  {id:'flo49',cat:'flora',text:"The squirting cucumber ripens then bursts to shoot its seeds far away in a jet of liquid."},
  {id:'flo50',cat:'flora',text:"Young sunflowers follow the Sun's path across the sky, turning east in the morning and west by evening."},
  // <<< FLORA
];
